window.KJV1769_STRONG_BOOKS["Job"] = {"osis":"Job","book":"욥기","verses":{"1:1":{"text":"There was a man in the land of Uz, whose name was Job; and that man was perfect and upright, and one that feared God, and eschewed evil.","words":[["H0376","There was a man",0,15],["H0776","in the land",16,27],["H5780","of Uz",28,33],["H8034","whose name",35,45],["H0347","was Job",46,53],["H0376","and that man",55,67],["H8535","was perfect",68,79],["H3477","and upright",80,91],["H3373","and one that feared",93,112],["H0430","God",113,116],["H5493","and eschewed",118,130],["H7451","evil",131,135]]},"1:2":{"text":"And there were born unto him seven sons and three daughters.","words":[["H3205","And there were born",0,19],["H7651","unto him seven",20,34],["H1121","sons",35,39],["H7969","and three",40,49],["H1323","daughters",50,59]]},"1:3":{"text":"His substance also was seven thousand sheep, and three thousand camels, and five hundred yoke of oxen, and five hundred she asses, and a very great household; so that this man was the greatest of all the men of the east.","words":[["H4735","His substance",0,13],["H7651","also was seven",14,28],["H0505","thousand",29,37],["H6629","sheep",38,43],["H7969","and three",45,54],["H0505","thousand",55,63],["H1581","camels",64,70],["H2568","and five",72,80],["H3967","hundred",81,88],["H6776","yoke",89,93],["H1241","of oxen",94,101],["H2568","and five",103,111],["H3967","hundred",112,119],["H0860","she asses",120,129],["H3966","and a very",131,141],["H7227","great",142,147],["H5657","household",148,157],["H0376","so that this man",159,175],["H1419","was the greatest",176,192],["H1121","of all the men",193,207],["H6924","of the east",208,219]]},"1:4":{"text":"And his sons went and feasted in their houses, every one his day; and sent and called for their three sisters to eat and to drink with them.","words":[["H1121","And his sons",0,12],["H1980","went",13,17],["H4960","and feasted",18,29],["H6213","and feasted",18,29],["H1004","in their houses",30,45],["H0376","every one",47,56],["H3117","his day",57,64],["H7971","and sent",66,74],["H7121","and called",75,85],["H7969","for their three",86,101],["H0269","sisters",102,109],["H0398","to eat",110,116],["H8354","and to drink",117,129]]},"1:5":{"text":"And it was so, when the days of their feasting were gone about, that Job sent and sanctified them, and rose up early in the morning, and offered burnt offerings according to the number of them all: for Job said, It may be that my sons have sinned, and cursed God in their hearts. Thus did Job continually.","words":[["H3117","And it was so, when the days",0,28],["H4960","of their feasting",29,46],["H5362","were gone about",47,62],["H0347","that Job",64,72],["H7971","sent",73,77],["H6942","and sanctified",78,92],["H7925","them, and rose up early",93,116],["H1242","in the morning",117,131],["H5927","and offered",133,144],["H5930","burnt offerings",145,160],["H4557","according to the number",161,184],["H0347","of them all: for Job",185,205],["H0559","said",206,210],["H0194","It may be",212,221],["H1121","that my sons",222,234],["H2398","have sinned",235,246],["H1288","and cursed",248,258],["H0430","God",259,262],["H3824","in their hearts",263,278],["H6213","Thus did",280,288],["H0347","Job",289,292],["H3117","continually",293,304]]},"1:6":{"text":"Now there was a day when the sons of God came to present themselves before the LORD, and Satan came also among them.","words":[["H3117","Now there was a day",0,19],["H1121","when the sons",20,33],["H0430","of God",34,40],["H0935","came",41,45],["H3320","to present",46,56],["H3068","themselves before the LORD",57,83],["H7854","and Satan",85,94],["H0935","came",95,99],["H8432","also among",100,110]]},"1:7":{"text":"And the LORD said unto Satan, Whence comest thou? Then Satan answered the LORD, and said, From going to and fro in the earth, and from walking up and down in it.","words":[["H3068","And the LORD",0,12],["H0559","said",13,17],["H7854","unto Satan",18,28],["H0370","Whence",30,36],["H0935","comest",37,43],["H7854","thou? Then Satan",44,60],["H6030","answered",61,69],["H3068","the LORD",70,78],["H0559","and said",80,88],["H7751","From going to and fro",90,111],["H0776","in the earth",112,124],["H1980","and from walking up and down",126,154]]},"1:8":{"text":"And the LORD said unto Satan, Hast thou considered my servant Job, that there is none like him in the earth, a perfect and an upright man, one that feareth God, and escheweth evil?","words":[["H3068","And the LORD",0,12],["H0559","said",13,17],["H7854","unto Satan",18,28],["H7760","Hast thou considered",30,50],["H3820","Hast thou considered",30,50],["H5650","my servant",51,61],["H0347","Job",62,65],["H0776","that there is none like him in the earth",67,107],["H8535","a perfect",109,118],["H3477","and an upright",119,133],["H0376","man",134,137],["H3373","one that feareth",139,155],["H0430","God",156,159],["H5493","and escheweth",161,174],["H7451","evil",175,179]]},"1:9":{"text":"Then Satan answered the LORD, and said, Doth Job fear God for nought?","words":[["H7854","Then Satan",0,10],["H6030","answered",11,19],["H3068","the LORD",20,28],["H0559","and said",30,38],["H0347","Doth Job",40,48],["H3372","fear",49,53],["H0430","God",54,57],["H2600","for nought",58,68]]},"1:10":{"text":"Hast not thou made an hedge about him, and about his house, and about all that he hath on every side? thou hast blessed the work of his hands, and his substance is increased in the land.","words":[["H7753","Hast not thou made an hedge",0,27],["H1157","about him, and about",28,48],["H1004","his house",49,58],["H5439","and about all that he hath on every side",60,100],["H1288","thou hast blessed",102,119],["H4639","the work",120,128],["H3027","of his hands",129,141],["H4735","and his substance",143,160],["H6555","is increased",161,173],["H0776","in the land",174,185]]},"1:11":{"text":"But put forth thine hand now, and touch all that he hath, and he will curse thee to thy face.","words":[["H0199","But",0,3],["H7971","put forth",4,13],["H3027","thine hand",14,24],["H5060","now, and touch",25,39],["H1288","all that he hath, and he will curse",40,75],["H3808","all that he hath, and he will curse",40,75],["H6440","thee to thy face",76,92]]},"1:12":{"text":"And the LORD said unto Satan, Behold, all that he hath is in thy power; only upon himself put not forth thine hand. So Satan went forth from the presence of the LORD.","words":[["H3068","And the LORD",0,12],["H0559","said",13,17],["H7854","unto Satan",18,28],["H3027","Behold, all that he hath is in thy power",30,70],["H7971","only upon himself put not forth",72,103],["H3027","thine hand",104,114],["H7854","So Satan",116,124],["H3318","went forth",125,135],["H6440","from the presence",136,153],["H3068","of the LORD",154,165]]},"1:13":{"text":"And there was a day when his sons and his daughters were eating and drinking wine in their eldest brother's house:","words":[["H3117","And there was a day",0,19],["H1121","when his sons",20,33],["H1323","and his daughters",34,51],["H0398","were eating",52,63],["H8354","and drinking",64,76],["H3196","wine",77,81],["H1060","in their eldest",82,97],["H0251","brother's",98,107],["H1004","house",108,113]]},"1:14":{"text":"And there came a messenger unto Job, and said, The oxen were plowing, and the asses feeding beside them:","words":[["H0935","And there came",0,14],["H4397","a messenger",15,26],["H0347","unto Job",27,35],["H0559","and said",37,45],["H1241","The oxen",47,55],["H2790","were plowing",56,68],["H0860","and the asses",70,83],["H7462","feeding",84,91],["H3027","beside",92,98]]},"1:15":{"text":"And the Sabeans fell upon them, and took them away; yea, they have slain the servants with the edge of the sword; and I only am escaped alone to tell thee.","words":[["H7614","And the Sabeans",0,15],["H5307","fell",16,20],["H3947","upon them, and took them away",21,50],["H5221","yea, they have slain",52,72],["H5288","the servants",73,85],["H6310","with the edge",86,99],["H2719","of the sword",100,112],["H4422","and I only am escaped",114,135],["H5046","alone to tell",136,149]]},"1:16":{"text":"While he was yet speaking, there came also another, and said, The fire of God is fallen from heaven, and hath burned up the sheep, and the servants, and consumed them; and I only am escaped alone to tell thee.","words":[["H1696","While he was yet speaking",0,25],["H0935","there came",27,37],["H0559","also another, and said",38,60],["H0784","The fire",62,70],["H0430","of God",71,77],["H5307","is fallen",78,87],["H8064","from heaven",88,99],["H1197","and hath burned up",101,119],["H6629","the sheep",120,129],["H5288","and the servants",131,147],["H0398","and consumed",149,161],["H4422","them; and I only am escaped",162,189],["H5046","alone to tell",190,203]]},"1:17":{"text":"While he was yet speaking, there came also another, and said, The Chaldeans made out three bands, and fell upon the camels, and have carried them away, yea, and slain the servants with the edge of the sword; and I only am escaped alone to tell thee.","words":[["H1696","While he was yet speaking",0,25],["H0935","there came",27,37],["H0559","also another, and said",38,60],["H3778","The Chaldeans",62,75],["H7760","made out",76,84],["H7969","three",85,90],["H7218","bands",91,96],["H6584","and fell",98,106],["H1581","upon the camels",107,122],["H3947","and have carried them away",124,150],["H5221","yea, and slain",152,166],["H5288","the servants",167,179],["H6310","with the edge",180,193],["H2719","of the sword",194,206],["H4422","and I only am escaped",208,229],["H5046","alone to tell",230,243]]},"1:18":{"text":"While he was yet speaking, there came also another, and said, Thy sons and thy daughters were eating and drinking wine in their eldest brother's house:","words":[["H1696","While he was yet speaking",0,25],["H0935","there came",27,37],["H0559","also another, and said",38,60],["H1121","Thy sons",62,70],["H1323","and thy daughters",71,88],["H0398","were eating",89,100],["H8354","and drinking",101,113],["H3196","wine",114,118],["H1060","in their eldest",119,134],["H0251","brother's",135,144],["H1004","house",145,150]]},"1:19":{"text":"And, behold, there came a great wind from the wilderness, and smote the four corners of the house, and it fell upon the young men, and they are dead; and I only am escaped alone to tell thee.","words":[["H0935","And, behold, there came",0,23],["H1419","a great",24,31],["H7307","wind",32,36],["H5676","from",37,41],["H4057","the wilderness",42,56],["H5060","and smote",58,67],["H0702","the four",68,76],["H6438","corners",77,84],["H1004","of the house",85,97],["H5307","and it fell",99,110],["H5288","upon the young men",111,129],["H4191","and they are dead",131,148],["H4422","and I only am escaped",150,171],["H5046","alone to tell",172,185]]},"1:20":{"text":"Then Job arose, and rent his mantle, and shaved his head, and fell down upon the ground, and worshipped,","words":[["H0347","Then Job",0,8],["H6965","arose",9,14],["H7167","and rent",16,24],["H4598","his mantle",25,35],["H1494","and shaved",37,47],["H7218","his head",48,56],["H5307","and fell down",58,71],["H0776","upon the ground",72,87],["H7812","and worshipped",89,103]]},"1:21":{"text":"And said, Naked came I out of my mother's womb, and naked shall I return thither: the LORD gave, and the LORD hath taken away; blessed be the name of the LORD.","words":[["H0559","And said",0,8],["H6174","Naked",10,15],["H3318","came I out",16,26],["H0517","of my mother's",27,41],["H0990","womb",42,46],["H6174","and naked",48,57],["H7725","shall I return",58,72],["H3068","thither: the LORD",73,90],["H5414","gave",91,95],["H3068","and the LORD",97,109],["H3947","hath taken away",110,125],["H1288","blessed",127,134],["H8034","be the name",135,146],["H3068","of the LORD",147,158]]},"1:22":{"text":"In all this Job sinned not, nor charged God foolishly.","words":[["H0347","In all this Job",0,15],["H2398","sinned",16,22],["H5414","not, nor charged",23,39],["H0430","God",40,43],["H8604","foolishly",44,53]]},"2:1":{"text":"Again there was a day when the sons of God came to present themselves before the LORD, and Satan came also among them to present himself before the LORD.","words":[["H3117","Again there was a day",0,21],["H1121","when the sons",22,35],["H0430","of God",36,42],["H0935","came",43,47],["H3320","to present",48,58],["H3068","themselves before the LORD",59,85],["H7854","and Satan",87,96],["H0935","came",97,101],["H8432","also among",102,112],["H3320","them to present",113,128],["H3068","himself before the LORD",129,152]]},"2:2":{"text":"And the LORD said unto Satan, From whence comest thou? And Satan answered the LORD, and said, From going to and fro in the earth, and from walking up and down in it.","words":[["H3068","And the LORD",0,12],["H0559","said",13,17],["H7854","unto Satan",18,28],["H0335","From whence",30,41],["H0935","comest",42,48],["H7854","thou? And Satan",49,64],["H6030","answered",65,73],["H3068","the LORD",74,82],["H0559","and said",84,92],["H7751","From going to and fro",94,115],["H0776","in the earth",116,128],["H1980","and from walking up and down",130,158]]},"2:3":{"text":"And the LORD said unto Satan, Hast thou considered my servant Job, that there is none like him in the earth, a perfect and an upright man, one that feareth God, and escheweth evil? and still he holdeth fast his integrity, although thou movedst me against him, to destroy him without cause.","words":[["H3068","And the LORD",0,12],["H0559","said",13,17],["H7854","unto Satan",18,28],["H7760","Hast thou",30,39],["H3820","considered",40,50],["H5650","my servant",51,61],["H0347","Job",62,65],["H0776","that there is none like him in the earth",67,107],["H8535","a perfect",109,118],["H3477","and an upright",119,133],["H0376","man",134,137],["H3373","one that feareth",139,155],["H0430","God",156,159],["H5493","and escheweth",161,174],["H7451","evil",175,179],["H2388","and still he holdeth fast",181,206],["H8538","his integrity",207,220],["H5496","although thou movedst",222,243],["H1104","me against him, to destroy",244,270],["H2600","him without cause",271,288]]},"2:4":{"text":"And Satan answered the LORD, and said, Skin for skin, yea, all that a man hath will he give for his life.","words":[["H7854","And Satan",0,9],["H6030","answered",10,18],["H3068","the LORD",19,27],["H0559","and said",29,37],["H5785","Skin",39,43],["H5785","for skin",44,52],["H0376","yea, all that a man",54,73],["H5414","hath will he give",74,91],["H5315","for his life",92,104]]},"2:5":{"text":"But put forth thine hand now, and touch his bone and his flesh, and he will curse thee to thy face.","words":[["H0199","But",0,3],["H7971","put forth",4,13],["H3027","thine hand",14,24],["H5060","now, and touch",25,39],["H6106","his bone",40,48],["H1320","and his flesh",49,62],["H1288","and he will curse",64,81],["H6440","thee to thy face",82,98]]},"2:6":{"text":"And the LORD said unto Satan, Behold, he is in thine hand; but save his life.","words":[["H3068","And the LORD",0,12],["H0559","said",13,17],["H7854","unto Satan",18,28],["H3027","Behold, he is in thine hand",30,57],["H8104","but save",59,67],["H5315","his life",68,76]]},"2:7":{"text":"So went Satan forth from the presence of the LORD, and smote Job with sore boils from the sole of his foot unto his crown.","words":[["H3318","So went",0,7],["H7854","Satan",8,13],["H3318","forth",14,19],["H6440","from the presence",20,37],["H3068","of the LORD",38,49],["H5221","and smote",51,60],["H0347","Job",61,64],["H7451","with sore",65,74],["H7822","boils",75,80],["H3709","from the sole",81,94],["H7272","of his foot",95,106],["H6936","unto his crown",107,121]]},"2:8":{"text":"And he took him a potsherd to scrape himself withal; and he sat down among the ashes.","words":[["H3947","And he took",0,11],["H2789","him a potsherd",12,26],["H1623","to scrape",27,36],["H3427","himself withal; and he sat down",37,68],["H8432","among",69,74],["H0665","the ashes",75,84]]},"2:9":{"text":"Then said his wife unto him, Dost thou still retain thine integrity? curse God, and die.","words":[["H0559","Then said",0,9],["H0802","his wife",10,18],["H2388","unto him, Dost thou still retain",19,51],["H8538","thine integrity",52,67],["H1288","curse",69,74],["H0430","God",75,78],["H4191","and die",80,87]]},"2:10":{"text":"But he said unto her, Thou speakest as one of the foolish women speaketh. What? shall we receive good at the hand of God, and shall we not receive evil? In all this did not Job sin with his lips.","words":[["H0559","But he said",0,11],["H1696","unto her, Thou speakest",12,35],["H0259","as one",36,42],["H5036","of the foolish women",43,63],["H1696","speaketh",64,72],["H1571","What",74,78],["H6901","shall we receive",80,96],["H2896","good",97,101],["H0430","at the hand of God",102,120],["H6901","and shall we not receive",122,146],["H7451","evil",147,151],["H0347","In all this did not Job",153,176],["H2398","sin",177,180],["H8193","with his lips",181,194]]},"2:11":{"text":"Now when Job's three friends heard of all this evil that was come upon him, they came every one from his own place; Eliphaz the Temanite, and Bildad the Shuhite, and Zophar the Naamathite: for they had made an appointment together to come to mourn with him and to comfort him.","words":[["H0347","Now when Job's",0,14],["H7969","three",15,20],["H7453","friends",21,28],["H8085","heard",29,34],["H7451","of all this evil",35,51],["H0935","that was come",52,65],["H0935","upon him, they came",66,85],["H0376","every one",86,95],["H4725","from his own place",96,114],["H0464","Eliphaz",116,123],["H8489","the Temanite",124,136],["H1085","and Bildad",138,148],["H7747","the Shuhite",149,160],["H6691","and Zophar",162,172],["H5284","the Naamathite",173,187],["H3259","for they had made an appointment",189,221],["H3162","together",222,230],["H0935","to come",231,238],["H5110","to mourn",239,247],["H5162","with him and to comfort",248,271]]},"2:12":{"text":"And when they lifted up their eyes afar off, and knew him not, they lifted up their voice, and wept; and they rent every one his mantle, and sprinkled dust upon their heads toward heaven.","words":[["H5375","And when they lifted up",0,23],["H5869","their eyes",24,34],["H7350","afar off",35,43],["H5234","and knew",45,53],["H5375","him not, they lifted up",54,77],["H6963","their voice",78,89],["H1058","and wept",91,99],["H7167","and they rent",101,114],["H0376","every one",115,124],["H4598","his mantle",125,135],["H2236","and sprinkled",137,150],["H6083","dust",151,155],["H7218","upon their heads",156,172],["H8064","toward heaven",173,186]]},"2:13":{"text":"So they sat down with him upon the ground seven days and seven nights, and none spake a word unto him: for they saw that his grief was very great.","words":[["H3427","So they sat down",0,16],["H0776","with him upon the ground",17,41],["H7651","seven",42,47],["H3117","days",48,52],["H7651","and seven",53,62],["H3915","nights",63,69],["H1696","and none spake",71,85],["H1697","a word",86,92],["H7200","unto him: for they saw",93,115],["H3511","that his grief",116,130],["H3966","was very",131,139],["H1431","great",140,145]]},"3:1":{"text":"After this opened Job his mouth, and cursed his day.","words":[["H0310","After",0,5],["H6605","this opened",6,17],["H0347","Job",18,21],["H6310","his mouth",22,31],["H7043","and cursed",33,43],["H3117","his day",44,51]]},"3:2":{"text":"And Job spake, and said,","words":[["H0347","And Job",0,7],["H6030","spake",8,13],["H0559","and said",15,23]]},"3:3":{"text":"Let the day perish wherein I was born, and the night in which it was said, There is a man child conceived.","words":[["H3117","Let the day",0,11],["H0006","perish",12,18],["H3205","wherein I was born",19,37],["H3915","and the night",39,52],["H0559","in which it was said",53,73],["H1397","There is a man child",75,95],["H2029","conceived",96,105]]},"3:4":{"text":"Let that day be darkness; let not God regard it from above, neither let the light shine upon it.","words":[["H3117","Let that day",0,12],["H2822","be darkness",13,24],["H0433","let not God",26,37],["H1875","regard",38,44],["H4605","it from above",45,58],["H5105","neither let the light",60,81],["H3313","shine",82,87]]},"3:5":{"text":"Let darkness and the shadow of death stain it; let a cloud dwell upon it; let the blackness of the day terrify it.","words":[["H2822","Let darkness",0,12],["H6757","and the shadow of death",13,36],["H1350","stain",37,42],["H6053","it; let a cloud",43,58],["H7931","dwell",59,64],["H3650","upon it; let the blackness",65,91],["H3117","of the day",92,102],["H1204","terrify",103,110]]},"3:6":{"text":"As for that night, let darkness seize upon it; let it not be joined unto the days of the year, let it not come into the number of the months.","words":[["H3915","As for that night",0,17],["H0652","let darkness",19,31],["H3947","seize",32,37],["H2302","upon it; let it not be joined",38,67],["H3117","unto the days",68,81],["H8141","of the year",82,93],["H0935","let it not come",95,110],["H4557","into the number",111,126],["H3391","of the months",127,140]]},"3:7":{"text":"Lo, let that night be solitary, let no joyful voice come therein.","words":[["H3915","Lo, let that night",0,18],["H1565","be solitary",19,30],["H7445","let no joyful voice",32,51],["H0935","come",52,56]]},"3:8":{"text":"Let them curse it that curse the day, who are ready to raise up their mourning.","words":[["H5344","Let them curse",0,14],["H0779","it that curse",15,28],["H3117","the day",29,36],["H6264","who are ready",38,51],["H5782","to raise up",52,63],["H3882","their mourning",64,78]]},"3:9":{"text":"Let the stars of the twilight thereof be dark; let it look for light, but have none; neither let it see the dawning of the day:","words":[["H3556","Let the stars",0,13],["H5399","of the twilight",14,29],["H2821","thereof be dark",30,45],["H6960","let it look",47,58],["H0216","for light",59,68],["H7200","but have none; neither let it see",70,103],["H6079","the dawning",104,115],["H7837","of the day",116,126]]},"3:10":{"text":"Because it shut not up the doors of my mother's womb, nor hid sorrow from mine eyes.","words":[["H5462","Because it shut not up",0,22],["H1817","the doors",23,32],["H0990","of my mother's womb",33,52],["H5641","nor hid",54,61],["H5999","sorrow",62,68],["H5869","from mine eyes",69,83]]},"3:11":{"text":"Why died I not from the womb? why did I not give up the ghost when I came out of the belly?","words":[["H4191","Why died",0,8],["H7358","I not from the womb",9,28],["H1478","why did I not give up the ghost",30,61],["H3318","when I came out",62,77],["H0990","of the belly",78,90]]},"3:12":{"text":"Why did the knees prevent me? or why the breasts that I should suck?","words":[["H1290","Why did the knees",0,17],["H6923","prevent",18,25],["H7699","me? or why the breasts",26,48],["H3243","that I should suck",49,67]]},"3:13":{"text":"For now should I have lain still and been quiet, I should have slept: then had I been at rest,","words":[["H7901","For now should I have lain still",0,32],["H8252","and been quiet",33,47],["H3462","I should have slept",49,68],["H5117","then had I been at rest",70,93]]},"3:14":{"text":"With kings and counsellors of the earth, which built desolate places for themselves;","words":[["H4428","With kings",0,10],["H3289","and counsellors",11,26],["H0776","of the earth",27,39],["H1129","which built",41,52],["H2723","desolate places",53,68]]},"3:15":{"text":"Or with princes that had gold, who filled their houses with silver:","words":[["H8269","Or with princes",0,15],["H2091","that had gold",16,29],["H4390","who filled",31,41],["H1004","their houses",42,54],["H3701","with silver",55,66]]},"3:16":{"text":"Or as an hidden untimely birth I had not been; as infants which never saw light.","words":[["H2934","Or as an hidden",0,15],["H5309","untimely birth",16,30],["H5768","I had not been; as infants",31,57],["H7200","which never saw",58,73],["H0216","light",74,79]]},"3:17":{"text":"There the wicked cease from troubling; and there the weary be at rest.","words":[["H7563","There the wicked",0,16],["H2308","cease",17,22],["H7267","from troubling",23,37],["H3019","and there the weary",39,58],["H3581","and there the weary",39,58],["H5117","be at rest",59,69]]},"3:18":{"text":"There the prisoners rest together; they hear not the voice of the oppressor.","words":[["H0615","There the prisoners",0,19],["H7599","rest",20,24],["H3162","together",25,33],["H8085","they hear",35,44],["H6963","not the voice",45,58],["H5065","of the oppressor",59,75]]},"3:19":{"text":"The small and great are there; and the servant is free from his master.","words":[["H6996","The small",0,9],["H1419","and great",10,19],["H5650","are there; and the servant",20,46],["H2670","is free",47,54],["H0113","from his master",55,70]]},"3:20":{"text":"Wherefore is light given to him that is in misery, and life unto the bitter in soul;","words":[["H0216","Wherefore is light",0,18],["H5414","given",19,24],["H6001","to him that is in misery",25,49],["H2416","and life",51,59],["H4751","unto the bitter",60,75],["H5315","in soul",76,83]]},"3:21":{"text":"Which long for death, but it cometh not; and dig for it more than for hid treasures;","words":[["H2442","Which long",0,10],["H4194","for death",11,20],["H2658","but it cometh not; and dig",22,48],["H4301","for it more than for hid treasures",49,83]]},"3:22":{"text":"Which rejoice exceedingly, and are glad, when they can find the grave?","words":[["H8056","Which rejoice",0,13],["H1524","exceedingly",14,25],["H7797","and are glad",27,39],["H4672","when they can find",41,59],["H6913","the grave",60,69]]},"3:23":{"text":"Why is light given to a man whose way is hid, and whom God hath hedged in?","words":[["H1397","Why is light given to a man",0,27],["H1870","whose way",28,37],["H5641","is hid",38,44],["H0433","and whom God",46,58],["H5526","hath hedged in",59,73]]},"3:24":{"text":"For my sighing cometh before I eat, and my roarings are poured out like the waters.","words":[["H0585","For my sighing",0,14],["H0935","cometh",15,21],["H6440","before",22,28],["H3899","I eat",29,34],["H7581","and my roarings",36,51],["H5413","are poured out",52,66],["H4325","like the waters",67,82]]},"3:25":{"text":"For the thing which I greatly feared is come upon me, and that which I was afraid of is come unto me.","words":[["H6343","For the thing which I greatly",0,29],["H6342","feared",30,36],["H0857","is come",37,44],["H3025","upon me, and that which I was afraid",45,81],["H0935","of is come",82,92]]},"3:26":{"text":"I was not in safety, neither had I rest, neither was I quiet; yet trouble came.","words":[["H7951","I was not in safety",0,19],["H8252","neither had I rest",21,39],["H5117","neither was I quiet",41,60],["H7267","yet trouble",62,73],["H0935","came",74,78]]},"4:1":{"text":"Then Eliphaz the Temanite answered and said,","words":[["H0464","Then Eliphaz",0,12],["H8489","the Temanite",13,25],["H6030","answered",26,34],["H0559","and said",35,43]]},"4:2":{"text":"If we assay to commune with thee, wilt thou be grieved? but who can withhold himself from speaking?","words":[["H5254","If we assay",0,11],["H1697","to commune",12,22],["H3811","with thee, wilt thou be grieved",23,54],["H3201","but who can",56,67],["H6113","withhold",68,76],["H4405","himself from speaking",77,98]]},"4:3":{"text":"Behold, thou hast instructed many, and thou hast strengthened the weak hands.","words":[["H3256","Behold, thou hast instructed",0,28],["H7227","many",29,33],["H2388","and thou hast strengthened",35,61],["H7504","the weak",62,70],["H3027","hands",71,76]]},"4:4":{"text":"Thy words have upholden him that was falling, and thou hast strengthened the feeble knees.","words":[["H4405","Thy words",0,9],["H6965","have upholden",10,23],["H3782","him that was falling",24,44],["H0553","and thou hast strengthened",46,72],["H3766","the feeble",73,83],["H1290","knees",84,89]]},"4:5":{"text":"But now it is come upon thee, and thou faintest; it toucheth thee, and thou art troubled.","words":[["H0935","But now it is come",0,18],["H3811","upon thee, and thou faintest",19,47],["H5060","it toucheth",49,60],["H0926","thee, and thou art troubled",61,88]]},"4:6":{"text":"Is not this thy fear, thy confidence, thy hope, and the uprightness of thy ways?","words":[["H3374","Is not this thy fear",0,20],["H3690","thy confidence",22,36],["H8615","thy hope",38,46],["H8537","and the uprightness",48,67],["H1870","of thy ways",68,79]]},"4:7":{"text":"Remember, I pray thee, who ever perished, being innocent? or where were the righteous cut off?","words":[["H2142","Remember",0,8],["H0006","I pray thee, who ever perished",10,40],["H5355","being innocent",42,56],["H0375","or where",58,66],["H3477","were the righteous",67,85],["H3582","cut off",86,93]]},"4:8":{"text":"Even as I have seen, they that plow iniquity, and sow wickedness, reap the same.","words":[["H7200","Even as I have seen",0,19],["H2790","they that plow",21,35],["H0205","iniquity",36,44],["H2232","and sow",46,53],["H5999","wickedness",54,64],["H7114","reap",66,70]]},"4:9":{"text":"By the blast of God they perish, and by the breath of his nostrils are they consumed.","words":[["H5397","By the blast",0,12],["H0433","of God",13,19],["H0006","they perish",20,31],["H7307","and by the breath",33,50],["H0639","of his nostrils",51,66],["H3615","are they consumed",67,84]]},"4:10":{"text":"The roaring of the lion, and the voice of the fierce lion, and the teeth of the young lions, are broken.","words":[["H7581","The roaring",0,11],["H0738","of the lion",12,23],["H6963","and the voice",25,38],["H7826","of the fierce lion",39,57],["H8127","and the teeth",59,72],["H3715","of the young lions",73,91],["H5421","are broken",93,103]]},"4:11":{"text":"The old lion perisheth for lack of prey, and the stout lion's whelps are scattered abroad.","words":[["H3918","The old lion",0,12],["H0006","perisheth",13,22],["H1097","for lack",23,31],["H2964","of prey",32,39],["H3833","and the stout lion's",41,61],["H1121","whelps",62,68],["H6504","are scattered abroad",69,89]]},"4:12":{"text":"Now a thing was secretly brought to me, and mine ear received a little thereof.","words":[["H1697","Now a thing",0,11],["H1589","was secretly brought",12,32],["H0241","to me, and mine ear",33,52],["H3947","received",53,61],["H8102","a little",62,70]]},"4:13":{"text":"In thoughts from the visions of the night, when deep sleep falleth on men,","words":[["H5587","In thoughts",0,11],["H2384","from the visions",12,28],["H3915","of the night",29,41],["H8639","when deep sleep",43,58],["H5307","falleth",59,66],["H0582","on men",67,73]]},"4:14":{"text":"Fear came upon me, and trembling, which made all my bones to shake.","words":[["H6343","Fear",0,4],["H7122","came",5,9],["H7461","upon me, and trembling",10,32],["H7230","which made all",34,48],["H6106","my bones",49,57],["H6342","to shake",58,66]]},"4:15":{"text":"Then a spirit passed before my face; the hair of my flesh stood up:","words":[["H7307","Then a spirit",0,13],["H2498","passed",14,20],["H6440","before my face",21,35],["H8185","the hair",37,45],["H1320","of my flesh",46,57],["H5568","stood up",58,66]]},"4:16":{"text":"It stood still, but I could not discern the form thereof: an image was before mine eyes, there was silence, and I heard a voice, saying,","words":[["H5975","It stood still",0,14],["H5234","but I could not discern",16,39],["H4758","the form",40,48],["H8544","thereof: an image",49,66],["H5869","was before mine eyes",67,87],["H1827","there was silence",89,106],["H8085","and I heard",108,119],["H6963","a voice",120,127]]},"4:17":{"text":"Shall mortal man be more just than God? shall a man be more pure than his maker?","words":[["H0582","Shall mortal man",0,16],["H6663","be more just",17,29],["H0433","than God",30,38],["H1397","shall a man",40,51],["H2891","be more pure",52,64],["H6213","than his maker",65,79]]},"4:18":{"text":"Behold, he put no trust in his servants; and his angels he charged with folly:","words":[["H0539","Behold, he put no trust",0,23],["H5650","in his servants",24,39],["H4397","and his angels",41,55],["H7760","he charged",56,66],["H8417","with folly",67,77]]},"4:19":{"text":"How much less in them that dwell in houses of clay, whose foundation is in the dust, which are crushed before the moth?","words":[["H0637","How much less",0,13],["H7931","in them that dwell",14,32],["H1004","in houses",33,42],["H2563","of clay",43,50],["H3247","whose foundation",52,68],["H6083","is in the dust",69,83],["H1792","which are crushed",85,102],["H6440","before",103,109],["H6211","the moth",110,118]]},"4:20":{"text":"They are destroyed from morning to evening: they perish for ever without any regarding it.","words":[["H3807","They are destroyed",0,18],["H1242","from morning",19,31],["H6153","to evening",32,42],["H0006","they perish",44,55],["H5331","for ever",56,64],["H7760","without any regarding",65,86]]},"4:21":{"text":"Doth not their excellency which is in them go away? they die, even without wisdom.","words":[["H3499","Doth not their excellency",0,25],["H5265","which is in them go away",26,50],["H4191","they die",52,60],["H2451","even without wisdom",62,81]]},"5:1":{"text":"Call now, if there be any that will answer thee; and to which of the saints wilt thou turn?","words":[["H7121","Call",0,4],["H3426","now, if there be",5,21],["H6030","any that will answer",22,42],["H6918","thee; and to which of the saints",43,75],["H6437","wilt thou turn",76,90]]},"5:2":{"text":"For wrath killeth the foolish man, and envy slayeth the silly one.","words":[["H3708","For wrath",0,9],["H2026","killeth",10,17],["H0191","the foolish man",18,33],["H7068","and envy",35,43],["H4191","slayeth",44,51],["H6601","the silly one",52,65]]},"5:3":{"text":"I have seen the foolish taking root: but suddenly I cursed his habitation.","words":[["H7200","I have seen",0,11],["H0191","the foolish",12,23],["H8327","taking root",24,35],["H6597","but suddenly",37,49],["H5344","I cursed",50,58],["H5116","his habitation",59,73]]},"5:4":{"text":"His children are far from safety, and they are crushed in the gate, neither is there any to deliver them.","words":[["H1121","His children",0,12],["H7368","are far",13,20],["H3468","from safety",21,32],["H1792","and they are crushed",34,54],["H8179","in the gate",55,66],["H5337","neither is there any to deliver",68,99]]},"5:5":{"text":"Whose harvest the hungry eateth up, and taketh it even out of the thorns, and the robber swalloweth up their substance.","words":[["H7105","Whose harvest",0,13],["H7457","the hungry",14,24],["H0398","eateth up",25,34],["H3947","and taketh",36,46],["H0413","it even out",47,58],["H6791","of the thorns",59,72],["H6782","and the robber",74,88],["H7602","swalloweth up",89,102],["H2428","their substance",103,118]]},"5:6":{"text":"Although affliction cometh not forth of the dust, neither doth trouble spring out of the ground;","words":[["H0205","Although affliction",0,19],["H3318","cometh not forth",20,36],["H6083","of the dust",37,48],["H5999","neither doth trouble",50,70],["H6779","spring out",71,81],["H0127","of the ground",82,95]]},"5:7":{"text":"Yet man is born unto trouble, as the sparks fly upward.","words":[["H0120","Yet man",0,7],["H3205","is born",8,15],["H5999","unto trouble",16,28],["H1121","as the sparks",30,43],["H7565","as the sparks",30,43],["H5774","fly",44,47],["H1361","upward",48,54]]},"5:8":{"text":"I would seek unto God, and unto God would I commit my cause:","words":[["H0199","I would seek",0,12],["H1875","I would seek",0,12],["H0410","unto God",13,21],["H0430","and unto God",23,35],["H7760","would I commit",36,50],["H1700","my cause",51,59]]},"5:9":{"text":"Which doeth great things and unsearchable; marvellous things without number:","words":[["H6213","Which doeth",0,11],["H1419","great things",12,24],["H0369","and unsearchable",25,41],["H2714","and unsearchable",25,41],["H6381","marvellous things",43,60],["H4557","without number",61,75]]},"5:10":{"text":"Who giveth rain upon the earth, and sendeth waters upon the fields:","words":[["H5414","Who giveth",0,10],["H4306","rain",11,15],["H6440","upon",16,20],["H0776","the earth",21,30],["H7971","and sendeth",32,43],["H4325","waters",44,50],["H6440","upon",51,55],["H2351","the fields",56,66]]},"5:11":{"text":"To set up on high those that be low; that those which mourn may be exalted to safety.","words":[["H7760","To set up",0,9],["H4791","on high",10,17],["H8217","those that be low",18,35],["H6937","that those which mourn",37,59],["H7682","may be exalted",60,74],["H3468","to safety",75,84]]},"5:12":{"text":"He disappointeth the devices of the crafty, so that their hands cannot perform their enterprise.","words":[["H6565","He disappointeth",0,16],["H4284","the devices",17,28],["H6175","of the crafty",29,42],["H3027","so that their hands",44,63],["H6213","cannot perform",64,78],["H8454","their enterprise",79,95]]},"5:13":{"text":"He taketh the wise in their own craftiness: and the counsel of the froward is carried headlong.","words":[["H3920","He taketh",0,9],["H2450","the wise",10,18],["H6193","in their own craftiness",19,42],["H6098","and the counsel",44,59],["H6617","of the froward",60,74],["H4116","is carried headlong",75,94]]},"5:14":{"text":"They meet with darkness in the daytime, and grope in the noonday as in the night.","words":[["H6298","They meet",0,9],["H2822","with darkness",10,23],["H3119","in the daytime",24,38],["H4959","and grope",40,49],["H6672","in the noonday",50,64],["H3915","as in the night",65,80]]},"5:15":{"text":"But he saveth the poor from the sword, from their mouth, and from the hand of the mighty.","words":[["H3467","But he saveth",0,13],["H0034","the poor",14,22],["H2719","from the sword",23,37],["H6310","from their mouth",39,55],["H3027","and from the hand",57,74],["H2389","of the mighty",75,88]]},"5:16":{"text":"So the poor hath hope, and iniquity stoppeth her mouth.","words":[["H1800","So the poor",0,11],["H8615","hath hope",12,21],["H5766","and iniquity",23,35],["H7092","stoppeth",36,44],["H6310","her mouth",45,54]]},"5:17":{"text":"Behold, happy is the man whom God correcteth: therefore despise not thou the chastening of the Almighty:","words":[["H0835","Behold, happy",0,13],["H0582","is the man",14,24],["H0433","whom God",25,33],["H3198","correcteth",34,44],["H3988","therefore despise",46,63],["H4148","not thou the chastening",64,87],["H7706","of the Almighty",88,103]]},"5:18":{"text":"For he maketh sore, and bindeth up: he woundeth, and his hands make whole.","words":[["H3510","For he maketh sore",0,18],["H2280","and bindeth up",20,34],["H4272","he woundeth",36,47],["H3027","and his hands",49,62],["H7495","make whole",63,73]]},"5:19":{"text":"He shall deliver thee in six troubles: yea, in seven there shall no evil touch thee.","words":[["H5337","He shall deliver",0,16],["H8337","thee in six",17,28],["H6869","troubles",29,37],["H7651","yea, in seven",39,52],["H7451","there shall no evil",53,72],["H5060","touch",73,78]]},"5:20":{"text":"In famine he shall redeem thee from death: and in war from the power of the sword.","words":[["H7458","In famine",0,9],["H6299","he shall redeem",10,25],["H4194","thee from death",26,41],["H4421","and in war",43,53],["H3027","from the power",54,68],["H2719","of the sword",69,81]]},"5:21":{"text":"Thou shalt be hid from the scourge of the tongue: neither shalt thou be afraid of destruction when it cometh.","words":[["H2244","Thou shalt be hid",0,17],["H7752","from the scourge",18,34],["H3956","of the tongue",35,48],["H3372","neither shalt thou be afraid",50,78],["H7701","of destruction",79,93],["H0935","when it cometh",94,108]]},"5:22":{"text":"At destruction and famine thou shalt laugh: neither shalt thou be afraid of the beasts of the earth.","words":[["H7701","At destruction",0,14],["H3720","and famine",15,25],["H7832","thou shalt laugh",26,42],["H3372","neither shalt thou be afraid",44,72],["H2416","of the beasts",73,86],["H0776","of the earth",87,99]]},"5:23":{"text":"For thou shalt be in league with the stones of the field: and the beasts of the field shall be at peace with thee.","words":[["H1285","For thou shalt be in league",0,27],["H0068","with the stones",28,43],["H7704","of the field",44,56],["H2416","and the beasts",58,72],["H7704","of the field",73,85],["H7999","shall be at peace",86,103]]},"5:24":{"text":"And thou shalt know that thy tabernacle shall be in peace; and thou shalt visit thy habitation, and shalt not sin.","words":[["H3045","And thou shalt know",0,19],["H0168","that thy tabernacle",20,39],["H7965","shall be in peace",40,57],["H6485","and thou shalt visit",59,79],["H5116","thy habitation",80,94],["H2398","and shalt not sin",96,113]]},"5:25":{"text":"Thou shalt know also that thy seed shall be great, and thine offspring as the grass of the earth.","words":[["H3045","Thou shalt know",0,15],["H2233","also that thy seed",16,34],["H7227","shall be great",35,49],["H6631","and thine offspring",51,70],["H6212","as the grass",71,83],["H0776","of the earth",84,96]]},"5:26":{"text":"Thou shalt come to thy grave in a full age, like as a shock of corn cometh in in his season.","words":[["H0935","Thou shalt come",0,15],["H6913","to thy grave",16,28],["H3624","in a full age",29,42],["H1430","like as a shock of corn",44,67],["H5927","cometh in",68,77],["H6256","in his season",78,91]]},"5:27":{"text":"Lo this, we have searched it, so it is; hear it, and know thou it for thy good.","words":[["H2713","Lo this, we have searched",0,25],["H8085","it, so it is; hear",26,44],["H3045","it, and know",45,57]]},"6:1":{"text":"But Job answered and said,","words":[["H0347","But Job",0,7],["H6030","answered",8,16],["H0559","and said",17,25]]},"6:2":{"text":"Oh that my grief were throughly weighed, and my calamity laid in the balances together!","words":[["H3863","Oh that",0,7],["H3708","my grief",8,16],["H8254","were throughly",17,31],["H8254","weighed",32,39],["H1942","and my calamity",41,56],["H1962","and my calamity",41,56],["H5375","laid",57,61],["H3976","in the balances",62,77],["H3162","together",78,86]]},"6:3":{"text":"For now it would be heavier than the sand of the sea: therefore my words are swallowed up.","words":[["H3513","For now it would be heavier",0,27],["H2344","than the sand",28,41],["H3220","of the sea",42,52],["H1697","therefore my words",54,72],["H3886","are swallowed up",73,89]]},"6:4":{"text":"For the arrows of the Almighty are within me, the poison whereof drinketh up my spirit: the terrors of God do set themselves in array against me.","words":[["H2671","For the arrows",0,14],["H7706","of the Almighty",15,30],["H5978","are within",31,41],["H2534","me, the poison",42,56],["H8354","whereof drinketh up",57,76],["H7307","my spirit",77,86],["H1161","the terrors",88,99],["H0433","of God",100,106],["H6186","do set themselves in array",107,133]]},"6:5":{"text":"Doth the wild ass bray when he hath grass? or loweth the ox over his fodder?","words":[["H6501","Doth the wild ass",0,17],["H5101","bray",18,22],["H1877","when he hath grass",23,41],["H1600","or loweth",43,52],["H7794","the ox",53,59],["H1098","over his fodder",60,75]]},"6:6":{"text":"Can that which is unsavoury be eaten without salt? or is there any taste in the white of an egg?","words":[["H8602","Can that which is unsavoury",0,27],["H0398","be eaten",28,36],["H4417","without salt",37,49],["H3426","or is there",51,62],["H2940","any taste",63,72],["H7388","in the white",73,85],["H2495","of an egg",86,95]]},"6:7":{"text":"The things that my soul refused to touch are as my sorrowful meat.","words":[["H5315","The things that my soul",0,23],["H3985","refused",24,31],["H5060","to touch",32,40],["H1741","are as my sorrowful",41,60],["H3899","meat",61,65]]},"6:8":{"text":"Oh that I might have my request; and that God would grant me the thing that I long for!","words":[["H0935","Oh that I might have",0,20],["H7596","my request",21,31],["H0433","and that God",33,45],["H5414","would grant",46,57],["H8615","me the thing that I long for",58,86]]},"6:9":{"text":"Even that it would please God to destroy me; that he would let loose his hand, and cut me off!","words":[["H2974","Even that it would please",0,25],["H0433","God",26,29],["H1792","to destroy",30,40],["H5425","me; that he would let loose",41,68],["H3027","his hand",69,77],["H1214","and cut me off",79,93]]},"6:10":{"text":"Then should I yet have comfort; yea, I would harden myself in sorrow: let him not spare; for I have not concealed the words of the Holy One.","words":[["H5165","Then should I yet have comfort",0,30],["H5539","yea, I would harden",32,51],["H2427","myself in sorrow",52,68],["H2550","let him not spare",70,87],["H3582","for I have not concealed",89,113],["H0561","the words",114,123],["H6918","of the Holy One",124,139]]},"6:11":{"text":"What is my strength, that I should hope? and what is mine end, that I should prolong my life?","words":[["H3581","What is my strength",0,19],["H3176","that I should hope",21,39],["H7093","and what is mine end",41,61],["H0748","that I should prolong",63,84],["H5315","my life",85,92]]},"6:12":{"text":"Is my strength the strength of stones? or is my flesh of brass?","words":[["H3581","Is my strength",0,14],["H3581","the strength",15,27],["H0068","of stones",28,37],["H1320","or is my flesh",39,53],["H5153","of brass",54,62]]},"6:13":{"text":"Is not my help in me? and is wisdom driven quite from me?","words":[["H5833","Is not my help",0,14],["H8454","in me? and is wisdom",15,35],["H5080","driven quite",36,48]]},"6:14":{"text":"To him that is afflicted pity should be shewed from his friend; but he forsaketh the fear of the Almighty.","words":[["H4523","To him that is afflicted",0,24],["H2617","pity",25,29],["H7453","should be shewed from his friend",30,62],["H5800","but he forsaketh",64,80],["H3374","the fear",81,89],["H7706","of the Almighty",90,105]]},"6:15":{"text":"My brethren have dealt deceitfully as a brook, and as the stream of brooks they pass away;","words":[["H0251","My brethren",0,11],["H0898","have dealt deceitfully",12,34],["H5158","as a brook",35,45],["H0650","and as the stream",47,64],["H5158","of brooks",65,74],["H5674","they pass away",75,89]]},"6:16":{"text":"Which are blackish by reason of the ice, and wherein the snow is hid:","words":[["H6937","Which are blackish",0,18],["H7140","by reason of the ice",19,39],["H7950","and wherein the snow",41,61],["H5956","is hid",62,68]]},"6:17":{"text":"What time they wax warm, they vanish: when it is hot, they are consumed out of their place.","words":[["H6256","What time",0,9],["H2215","they wax warm",10,23],["H6789","they vanish",25,36],["H2527","when it is hot",38,52],["H1846","they are consumed out",54,75],["H4725","of their place",76,90]]},"6:18":{"text":"The paths of their way are turned aside; they go to nothing, and perish.","words":[["H0734","The paths",0,9],["H1870","of their way",10,22],["H3943","are turned aside",23,39],["H5927","they go",41,48],["H8414","to nothing",49,59],["H0006","and perish",61,71]]},"6:19":{"text":"The troops of Tema looked, the companies of Sheba waited for them.","words":[["H0734","The troops",0,10],["H8485","of Tema",11,18],["H5027","looked",19,25],["H1979","the companies",27,40],["H7614","of Sheba",41,49],["H6960","waited",50,56]]},"6:20":{"text":"They were confounded because they had hoped; they came thither, and were ashamed.","words":[["H0954","They were confounded",0,20],["H0982","because they had hoped",21,43],["H0935","they came",45,54],["H2659","thither, and were ashamed",55,80]]},"6:21":{"text":"For now ye are nothing; ye see my casting down, and are afraid.","words":[["H7200","For now ye are nothing; ye see",0,30],["H2866","my casting down",31,46],["H3372","and are afraid",48,62]]},"6:22":{"text":"Did I say, Bring unto me? or, Give a reward for me of your substance?","words":[["H0559","Did I say",0,9],["H3051","Bring",11,16],["H7809","unto me? or, Give a reward",17,43],["H3581","for me of your substance",44,68]]},"6:23":{"text":"Or, Deliver me from the enemy's hand? or, Redeem me from the hand of the mighty?","words":[["H4422","Or, Deliver",0,11],["H6862","me from the enemy's",12,31],["H3027","hand",32,36],["H6299","or, Redeem",38,48],["H3027","me from the hand",49,65],["H6184","of the mighty",66,79]]},"6:24":{"text":"Teach me, and I will hold my tongue: and cause me to understand wherein I have erred.","words":[["H3384","Teach",0,5],["H2790","me, and I will hold my tongue",6,35],["H0995","and cause me to understand",37,63],["H7686","wherein I have erred",64,84]]},"6:25":{"text":"How forcible are right words! but what doth your arguing reprove?","words":[["H4834","How forcible",0,12],["H3476","are right",13,22],["H0561","words",23,28],["H3198","but what doth your arguing",30,56],["H3198","reprove",57,64]]},"6:26":{"text":"Do ye imagine to reprove words, and the speeches of one that is desperate, which are as wind?","words":[["H2803","Do ye imagine",0,13],["H3198","to reprove",14,24],["H4405","words",25,30],["H0561","and the speeches",32,48],["H2976","of one that is desperate",49,73],["H7307","which are as wind",75,92]]},"6:27":{"text":"Yea, ye overwhelm the fatherless, and ye dig a pit for your friend.","words":[["H5307","Yea, ye overwhelm",0,17],["H3490","the fatherless",18,32],["H3738","and ye dig",34,44],["H7453","a pit for your friend",45,66]]},"6:28":{"text":"Now therefore be content, look upon me; for it is evident unto you if I lie.","words":[["H2974","Now therefore be content",0,24],["H6437","look",26,30],["H6440","upon me; for it is evident",31,57],["H3576","unto you if I lie",58,75]]},"6:29":{"text":"Return, I pray you, let it not be iniquity; yea, return again, my righteousness is in it.","words":[["H7725","Return",0,6],["H5766","I pray you, let it not be iniquity",8,42],["H7725","yea, return again",44,61],["H6664","my righteousness",63,79]]},"6:30":{"text":"Is there iniquity in my tongue? cannot my taste discern perverse things?","words":[["H3426","Is there",0,8],["H5766","iniquity",9,17],["H3956","in my tongue",18,30],["H2441","cannot my taste",32,47],["H0995","discern",48,55],["H1942","perverse things",56,71]]},"7:1":{"text":"Is there not an appointed time to man upon earth? are not his days also like the days of an hireling?","words":[["H6635","Is there not an appointed time",0,30],["H0582","to man",31,37],["H0776","upon earth",38,48],["H3117","are not his days",50,66],["H3117","also like the days",67,85],["H7916","of an hireling",86,100]]},"7:2":{"text":"As a servant earnestly desireth the shadow, and as an hireling looketh for the reward of his work:","words":[["H5650","As a servant",0,12],["H7602","earnestly desireth",13,31],["H6738","the shadow",32,42],["H7916","and as an hireling",44,62],["H6960","looketh",63,70],["H6467","for the reward of his work",71,97]]},"7:3":{"text":"So am I made to possess months of vanity, and wearisome nights are appointed to me.","words":[["H5157","So am I made to possess",0,23],["H3391","months",24,30],["H7723","of vanity",31,40],["H5999","and wearisome",42,55],["H3915","nights",56,62],["H4487","are appointed",63,76]]},"7:4":{"text":"When I lie down, I say, When shall I arise, and the night be gone? and I am full of tossings to and fro unto the dawning of the day.","words":[["H7901","When I lie down",0,15],["H0559","I say",17,22],["H6965","When shall I arise",24,42],["H6153","and the night",44,57],["H4059","be gone",58,65],["H7646","and I am full",67,80],["H5076","of tossings to and fro",81,103],["H5399","unto the dawning of the day",104,131]]},"7:5":{"text":"My flesh is clothed with worms and clods of dust; my skin is broken, and become loathsome.","words":[["H1320","My flesh",0,8],["H3847","is clothed",9,19],["H7415","with worms",20,30],["H1487","and clods",31,40],["H6083","of dust",41,48],["H5785","my skin",50,57],["H7280","is broken",58,67],["H3988","and become loathsome",69,89]]},"7:6":{"text":"My days are swifter than a weaver's shuttle, and are spent without hope.","words":[["H3117","My days",0,7],["H7043","are swifter",8,19],["H0708","than a weaver's shuttle",20,43],["H3615","and are spent",45,58],["H0657","without",59,66],["H8615","hope",67,71]]},"7:7":{"text":"O remember that my life is wind: mine eye shall no more see good.","words":[["H2142","O remember",0,10],["H2416","that my life",11,23],["H7307","is wind",24,31],["H5869","mine eye",33,41],["H7725","shall no more",42,55],["H7200","see",56,59],["H2896","good",60,64]]},"7:8":{"text":"The eye of him that hath seen me shall see me no more: thine eyes are upon me, and I am not.","words":[["H5869","The eye",0,7],["H7210","of him that hath seen",8,29],["H7789","me shall see",30,42],["H5869","me no more: thine eyes",43,65]]},"7:9":{"text":"As the cloud is consumed and vanisheth away: so he that goeth down to the grave shall come up no more.","words":[["H6051","As the cloud",0,12],["H3615","is consumed",13,24],["H3212","and vanisheth away",25,43],["H3381","so he that goeth down",45,66],["H7585","to the grave",67,79],["H5927","shall come up",80,93]]},"7:10":{"text":"He shall return no more to his house, neither shall his place know him any more.","words":[["H7725","He shall return",0,15],["H1004","no more to his house",16,36],["H4725","neither shall his place",38,61],["H5234","know",62,66]]},"7:11":{"text":"Therefore I will not refrain my mouth; I will speak in the anguish of my spirit; I will complain in the bitterness of my soul.","words":[["H2820","Therefore I will not refrain",0,28],["H6310","my mouth",29,37],["H1696","I will speak",39,51],["H6862","in the anguish",52,66],["H7307","of my spirit",67,79],["H7878","I will complain",81,96],["H4751","in the bitterness",97,114],["H5315","of my soul",115,125]]},"7:12":{"text":"Am I a sea, or a whale, that thou settest a watch over me?","words":[["H3220","Am I a sea",0,10],["H8577","or a whale",12,22],["H7760","that thou settest",24,41],["H4929","a watch",42,49]]},"7:13":{"text":"When I say, My bed shall comfort me, my couch shall ease my complaint;","words":[["H0559","When I say",0,10],["H6210","My bed",12,18],["H5162","shall comfort",19,32],["H4904","me, my couch",33,45],["H5375","shall ease",46,56],["H7879","my complaint",57,69]]},"7:14":{"text":"Then thou scarest me with dreams, and terrifiest me through visions:","words":[["H2865","Then thou scarest",0,17],["H2472","me with dreams",18,32],["H1204","and terrifiest",34,48],["H2384","me through visions",49,67]]},"7:15":{"text":"So that my soul chooseth strangling, and death rather than my life.","words":[["H5315","So that my soul",0,15],["H0977","chooseth",16,24],["H4267","strangling",25,35],["H4194","and death",37,46],["H6106","rather than my life",47,66]]},"7:16":{"text":"I loathe it; I would not live alway: let me alone; for my days are vanity.","words":[["H3988","I loathe",0,8],["H2421","it; I would not live",9,29],["H5769","alway",30,35],["H2308","let me alone",37,49],["H3117","for my days",51,62],["H1892","are vanity",63,73]]},"7:17":{"text":"What is man, that thou shouldest magnify him? and that thou shouldest set thine heart upon him?","words":[["H0582","What is man",0,11],["H1431","that thou shouldest magnify",13,40],["H7896","him? and that thou shouldest set",41,73],["H3820","thine heart",74,85]]},"7:18":{"text":"And that thou shouldest visit him every morning, and try him every moment?","words":[["H6485","And that thou shouldest visit",0,29],["H1242","him every morning",30,47],["H0974","and try",49,56],["H7281","him every moment",57,73]]},"7:19":{"text":"How long wilt thou not depart from me, nor let me alone till I swallow down my spittle?","words":[["H4100","How long",0,8],["H8159","wilt thou not depart",9,29],["H7503","from me, nor let me alone",30,55],["H1104","till I swallow down",56,75],["H7536","my spittle",76,86]]},"7:20":{"text":"I have sinned; what shall I do unto thee, O thou preserver of men? why hast thou set me as a mark against thee, so that I am a burden to myself?","words":[["H2398","I have sinned",0,13],["H6466","what shall I do",15,30],["H5341","unto thee, O thou preserver",31,58],["H0120","of men",59,65],["H7760","why hast thou set",67,84],["H4645","me as a mark",85,97],["H4853","against thee, so that I am a burden",98,133]]},"7:21":{"text":"And why dost thou not pardon my transgression, and take away mine iniquity? for now shall I sleep in the dust; and thou shalt seek me in the morning, but I shall not be.","words":[["H5375","And why dost thou not pardon",0,28],["H6588","my transgression",29,45],["H5674","and take away",47,60],["H5771","mine iniquity",61,74],["H7901","for now shall I sleep",76,97],["H6083","in the dust",98,109],["H7836","and thou shalt seek me in the morning",111,148]]},"8:1":{"text":"Then answered Bildad the Shuhite, and said,","words":[["H6030","Then answered",0,13],["H1085","Bildad",14,20],["H7747","the Shuhite",21,32],["H0559","and said",34,42]]},"8:2":{"text":"How long wilt thou speak these things? and how long shall the words of thy mouth be like a strong wind?","words":[["H0575","How",0,3],["H5704","long",4,8],["H4448","wilt thou speak",9,24],["H0561","these things? and how long shall the words",25,67],["H6310","of thy mouth",68,80],["H3524","be like a strong",81,97],["H7307","wind",98,102]]},"8:3":{"text":"Doth God pervert judgment? or doth the Almighty pervert justice?","words":[["H0410","Doth God",0,8],["H5791","pervert",9,16],["H4941","judgment",17,25],["H7706","or doth the Almighty",27,47],["H5791","pervert",48,55],["H6664","justice",56,63]]},"8:4":{"text":"If thy children have sinned against him, and he have cast them away for their transgression;","words":[["H1121","If thy children",0,15],["H2398","have sinned",16,27],["H7971","against him, and he have cast them away",28,67],["H3027","for",68,71],["H6588","their transgression",72,91]]},"8:5":{"text":"If thou wouldest seek unto God betimes, and make thy supplication to the Almighty;","words":[["H7836","If thou wouldest seek",0,21],["H0410","unto God",22,30],["H7836","betimes",31,38],["H2603","and make thy supplication",40,65],["H7706","to the Almighty",66,81]]},"8:6":{"text":"If thou wert pure and upright; surely now he would awake for thee, and make the habitation of thy righteousness prosperous.","words":[["H2134","If thou wert pure",0,17],["H3477","and upright",18,29],["H5782","surely now he would awake",31,56],["H5116","for thee, and make the habitation",57,90],["H6664","of thy righteousness",91,111],["H7999","prosperous",112,122]]},"8:7":{"text":"Though thy beginning was small, yet thy latter end should greatly increase.","words":[["H7225","Though thy beginning",0,20],["H4705","was small",21,30],["H0319","yet thy latter end",32,50],["H3966","should greatly",51,65],["H7685","increase",66,74]]},"8:8":{"text":"For enquire, I pray thee, of the former age, and prepare thyself to the search of their fathers:","words":[["H7592","For enquire",0,11],["H7223","I pray thee, of the former",13,39],["H7223","I pray thee, of the former",13,39],["H1755","age",40,43],["H3559","and prepare",45,56],["H2714","thyself to the search",57,78],["H0001","of their fathers",79,95]]},"8:9":{"text":"(For we are but of yesterday, and know nothing, because our days upon earth are a shadow:)","words":[["H8543","(For we are but of yesterday",0,28],["H3045","and know",30,38],["H3117","nothing, because our days",39,64],["H0776","upon earth",65,75],["H6738","are a shadow",76,88]]},"8:10":{"text":"Shall not they teach thee, and tell thee, and utter words out of their heart?","words":[["H3384","Shall not they teach",0,20],["H0559","thee, and tell",21,35],["H3318","thee, and utter",36,51],["H4405","words",52,57],["H3820","out of their heart",58,76]]},"8:11":{"text":"Can the rush grow up without mire? can the flag grow without water?","words":[["H1573","Can the rush",0,12],["H1342","grow up",13,20],["H1207","without mire",21,33],["H7685","can",35,38],["H0260","the flag",39,47],["H7685","grow",48,52],["H1097","without",53,60],["H4325","water",61,66]]},"8:12":{"text":"Whilst it is yet in his greenness, and not cut down, it withereth before any other herb.","words":[["H0003","Whilst it is yet in his greenness",0,33],["H6998","and not cut down",35,51],["H3001","it withereth",53,65],["H6440","before",66,72],["H2682","any other herb",73,87]]},"8:13":{"text":"So are the paths of all that forget God; and the hypocrite's hope shall perish:","words":[["H0734","So are the paths",0,16],["H7911","of all that forget",17,35],["H0410","God",36,39],["H2611","and the hypocrite's",41,60],["H8615","hope",61,65],["H0006","shall perish",66,78]]},"8:14":{"text":"Whose hope shall be cut off, and whose trust shall be a spider's web.","words":[["H3689","Whose hope",0,10],["H6990","shall be cut off",11,27],["H4009","and whose trust",29,44],["H5908","shall be a spider's",45,64],["H1004","web",65,68]]},"8:15":{"text":"He shall lean upon his house, but it shall not stand: he shall hold it fast, but it shall not endure.","words":[["H8172","He shall lean",0,13],["H1004","upon his house",14,28],["H5975","but it shall not stand",30,52],["H2388","he shall hold",54,67],["H6965","it fast, but it shall not endure",68,100]]},"8:16":{"text":"He is green before the sun, and his branch shooteth forth in his garden.","words":[["H7373","He is green",0,11],["H6440","before",12,18],["H8121","the sun",19,26],["H3127","and his branch",28,42],["H3318","shooteth forth",43,57],["H1593","in his garden",58,71]]},"8:17":{"text":"His roots are wrapped about the heap, and seeth the place of stones.","words":[["H8328","His roots",0,9],["H5440","are wrapped about",10,27],["H1530","the heap",28,36],["H2372","and seeth",38,47],["H1004","the place",48,57],["H0068","of stones",58,67]]},"8:18":{"text":"If he destroy him from his place, then it shall deny him, saying, I have not seen thee.","words":[["H1104","If he destroy",0,13],["H4725","him from his place",14,32],["H3584","then it shall deny",34,52],["H7200","him, saying, I have not seen",53,81]]},"8:19":{"text":"Behold, this is the joy of his way, and out of the earth shall others grow.","words":[["H4885","Behold, this is the joy",0,23],["H1870","of his way",24,34],["H6083","and out of the earth",36,56],["H0312","shall others",57,69],["H6779","grow",70,74]]},"8:20":{"text":"Behold, God will not cast away a perfect man, neither will he help the evil doers:","words":[["H0410","Behold, God",0,11],["H3988","will not cast away",12,30],["H8535","a perfect",31,40],["H2388","man, neither will he help",41,66],["H3027","man, neither will he help",41,66],["H7489","the evil doers",67,81]]},"8:21":{"text":"Till he fill thy mouth with laughing, and thy lips with rejoicing.","words":[["H4390","Till he fill",0,12],["H6310","thy mouth",13,22],["H7814","with laughing",23,36],["H8193","and thy lips",38,50],["H8643","with rejoicing",51,65]]},"8:22":{"text":"They that hate thee shall be clothed with shame; and the dwelling place of the wicked shall come to nought.","words":[["H8130","They that hate",0,14],["H3847","thee shall be clothed",15,36],["H1322","with shame",37,47],["H0168","and the dwelling",49,65],["H7563","place of the wicked",66,85],["H0369","shall come to nought",86,106]]},"9:1":{"text":"Then Job answered and said,","words":[["H0347","Then Job",0,8],["H6030","answered",9,17],["H0559","and said",18,26]]},"9:2":{"text":"I know it is so of a truth: but how should man be just with God?","words":[["H3045","I know",0,6],["H0551","it is so of a truth",7,26],["H0582","but how should man",28,46],["H6663","be just",47,54],["H0410","with God",55,63]]},"9:3":{"text":"If he will contend with him, he cannot answer him one of a thousand.","words":[["H2654","If he will",0,10],["H7378","contend",11,18],["H6030","with him, he cannot answer",19,45],["H0259","him one",46,53],["H0505","of a thousand",54,67]]},"9:4":{"text":"He is wise in heart, and mighty in strength: who hath hardened himself against him, and hath prospered?","words":[["H2450","He is wise",0,10],["H3824","in heart",11,19],["H0533","and mighty",21,31],["H3581","in strength",32,43],["H7185","who hath hardened",45,62],["H7999","himself against him, and hath prospered",63,102]]},"9:5":{"text":"Which removeth the mountains, and they know not: which overturneth them in his anger.","words":[["H6275","Which removeth",0,14],["H2022","the mountains",15,28],["H3045","and they know",30,43],["H2015","not: which overturneth",44,66],["H0639","them in his anger",67,84]]},"9:6":{"text":"Which shaketh the earth out of her place, and the pillars thereof tremble.","words":[["H7264","Which shaketh",0,13],["H0776","the earth",14,23],["H4725","out of her place",24,40],["H5982","and the pillars",42,57],["H6426","thereof tremble",58,73]]},"9:7":{"text":"Which commandeth the sun, and it riseth not; and sealeth up the stars.","words":[["H0559","Which commandeth",0,16],["H2775","the sun",17,24],["H2224","and it riseth",26,39],["H2856","not; and sealeth up",40,59],["H3556","the stars",60,69]]},"9:8":{"text":"Which alone spreadeth out the heavens, and treadeth upon the waves of the sea.","words":[["H5186","Which alone spreadeth out",0,25],["H8064","the heavens",26,37],["H1869","and treadeth",39,51],["H1116","upon the waves",52,66],["H3220","of the sea",67,77]]},"9:9":{"text":"Which maketh Arcturus, Orion, and Pleiades, and the chambers of the south.","words":[["H6213","Which maketh",0,12],["H5906","Arcturus",13,21],["H3685","Orion",23,28],["H3598","and Pleiades",30,42],["H2315","and the chambers",44,60],["H8486","of the south",61,73]]},"9:10":{"text":"Which doeth great things past finding out; yea, and wonders without number.","words":[["H6213","Which doeth",0,11],["H1419","great things",12,24],["H0369","past",25,29],["H2714","finding out",30,41],["H6381","yea, and wonders",43,59],["H4557","without number",60,74]]},"9:11":{"text":"Lo, he goeth by me, and I see him not: he passeth on also, but I perceive him not.","words":[["H5674","Lo, he goeth",0,12],["H7200","by me, and I see",13,29],["H2498","him not: he passeth on",30,52],["H0995","also, but I perceive",53,73]]},"9:12":{"text":"Behold, he taketh away, who can hinder him? who will say unto him, What doest thou?","words":[["H2862","Behold, he taketh away",0,22],["H7725","who can hinder",24,38],["H0559","him? who will say",39,56],["H6213","unto him, What doest",57,77]]},"9:13":{"text":"If God will not withdraw his anger, the proud helpers do stoop under him.","words":[["H0433","If God",0,6],["H7725","will not withdraw",7,24],["H0639","his anger",25,34],["H7293","the proud",36,45],["H5826","helpers",46,53],["H7817","do stoop",54,62]]},"9:14":{"text":"How much less shall I answer him, and choose out my words to reason with him?","words":[["H6030","How much less shall I answer",0,28],["H0977","him, and choose out",29,48],["H1697","my words",49,57]]},"9:15":{"text":"Whom, though I were righteous, yet would I not answer, but I would make supplication to my judge.","words":[["H6663","Whom, though I were righteous",0,29],["H6030","yet would I not answer",31,53],["H2603","but I would make supplication",55,84],["H8199","to my judge",85,96]]},"9:16":{"text":"If I had called, and he had answered me; yet would I not believe that he had hearkened unto my voice.","words":[["H7121","If I had called",0,15],["H6030","and he had answered",17,36],["H0539","me; yet would I not believe",37,64],["H0238","that he had hearkened",65,86],["H6963","unto my voice",87,100]]},"9:17":{"text":"For he breaketh me with a tempest, and multiplieth my wounds without cause.","words":[["H7779","For he breaketh",0,15],["H8183","me with a tempest",16,33],["H7235","and multiplieth",35,50],["H6482","my wounds",51,60],["H2600","without cause",61,74]]},"9:18":{"text":"He will not suffer me to take my breath, but filleth me with bitterness.","words":[["H5414","He will not suffer",0,18],["H7725","me to take",19,29],["H7307","my breath",30,39],["H7646","but filleth",41,52],["H4472","me with bitterness",53,71]]},"9:19":{"text":"If I speak of strength, lo, he is strong: and if of judgment, who shall set me a time to plead?","words":[["H3581","If I speak of strength",0,22],["H0533","lo, he is strong",24,40],["H4941","and if of judgment",42,60],["H3259","who shall set",62,75]]},"9:20":{"text":"If I justify myself, mine own mouth shall condemn me: if I say, I am perfect, it shall also prove me perverse.","words":[["H6663","If I justify",0,12],["H6310","myself, mine own mouth",13,35],["H7561","shall condemn",36,49],["H8535","me: if I say, I am perfect",50,76],["H6140","it shall also prove me perverse",78,109]]},"9:21":{"text":"Though I were perfect, yet would I not know my soul: I would despise my life.","words":[["H8535","Though I were perfect",0,21],["H3045","yet would I not know",23,43],["H5315","my soul",44,51],["H3988","I would despise",53,68],["H2416","my life",69,76]]},"9:22":{"text":"This is one thing, therefore I said it, He destroyeth the perfect and the wicked.","words":[["H0259","This is one",0,11],["H0559","thing, therefore I said",12,35],["H3615","it, He destroyeth",36,53],["H8535","the perfect",54,65],["H7563","and the wicked",66,80]]},"9:23":{"text":"If the scourge slay suddenly, he will laugh at the trial of the innocent.","words":[["H7752","If the scourge",0,14],["H4191","slay",15,19],["H6597","suddenly",20,28],["H3932","he will laugh",30,43],["H4531","at the trial",44,56],["H5355","of the innocent",57,72]]},"9:24":{"text":"The earth is given into the hand of the wicked: he covereth the faces of the judges thereof; if not, where, and who is he?","words":[["H0776","The earth",0,9],["H5414","is given",10,18],["H3027","into the hand",19,32],["H7563","of the wicked",33,46],["H3680","he covereth",48,59],["H6440","the faces",60,69],["H8199","of the judges",70,83],["H0645","thereof; if not, where",84,106]]},"9:25":{"text":"Now my days are swifter than a post: they flee away, they see no good.","words":[["H3117","Now my days",0,11],["H7043","are swifter",12,23],["H7323","than a post",24,35],["H1272","they flee away",37,51],["H7200","they see",53,61],["H2896","no good",62,69]]},"9:26":{"text":"They are passed away as the swift ships: as the eagle that hasteth to the prey.","words":[["H2498","They are passed away",0,20],["H5973","as",21,23],["H0016","the swift",24,33],["H0591","ships",34,39],["H5404","as the eagle",41,53],["H2907","that hasteth",54,66],["H0400","to the prey",67,78]]},"9:27":{"text":"If I say, I will forget my complaint, I will leave off my heaviness, and comfort myself:","words":[["H0559","If I say",0,8],["H7911","I will forget",10,23],["H7879","my complaint",24,36],["H5800","I will leave off",38,54],["H6440","my heaviness",55,67],["H1082","and comfort",69,80]]},"9:28":{"text":"I am afraid of all my sorrows, I know that thou wilt not hold me innocent.","words":[["H3025","I am afraid",0,11],["H6094","of all my sorrows",12,29],["H3045","I know",31,37],["H5352","that thou wilt not hold me innocent",38,73]]},"9:29":{"text":"If I be wicked, why then labour I in vain?","words":[["H7561","If I be wicked",0,14],["H3021","why then labour",16,31],["H1892","I in vain",32,41]]},"9:30":{"text":"If I wash myself with snow water, and make my hands never so clean;","words":[["H7364","If I wash",0,9],["H7950","myself with",10,21],["H4325","snow water",22,32],["H1119","snow water",22,32],["H3709","and make my hands",34,51],["H1252","never",52,57],["H1253","never",52,57],["H2141","so clean",58,66]]},"9:31":{"text":"Yet shalt thou plunge me in the ditch, and mine own clothes shall abhor me.","words":[["H0227","Yet",0,3],["H2881","shalt thou plunge",4,21],["H7845","me in the ditch",22,37],["H8008","and mine own clothes",39,59],["H8581","shall abhor",60,71]]},"9:32":{"text":"For he is not a man, as I am, that I should answer him, and we should come together in judgment.","words":[["H0376","For he is not a man",0,19],["H6030","as I am, that I should answer",21,50],["H0935","him, and we should come",51,74],["H3162","together",75,83],["H4941","in judgment",84,95]]},"9:33":{"text":"Neither is there any daysman betwixt us, that might lay his hand upon us both.","words":[["H3426","Neither is",0,10],["H3198","there any daysman",11,28],["H7896","betwixt us, that might lay",29,55],["H3027","his hand",56,64],["H8147","upon us both",65,77]]},"9:34":{"text":"Let him take his rod away from me, and let not his fear terrify me:","words":[["H5493","Let him take",0,12],["H7626","his rod",13,20],["H5493","away",21,25],["H0367","from me, and let not his fear",26,55],["H1204","terrify",56,63]]},"9:35":{"text":"Then would I speak, and not fear him; but it is not so with me.","words":[["H1696","Then would I speak",0,18],["H3372","and not fear",20,32]]},"10:1":{"text":"My soul is weary of my life; I will leave my complaint upon myself; I will speak in the bitterness of my soul.","words":[["H5315","My soul",0,7],["H5354","is weary",8,16],["H2416","of my life",17,27],["H5800","I will leave",29,41],["H7879","my complaint",42,54],["H1696","upon myself; I will speak",55,80],["H4751","in the bitterness",81,98],["H5315","of my soul",99,109]]},"10:2":{"text":"I will say unto God, Do not condemn me; shew me wherefore thou contendest with me.","words":[["H0559","I will say",0,10],["H0433","unto God",11,19],["H7561","Do not condemn",21,35],["H3045","me; shew",36,44],["H7378","me wherefore thou contendest",45,73]]},"10:3":{"text":"Is it good unto thee that thou shouldest oppress, that thou shouldest despise the work of thine hands, and shine upon the counsel of the wicked?","words":[["H2895","Is it good",0,10],["H6231","unto thee that thou shouldest oppress",11,48],["H3988","that thou shouldest despise",50,77],["H3018","the work",78,86],["H3709","of thine hands",87,101],["H3313","and shine",103,112],["H6098","upon the counsel",113,129],["H7563","of the wicked",130,143]]},"10:4":{"text":"Hast thou eyes of flesh? or seest thou as man seeth?","words":[["H5869","Hast thou eyes",0,14],["H1320","of flesh",15,23],["H7200","or seest",25,33],["H0582","thou as man",34,45],["H7200","seeth",46,51]]},"10:5":{"text":"Are thy days as the days of man? are thy years as man's days,","words":[["H3117","Are thy days",0,12],["H3117","as the days",13,24],["H0582","of man",25,31],["H8141","are thy years",33,46],["H1397","as man's",47,55],["H3117","days",56,60]]},"10:6":{"text":"That thou enquirest after mine iniquity, and searchest after my sin?","words":[["H1245","That thou enquirest",0,19],["H5771","after mine iniquity",20,39],["H1875","and searchest",41,54],["H2403","after my sin",55,67]]},"10:7":{"text":"Thou knowest that I am not wicked; and there is none that can deliver out of thine hand.","words":[["H1847","Thou knowest",0,12],["H7561","that I am not wicked",13,33],["H5337","and there is none that can deliver",35,69],["H3027","out of thine hand",70,87]]},"10:8":{"text":"Thine hands have made me and fashioned me together round about; yet thou dost destroy me.","words":[["H3027","Thine hands",0,11],["H6087","have made",12,21],["H6213","me and fashioned",22,38],["H3162","me together",39,50],["H5439","round about",51,62],["H1104","yet thou dost destroy",64,85]]},"10:9":{"text":"Remember, I beseech thee, that thou hast made me as the clay; and wilt thou bring me into dust again?","words":[["H2142","Remember",0,8],["H6213","I beseech thee, that thou hast made",10,45],["H2563","me as the clay",46,60],["H7725","and wilt thou bring",62,81],["H6083","me into dust",82,94],["H7725","again",95,100]]},"10:10":{"text":"Hast thou not poured me out as milk, and curdled me like cheese?","words":[["H5413","Hast thou not poured me out",0,27],["H2461","as milk",28,35],["H7087","and curdled",37,48],["H1385","me like cheese",49,63]]},"10:11":{"text":"Thou hast clothed me with skin and flesh, and hast fenced me with bones and sinews.","words":[["H3847","Thou hast clothed",0,17],["H5785","me with skin",18,30],["H1320","and flesh",31,40],["H7753","and hast fenced",42,57],["H6106","me with bones",58,71],["H1517","and sinews",72,82]]},"10:12":{"text":"Thou hast granted me life and favour, and thy visitation hath preserved my spirit.","words":[["H6213","Thou hast granted",0,17],["H2416","me life",18,25],["H2617","and favour",26,36],["H6486","and thy visitation",38,56],["H8104","hath preserved",57,71],["H7307","my spirit",72,81]]},"10:13":{"text":"And these things hast thou hid in thine heart: I know that this is with thee.","words":[["H6845","And these things hast thou hid",0,30],["H3824","in thine heart",31,45],["H3045","I know",47,53]]},"10:14":{"text":"If I sin, then thou markest me, and thou wilt not acquit me from mine iniquity.","words":[["H2398","If I sin",0,8],["H8104","then thou markest",10,27],["H5352","me, and thou wilt not acquit",28,56],["H5771","me from mine iniquity",57,78]]},"10:15":{"text":"If I be wicked, woe unto me; and if I be righteous, yet will I not lift up my head. I am full of confusion; therefore see thou mine affliction;","words":[["H7561","If I be wicked",0,14],["H0480","woe",16,19],["H6663","unto me; and if I be righteous",20,50],["H5375","yet will I not lift up",52,74],["H7218","my head",75,82],["H7649","I am full",84,93],["H7036","of confusion",94,106],["H7202","therefore see",108,121],["H7200","therefore see",108,121],["H6040","thou mine affliction",122,142]]},"10:16":{"text":"For it increaseth. Thou huntest me as a fierce lion: and again thou shewest thyself marvellous upon me.","words":[["H1342","For it increaseth",0,17],["H6679","Thou huntest",19,31],["H7826","me as a fierce lion",32,51],["H7725","and again",53,62],["H6381","thou shewest thyself marvellous",63,94]]},"10:17":{"text":"Thou renewest thy witnesses against me, and increasest thine indignation upon me; changes and war are against me.","words":[["H2318","Thou renewest",0,13],["H5707","thy witnesses",14,27],["H7235","against me, and increasest",28,54],["H3708","thine indignation",55,72],["H5978","upon me",73,80],["H2487","changes",82,89],["H6635","and war",90,97]]},"10:18":{"text":"Wherefore then hast thou brought me forth out of the womb? Oh that I had given up the ghost, and no eye had seen me!","words":[["H3318","Wherefore then hast thou brought me forth",0,41],["H7358","out of the womb",42,57],["H1478","Oh that I had given up the ghost",59,91],["H5869","and no eye",93,103],["H7200","had seen",104,112]]},"10:19":{"text":"I should have been as though I had not been; I should have been carried from the womb to the grave.","words":[["H2986","I should have been as though I had not been; I should have been carried",0,71],["H0990","from the womb",72,85],["H6913","to the grave",86,98]]},"10:20":{"text":"Are not my days few? cease then, and let me alone, that I may take comfort a little,","words":[["H3117","Are not my days",0,15],["H4592","few",16,19],["H2308","cease",21,26],["H2308","cease",21,26],["H7896","then, and let me alone",27,49],["H7896","then, and let me alone",27,49],["H1082","that I may take comfort",51,74],["H4592","a little",75,83]]},"10:21":{"text":"Before I go whence I shall not return, even to the land of darkness and the shadow of death;","words":[["H3212","Before I go",0,11],["H7725","whence I shall not return",12,37],["H0776","even to the land",39,55],["H2822","of darkness",56,67],["H6757","and the shadow of death",68,91]]},"10:22":{"text":"A land of darkness, as darkness itself; and of the shadow of death, without any order, and where the light is as darkness.","words":[["H0776","A land",0,6],["H5890","of darkness",7,18],["H0652","as darkness",20,31],["H6757","itself; and of the shadow of death",32,66],["H5468","without any order",68,85],["H3313","and where the light",87,106],["H0652","is as darkness",107,121]]},"11:1":{"text":"Then answered Zophar the Naamathite, and said,","words":[["H6030","Then answered",0,13],["H6691","Zophar",14,20],["H5284","the Naamathite",21,35],["H0559","and said",37,45]]},"11:2":{"text":"Should not the multitude of words be answered? and should a man full of talk be justified?","words":[["H7230","Should not the multitude",0,24],["H1697","of words",25,33],["H6030","be answered",34,45],["H0376","and should a man",47,63],["H8193","full of talk",64,76],["H6663","be justified",77,89]]},"11:3":{"text":"Should thy lies make men hold their peace? and when thou mockest, shall no man make thee ashamed?","words":[["H0907","Should thy lies",0,15],["H2790","make",16,20],["H4962","men",21,24],["H2790","hold their peace",25,41],["H3932","and when thou mockest",43,64],["H3637","shall no man make thee ashamed",66,96]]},"11:4":{"text":"For thou hast said, My doctrine is pure, and I am clean in thine eyes.","words":[["H0559","For thou hast said",0,18],["H3948","My doctrine",20,31],["H2134","is pure",32,39],["H1249","and I am clean",41,55],["H5869","in thine eyes",56,69]]},"11:5":{"text":"But oh that God would speak, and open his lips against thee;","words":[["H0199","But",0,3],["H5414","oh that",4,11],["H0433","God",12,15],["H1696","would speak",16,27],["H6605","and open",29,37],["H8193","his lips",38,46]]},"11:6":{"text":"And that he would shew thee the secrets of wisdom, that they are double to that which is! Know therefore that God exacteth of thee less than thine iniquity deserveth.","words":[["H5046","And that he would shew",0,22],["H8587","thee the secrets",23,39],["H2451","of wisdom",40,49],["H3718","that they are double",51,71],["H8454","to that which is",72,88],["H3045","Know",90,94],["H0433","therefore that God",95,113],["H5382","exacteth",114,122],["H5771","of thee less than thine iniquity",123,155]]},"11:7":{"text":"Canst thou by searching find out God? canst thou find out the Almighty unto perfection?","words":[["H2714","Canst thou by searching",0,23],["H4672","find out",24,32],["H0433","God",33,36],["H4672","canst thou find",38,53],["H7706","out the Almighty",54,70],["H8503","unto perfection",71,86]]},"11:8":{"text":"It is as high as heaven; what canst thou do? deeper than hell; what canst thou know?","words":[["H1363","It is as high",0,13],["H8064","as heaven",14,23],["H6466","what canst thou do",25,43],["H6013","deeper",45,51],["H7585","than hell",52,61],["H3045","what canst thou know",63,83]]},"11:9":{"text":"The measure thereof is longer than the earth, and broader than the sea.","words":[["H4055","The measure",0,11],["H0752","thereof is longer",12,29],["H0776","than the earth",30,44],["H7342","and broader",46,57],["H3220","than the sea",58,70]]},"11:10":{"text":"If he cut off, and shut up, or gather together, then who can hinder him?","words":[["H2498","If he cut off",0,13],["H5462","and shut up",15,26],["H6950","or gather together",28,46],["H7725","then who can hinder",48,67]]},"11:11":{"text":"For he knoweth vain men: he seeth wickedness also; will he not then consider it?","words":[["H3045","For he knoweth",0,14],["H7723","vain",15,19],["H4962","men",20,23],["H7200","he seeth",25,33],["H0205","wickedness",34,44],["H0995","also; will he not then consider",45,76]]},"11:12":{"text":"For vain man would be wise, though man be born like a wild ass's colt.","words":[["H5014","For vain",0,8],["H0376","man",9,12],["H3823","would be wise",13,26],["H0120","though man",28,38],["H3205","be born",39,46],["H6501","like a wild ass's",47,64],["H5895","colt",65,69]]},"11:13":{"text":"If thou prepare thine heart, and stretch out thine hands toward him;","words":[["H3559","If thou prepare",0,15],["H3820","thine heart",16,27],["H6566","and stretch",29,40],["H3709","out thine hands",41,56]]},"11:14":{"text":"If iniquity be in thine hand, put it far away, and let not wickedness dwell in thy tabernacles.","words":[["H0205","If iniquity",0,11],["H3027","be in thine hand",12,28],["H7368","put it far away",30,45],["H5766","and let not wickedness",47,69],["H7931","dwell",70,75],["H0168","in thy tabernacles",76,94]]},"11:15":{"text":"For then shalt thou lift up thy face without spot; yea, thou shalt be stedfast, and shalt not fear:","words":[["H5375","For then shalt thou lift up",0,27],["H6440","thy face",28,36],["H3971","without spot",37,49],["H3332","yea, thou shalt be stedfast",51,78],["H3372","and shalt not fear",80,98]]},"11:16":{"text":"Because thou shalt forget thy misery, and remember it as waters that pass away:","words":[["H7911","Because thou shalt forget",0,25],["H5999","thy misery",26,36],["H2142","and remember",38,50],["H4325","it as waters",51,63],["H5674","that pass away",64,78]]},"11:17":{"text":"And thine age shall be clearer than the noonday; thou shalt shine forth, thou shalt be as the morning.","words":[["H2465","And thine age",0,13],["H6965","shall be clearer",14,30],["H6672","than the noonday",31,47],["H5774","thou shalt shine forth",49,71],["H1242","thou shalt be as the morning",73,101]]},"11:18":{"text":"And thou shalt be secure, because there is hope; yea, thou shalt dig about thee, and thou shalt take thy rest in safety.","words":[["H0982","And thou shalt be secure",0,24],["H3426","because there is",26,42],["H8615","hope",43,47],["H2658","yea, thou shalt dig",49,68],["H7901","about thee, and thou shalt take thy rest",69,109],["H0983","in safety",110,119]]},"11:19":{"text":"Also thou shalt lie down, and none shall make thee afraid; yea, many shall make suit unto thee.","words":[["H7257","Also thou shalt lie down",0,24],["H2729","and none shall make thee afraid",26,57],["H7227","yea, many",59,68],["H2470","shall make suit",69,84],["H6440","unto thee",85,94]]},"11:20":{"text":"But the eyes of the wicked shall fail, and they shall not escape, and their hope shall be as the giving up of the ghost.","words":[["H5869","But the eyes",0,12],["H7563","of the wicked",13,26],["H3615","shall fail",27,37],["H0006","and they shall not escape",39,64],["H4498","and they shall not escape",39,64],["H8615","and their hope",66,80],["H4646","shall be as the giving up",81,106],["H5315","of the ghost",107,119]]},"12:1":{"text":"And Job answered and said,","words":[["H0347","And Job",0,7],["H6030","answered",8,16],["H0559","and said",17,25]]},"12:2":{"text":"No doubt but ye are the people, and wisdom shall die with you.","words":[["H0551","No doubt",0,8],["H5971","but ye are the people",9,30],["H2451","and wisdom",32,42],["H4191","shall die",43,52]]},"12:3":{"text":"But I have understanding as well as you; I am not inferior to you: yea, who knoweth not such things as these?","words":[["H1571","But",0,3],["H3824","I have understanding",4,24],["H5307","as well as you; I am not inferior",25,58],["H3644","to you: yea, who knoweth not such things",59,99]]},"12:4":{"text":"I am as one mocked of his neighbour, who calleth upon God, and he answereth him: the just upright man is laughed to scorn.","words":[["H7814","I am as one mocked",0,18],["H7453","of his neighbour",19,35],["H7121","who calleth",37,48],["H0433","upon God",49,57],["H6030","and he answereth",59,75],["H6662","him: the just",76,89],["H8549","upright",90,97],["H7814","man is laughed to scorn",98,121]]},"12:5":{"text":"He that is ready to slip with his feet is as a lamp despised in the thought of him that is at ease.","words":[["H3559","He that is ready",0,16],["H4571","to slip",17,24],["H7272","with his feet",25,38],["H3940","is as a lamp",39,51],["H0937","despised",52,60],["H6248","in the thought",61,75],["H7600","of him that is at ease",76,98]]},"12:6":{"text":"The tabernacles of robbers prosper, and they that provoke God are secure; into whose hand God bringeth abundantly.","words":[["H0168","The tabernacles",0,15],["H7703","of robbers",16,26],["H7951","prosper",27,34],["H7264","and they that provoke",36,57],["H0410","God",58,61],["H0987","are secure",62,72],["H3027","into whose hand",74,89],["H0433","God",90,93],["H0935","bringeth",94,102]]},"12:7":{"text":"But ask now the beasts, and they shall teach thee; and the fowls of the air, and they shall tell thee:","words":[["H0199","But",0,3],["H7592","ask",4,7],["H0929","now the beasts",8,22],["H3384","and they shall teach",24,44],["H5775","thee; and the fowls",45,64],["H8064","of the air",65,75],["H5046","and they shall tell",77,96]]},"12:8":{"text":"Or speak to the earth, and it shall teach thee: and the fishes of the sea shall declare unto thee.","words":[["H7878","Or speak",0,8],["H0776","to the earth",9,21],["H3384","and it shall teach",23,41],["H1709","thee: and the fishes",42,62],["H3220","of the sea",63,73],["H5608","shall declare",74,87]]},"12:9":{"text":"Who knoweth not in all these that the hand of the LORD hath wrought this?","words":[["H3045","Who knoweth",0,11],["H3027","not in all these that the hand",12,42],["H3068","of the LORD",43,54],["H6213","hath wrought",55,67]]},"12:10":{"text":"In whose hand is the soul of every living thing, and the breath of all mankind.","words":[["H3027","In whose hand",0,13],["H5315","is the soul",14,25],["H2416","of every living thing",26,47],["H7307","and the breath",49,63],["H0376","of all mankind",64,78],["H1320","of all mankind",64,78]]},"12:11":{"text":"Doth not the ear try words? and the mouth taste his meat?","words":[["H0241","Doth not the ear",0,16],["H0974","try",17,20],["H4405","words",21,26],["H2441","and the mouth",28,41],["H2938","taste",42,47],["H0400","his meat",48,56]]},"12:12":{"text":"With the ancient is wisdom; and in length of days understanding.","words":[["H3453","With the ancient",0,16],["H2451","is wisdom",17,26],["H0753","and in length",28,41],["H3117","of days",42,49],["H8394","understanding",50,63]]},"12:13":{"text":"With him is wisdom and strength, he hath counsel and understanding.","words":[["H2451","With him is wisdom",0,18],["H1369","and strength",19,31],["H6098","he hath counsel",33,48],["H8394","and understanding",49,66]]},"12:14":{"text":"Behold, he breaketh down, and it cannot be built again: he shutteth up a man, and there can be no opening.","words":[["H2040","Behold, he breaketh down",0,24],["H1129","and it cannot be built again",26,54],["H5462","he shutteth up",56,70],["H0376","a man",71,76],["H6605","and there can be no opening",78,105]]},"12:15":{"text":"Behold, he withholdeth the waters, and they dry up: also he sendeth them out, and they overturn the earth.","words":[["H6113","Behold, he withholdeth",0,22],["H4325","the waters",23,33],["H3001","and they dry up",35,50],["H7971","also he sendeth them out",52,76],["H2015","and they overturn",78,95],["H0776","the earth",96,105]]},"12:16":{"text":"With him is strength and wisdom: the deceived and the deceiver are his.","words":[["H5797","With him is strength",0,20],["H8454","and wisdom",21,31],["H7683","the deceived",33,45],["H7686","and the deceiver",46,62]]},"12:17":{"text":"He leadeth counsellors away spoiled, and maketh the judges fools.","words":[["H3212","He leadeth",0,10],["H3289","counsellors",11,22],["H7758","away spoiled",23,35],["H8199","and maketh the judges",37,58],["H1984","fools",59,64]]},"12:18":{"text":"He looseth the bond of kings, and girdeth their loins with a girdle.","words":[["H6605","He looseth",0,10],["H4148","the bond",11,19],["H4428","of kings",20,28],["H0631","and girdeth",30,41],["H4975","their loins",42,53],["H0232","with a girdle",54,67]]},"12:19":{"text":"He leadeth princes away spoiled, and overthroweth the mighty.","words":[["H3212","He leadeth",0,10],["H3548","princes",11,18],["H7758","away spoiled",19,31],["H5557","and overthroweth",33,49],["H0386","the mighty",50,60]]},"12:20":{"text":"He removeth away the speech of the trusty, and taketh away the understanding of the aged.","words":[["H5493","He removeth away",0,16],["H8193","the speech",17,27],["H0539","of the trusty",28,41],["H3947","and taketh away",43,58],["H2940","the understanding",59,76],["H2205","of the aged",77,88]]},"12:21":{"text":"He poureth contempt upon princes, and weakeneth the strength of the mighty.","words":[["H8210","He poureth",0,10],["H0937","contempt",11,19],["H5081","upon princes",20,32],["H7503","and weakeneth",34,47],["H4206","the strength",48,60],["H0650","of the mighty",61,74]]},"12:22":{"text":"He discovereth deep things out of darkness, and bringeth out to light the shadow of death.","words":[["H1540","He discovereth",0,14],["H6013","deep things",15,26],["H2822","out of darkness",27,42],["H3318","and bringeth out",44,60],["H0216","to light",61,69],["H6757","the shadow of death",70,89]]},"12:23":{"text":"He increaseth the nations, and destroyeth them: he enlargeth the nations, and straiteneth them again.","words":[["H7679","He increaseth",0,13],["H1471","the nations",14,25],["H0006","and destroyeth",27,41],["H7849","them: he enlargeth",42,60],["H1471","the nations",61,72],["H5148","and straiteneth",74,89]]},"12:24":{"text":"He taketh away the heart of the chief of the people of the earth, and causeth them to wander in a wilderness where there is no way.","words":[["H5493","He taketh away",0,14],["H3820","the heart",15,24],["H7218","of the chief",25,37],["H5971","of the people",38,51],["H0776","of the earth",52,64],["H8582","and causeth them to wander",66,92],["H8414","in a wilderness",93,108],["H1870","where there is no way",109,130]]},"12:25":{"text":"They grope in the dark without light, and he maketh them to stagger like a drunken man.","words":[["H4959","They grope",0,10],["H2822","in the dark",11,22],["H0216","without light",23,36],["H8582","and he maketh them to stagger",38,67],["H7910","like a drunken",68,82]]},"13:1":{"text":"Lo, mine eye hath seen all this, mine ear hath heard and understood it.","words":[["H5869","Lo, mine eye",0,12],["H7200","hath seen",13,22],["H0241","all this, mine ear",23,41],["H8085","hath heard",42,52],["H0995","and understood",53,67]]},"13:2":{"text":"What ye know, the same do I know also: I am not inferior unto you.","words":[["H1847","What ye know",0,12],["H3045","the same do I know",14,32],["H5307","also: I am not inferior",33,56]]},"13:3":{"text":"Surely I would speak to the Almighty, and I desire to reason with God.","words":[["H0199","Surely",0,6],["H1696","I would speak",7,20],["H7706","to the Almighty",21,36],["H2654","and I desire",38,50],["H3198","to reason",51,60],["H0410","with God",61,69]]},"13:4":{"text":"But ye are forgers of lies, ye are all physicians of no value.","words":[["H0199","But",0,3],["H2950","ye are forgers",4,18],["H8267","of lies",19,26],["H7495","ye are all physicians",28,49],["H0457","of no value",50,61]]},"13:5":{"text":"O that ye would altogether hold your peace! and it should be your wisdom.","words":[["H5414","O that",0,6],["H2790","ye would altogether",7,26],["H2790","hold your peace",27,42],["H2451","and it should be your wisdom",44,72]]},"13:6":{"text":"Hear now my reasoning, and hearken to the pleadings of my lips.","words":[["H8085","Hear",0,4],["H8433","now my reasoning",5,21],["H7181","and hearken",23,34],["H7379","to the pleadings",35,51],["H8193","of my lips",52,62]]},"13:7":{"text":"Will ye speak wickedly for God? and talk deceitfully for him?","words":[["H1696","Will ye speak",0,13],["H5766","wickedly",14,22],["H0410","for God",23,30],["H1696","and talk",32,40],["H7423","deceitfully",41,52]]},"13:8":{"text":"Will ye accept his person? will ye contend for God?","words":[["H5375","Will ye accept",0,14],["H6440","his person",15,25],["H7378","will ye contend",27,42],["H0410","for God",43,50]]},"13:9":{"text":"Is it good that he should search you out? or as one man mocketh another, do ye so mock him?","words":[["H2895","Is it good",0,10],["H2713","that he should search you out",11,40],["H0582","or as one man",42,55],["H2048","mocketh",56,63],["H2048","another, do ye so mock",64,86]]},"13:10":{"text":"He will surely reprove you, if ye do secretly accept persons.","words":[["H3198","He will surely",0,14],["H3198","reprove",15,22],["H5643","you, if ye do secretly",23,45],["H5375","accept",46,52],["H6440","persons",53,60]]},"13:11":{"text":"Shall not his excellency make you afraid? and his dread fall upon you?","words":[["H7613","Shall not his excellency",0,24],["H1204","make you afraid",25,40],["H6343","and his dread",42,55],["H5307","fall",56,60]]},"13:12":{"text":"Your remembrances are like unto ashes, your bodies to bodies of clay.","words":[["H2146","Your remembrances",0,17],["H4912","are like",18,26],["H0665","unto ashes",27,37],["H1354","your bodies",39,50],["H1354","to bodies",51,60],["H2563","of clay",61,68]]},"13:13":{"text":"Hold your peace, let me alone, that I may speak, and let come on me what will.","words":[["H2790","Hold your peace",0,15],["H1696","let me alone, that I may speak",17,47],["H5674","and let come",49,61]]},"13:14":{"text":"Wherefore do I take my flesh in my teeth, and put my life in mine hand?","words":[["H5375","Wherefore do I take",0,19],["H1320","my flesh",20,28],["H8127","in my teeth",29,40],["H7760","and put",42,49],["H5315","my life",50,57],["H3709","in mine hand",58,70]]},"13:15":{"text":"Though he slay me, yet will I trust in him: but I will maintain mine own ways before him.","words":[["H2005","Though",0,6],["H6991","he slay",7,14],["H3176","me, yet will I trust",15,35],["H3198","in him: but I will maintain",36,63],["H1870","mine own ways",64,77],["H6440","before",78,84]]},"13:16":{"text":"He also shall be my salvation: for an hypocrite shall not come before him.","words":[["H3444","He also shall be my salvation",0,29],["H2611","for an hypocrite",31,47],["H0935","shall not come",48,62],["H6440","before",63,69]]},"13:17":{"text":"Hear diligently my speech, and my declaration with your ears.","words":[["H8085","Hear",0,4],["H8085","diligently",5,15],["H4405","my speech",16,25],["H0262","and my declaration",27,45],["H0241","with your ears",46,60]]},"13:18":{"text":"Behold now, I have ordered my cause; I know that I shall be justified.","words":[["H6186","Behold now, I have ordered",0,26],["H4941","my cause",27,35],["H3045","I know",37,43],["H6663","that I shall be justified",44,69]]},"13:19":{"text":"Who is he that will plead with me? for now, if I hold my tongue, I shall give up the ghost.","words":[["H7378","Who is he that will plead",0,25],["H2790","with me? for now, if I hold my tongue",26,63],["H1478","I shall give up the ghost",65,90]]},"13:20":{"text":"Only do not two things unto me: then will I not hide myself from thee.","words":[["H6213","Only do",0,7],["H8147","not two",8,15],["H5641","things unto me: then will I not hide",16,52],["H6440","myself from thee",53,69]]},"13:21":{"text":"Withdraw thine hand far from me: and let not thy dread make me afraid.","words":[["H7368","Withdraw",0,8],["H3709","thine hand",9,19],["H7368","far",20,23],["H0367","from me: and let not thy dread",24,54],["H1204","make me afraid",55,69]]},"13:22":{"text":"Then call thou, and I will answer: or let me speak, and answer thou me.","words":[["H7121","Then call",0,9],["H6030","thou, and I will answer",10,33],["H1696","or let me speak",35,50],["H7725","and answer",52,62]]},"13:23":{"text":"How many are mine iniquities and sins? make me to know my transgression and my sin.","words":[["H5771","How many are mine iniquities",0,28],["H2403","and sins",29,37],["H3045","make me to know",39,54],["H6588","my transgression",55,71],["H2403","and my sin",72,82]]},"13:24":{"text":"Wherefore hidest thou thy face, and holdest me for thine enemy?","words":[["H5641","Wherefore hidest",0,16],["H6440","thou thy face",17,30],["H2803","and holdest",32,43],["H0341","me for thine enemy",44,62]]},"13:25":{"text":"Wilt thou break a leaf driven to and fro? and wilt thou pursue the dry stubble?","words":[["H6206","Wilt thou break",0,15],["H5929","a leaf",16,22],["H5086","driven to and fro",23,40],["H7291","and wilt thou pursue",42,62],["H3002","the dry",63,70],["H7179","stubble",71,78]]},"13:26":{"text":"For thou writest bitter things against me, and makest me to possess the iniquities of my youth.","words":[["H3789","For thou writest",0,16],["H4846","bitter things",17,30],["H3423","against me, and makest me to possess",31,67],["H5771","the iniquities",68,82],["H5271","of my youth",83,94]]},"13:27":{"text":"Thou puttest my feet also in the stocks, and lookest narrowly unto all my paths; thou settest a print upon the heels of my feet.","words":[["H7760","Thou puttest",0,12],["H7272","my feet",13,20],["H5465","also in the stocks",21,39],["H8104","and lookest narrowly",41,61],["H0734","unto all my paths",62,79],["H2707","thou settest a print",81,101],["H8328","upon the heels",102,116],["H7272","of my feet",117,127]]},"13:28":{"text":"And he, as a rotten thing, consumeth, as a garment that is moth eaten.","words":[["H7538","And he, as a rotten thing",0,25],["H1086","consumeth",27,36],["H0899","as a garment",38,50],["H6211","that is moth",51,63],["H0398","eaten",64,69]]},"14:1":{"text":"Man that is born of a woman is of few days, and full of trouble.","words":[["H0120","Man",0,3],["H3205","that is born",4,16],["H0802","of a woman",17,27],["H7116","is of few",28,37],["H3117","days",38,42],["H7649","and full",44,52],["H7267","of trouble",53,63]]},"14:2":{"text":"He cometh forth like a flower, and is cut down: he fleeth also as a shadow, and continueth not.","words":[["H3318","He cometh forth",0,15],["H6731","like a flower",16,29],["H5243","and is cut down",31,46],["H1272","he fleeth",48,57],["H6738","also as a shadow",58,74],["H5975","and continueth",76,90]]},"14:3":{"text":"And dost thou open thine eyes upon such an one, and bringest me into judgment with thee?","words":[["H6491","And dost thou open",0,18],["H5869","thine eyes",19,29],["H2088","upon such an one",30,46],["H0935","and bringest",48,60],["H4941","me into judgment",61,77]]},"14:4":{"text":"Who can bring a clean thing out of an unclean? not one.","words":[["H5414","Who can bring",0,13],["H2889","a clean",14,21],["H2931","thing out of an unclean",22,45],["H0259","not one",47,54]]},"14:5":{"text":"Seeing his days are determined, the number of his months are with thee, thou hast appointed his bounds that he cannot pass;","words":[["H0518","Seeing",0,6],["H3117","his days",7,15],["H2782","are determined",16,30],["H4557","the number",32,42],["H2320","of his months",43,56],["H6213","are with thee, thou hast appointed",57,91],["H2706","his bounds",92,102],["H5674","that he cannot pass",103,122]]},"14:6":{"text":"Turn from him, that he may rest, till he shall accomplish, as an hireling, his day.","words":[["H8159","Turn",0,4],["H2308","from him, that he may rest",5,31],["H7521","till he shall accomplish",33,57],["H7916","as an hireling",59,73],["H3117","his day",75,82]]},"14:7":{"text":"For there is hope of a tree, if it be cut down, that it will sprout again, and that the tender branch thereof will not cease.","words":[["H3426","For there is",0,12],["H8615","hope",13,17],["H6086","of a tree",18,27],["H3772","if it be cut down",29,46],["H2498","that it will sprout again",48,73],["H3127","and that the tender branch",75,101],["H2308","thereof will not cease",102,124]]},"14:8":{"text":"Though the root thereof wax old in the earth, and the stock thereof die in the ground;","words":[["H8328","Though the root",0,15],["H2204","thereof wax old",16,31],["H0776","in the earth",32,44],["H1503","and the stock",46,59],["H4191","thereof die",60,71],["H6083","in the ground",72,85]]},"14:9":{"text":"Yet through the scent of water it will bud, and bring forth boughs like a plant.","words":[["H7381","Yet through the scent",0,21],["H4325","of water",22,30],["H6524","it will bud",31,42],["H6213","and bring forth",44,59],["H7105","boughs",60,66],["H5194","like a plant",67,79]]},"14:10":{"text":"But man dieth, and wasteth away: yea, man giveth up the ghost, and where is he?","words":[["H1397","But man",0,7],["H4191","dieth",8,13],["H2522","and wasteth away",15,31],["H0120","yea, man",33,41],["H1478","giveth up the ghost",42,61]]},"14:11":{"text":"As the waters fail from the sea, and the flood decayeth and drieth up:","words":[["H4325","As the waters",0,13],["H0235","fail",14,18],["H3220","from the sea",19,31],["H5104","and the flood",33,46],["H2717","decayeth",47,55],["H3001","and drieth up",56,69]]},"14:12":{"text":"So man lieth down, and riseth not: till the heavens be no more, they shall not awake, nor be raised out of their sleep.","words":[["H0376","So man",0,6],["H7901","lieth down",7,17],["H6965","and riseth",19,29],["H8064","not: till the heavens",30,51],["H1115","be no more",52,62],["H6974","they shall not awake",64,84],["H5782","nor be raised out",86,103],["H8142","of their sleep",104,118]]},"14:13":{"text":"O that thou wouldest hide me in the grave, that thou wouldest keep me secret, until thy wrath be past, that thou wouldest appoint me a set time, and remember me!","words":[["H5414","O that",0,6],["H6845","thou wouldest hide",7,25],["H7585","me in the grave",26,41],["H5641","that thou wouldest keep me secret",43,76],["H0639","until thy wrath",78,93],["H7725","be past",94,101],["H7896","that thou wouldest appoint",103,129],["H2706","me a set time",130,143],["H2142","and remember",145,157]]},"14:14":{"text":"If a man die, shall he live again? all the days of my appointed time will I wait, till my change come.","words":[["H1397","If a man",0,8],["H4191","die",9,12],["H2421","shall he live",14,27],["H3117","again? all the days",28,47],["H6635","of my appointed time",48,68],["H3176","will I wait",69,80],["H2487","till my change",82,96],["H0935","come",97,101]]},"14:15":{"text":"Thou shalt call, and I will answer thee: thou wilt have a desire to the work of thine hands.","words":[["H7121","Thou shalt call",0,15],["H6030","and I will answer",17,34],["H3700","thee: thou wilt have a desire",35,64],["H4639","to the work",65,76],["H3027","of thine hands",77,91]]},"14:16":{"text":"For now thou numberest my steps: dost thou not watch over my sin?","words":[["H5608","For now thou numberest",0,22],["H6806","my steps",23,31],["H8104","dost thou not watch",33,52],["H2403","over my sin",53,64]]},"14:17":{"text":"My transgression is sealed up in a bag, and thou sewest up mine iniquity.","words":[["H6588","My transgression",0,16],["H2856","is sealed up",17,29],["H6872","in a bag",30,38],["H2950","and thou sewest up",40,58],["H5771","mine iniquity",59,72]]},"14:18":{"text":"And surely the mountain falling cometh to nought, and the rock is removed out of his place.","words":[["H0199","And surely",0,10],["H2022","the mountain",11,23],["H5307","falling",24,31],["H5034","cometh to nought",32,48],["H6697","and the rock",50,62],["H6275","is removed",63,73],["H4725","out of his place",74,90]]},"14:19":{"text":"The waters wear the stones: thou washest away the things which grow out of the dust of the earth; and thou destroyest the hope of man.","words":[["H4325","The waters",0,10],["H7833","wear",11,15],["H0068","the stones",16,26],["H7857","thou washest away",28,45],["H5599","the things which grow",46,67],["H6083","out of the dust",68,83],["H0776","of the earth",84,96],["H0006","and thou destroyest",98,117],["H8615","the hope",118,126],["H0582","of man",127,133]]},"14:20":{"text":"Thou prevailest for ever against him, and he passeth: thou changest his countenance, and sendest him away.","words":[["H8630","Thou prevailest",0,15],["H5331","for ever",16,24],["H1980","against him, and he passeth",25,52],["H8138","thou changest",54,67],["H6440","his countenance",68,83],["H7971","and sendest him away",85,105]]},"14:21":{"text":"His sons come to honour, and he knoweth it not; and they are brought low, but he perceiveth it not of them.","words":[["H1121","His sons",0,8],["H3513","come to honour",9,23],["H3045","and he knoweth",25,39],["H6819","it not; and they are brought low",40,72],["H0995","but he perceiveth",74,91]]},"14:22":{"text":"But his flesh upon him shall have pain, and his soul within him shall mourn.","words":[["H1320","But his flesh",0,13],["H3510","upon him shall have pain",14,38],["H5315","and his soul",40,52],["H0056","within him shall mourn",53,75]]},"15:1":{"text":"Then answered Eliphaz the Temanite, and said,","words":[["H6030","Then answered",0,13],["H0464","Eliphaz",14,21],["H8489","the Temanite",22,34],["H0559","and said",36,44]]},"15:2":{"text":"Should a wise man utter vain knowledge, and fill his belly with the east wind?","words":[["H2450","Should a wise man",0,17],["H6030","utter",18,23],["H7307","vain",24,28],["H1847","knowledge",29,38],["H4390","and fill",40,48],["H0990","his belly",49,58],["H6921","with the east wind",59,77]]},"15:3":{"text":"Should he reason with unprofitable talk? or with speeches wherewith he can do no good?","words":[["H3198","Should he reason",0,16],["H5532","with unprofitable",17,34],["H1697","talk",35,39],["H4405","or with speeches",41,57],["H3276","wherewith he can do no good",58,85]]},"15:4":{"text":"Yea, thou castest off fear, and restrainest prayer before God.","words":[["H6565","Yea, thou castest off",0,21],["H3374","fear",22,26],["H1639","and restrainest",28,43],["H7881","prayer",44,50],["H6440","before",51,57],["H0410","God",58,61]]},"15:5":{"text":"For thy mouth uttereth thine iniquity, and thou choosest the tongue of the crafty.","words":[["H6310","For thy mouth",0,13],["H0502","uttereth",14,22],["H5771","thine iniquity",23,37],["H0977","and thou choosest",39,56],["H3956","the tongue",57,67],["H6175","of the crafty",68,81]]},"15:6":{"text":"Thine own mouth condemneth thee, and not I: yea, thine own lips testify against thee.","words":[["H6310","Thine own mouth",0,15],["H7561","condemneth",16,26],["H8193","thee, and not I: yea, thine own lips",27,63],["H6030","testify",64,71]]},"15:7":{"text":"Art thou the first man that was born? or wast thou made before the hills?","words":[["H7223","Art thou the first",0,18],["H7223","Art thou the first",0,18],["H0120","man",19,22],["H3205","that was born",23,36],["H2342","or wast thou made",38,55],["H6440","before",56,62],["H1389","the hills",63,72]]},"15:8":{"text":"Hast thou heard the secret of God? and dost thou restrain wisdom to thyself?","words":[["H8085","Hast thou heard",0,15],["H5475","the secret",16,26],["H0433","of God",27,33],["H1639","and dost thou restrain",35,57],["H2451","wisdom",58,64]]},"15:9":{"text":"What knowest thou, that we know not? what understandest thou, which is not in us?","words":[["H3045","What knowest",0,12],["H3045","thou, that we know",13,31],["H0995","not? what understandest",32,55]]},"15:10":{"text":"With us are both the grayheaded and very aged men, much elder than thy father.","words":[["H7867","With us are both the grayheaded",0,31],["H3453","and very aged",32,45],["H3524","men, much",46,55],["H3117","elder",56,61],["H0001","than thy father",62,77]]},"15:11":{"text":"Are the consolations of God small with thee? is there any secret thing with thee?","words":[["H8575","Are the consolations",0,20],["H0410","of God",21,27],["H4592","small",28,33],["H0328","with thee? is there any secret",34,64],["H1697","thing",65,70]]},"15:12":{"text":"Why doth thine heart carry thee away? and what do thy eyes wink at,","words":[["H3820","Why doth thine heart",0,20],["H3947","carry thee away",21,36],["H5869","and what do thy eyes",38,58],["H7335","wink at",59,66]]},"15:13":{"text":"That thou turnest thy spirit against God, and lettest such words go out of thy mouth?","words":[["H7725","That thou turnest",0,17],["H7307","thy spirit",18,28],["H0410","against God",29,40],["H4405","and lettest such words",42,64],["H3318","go out",65,71],["H6310","of thy mouth",72,84]]},"15:14":{"text":"What is man, that he should be clean? and he which is born of a woman, that he should be righteous?","words":[["H0582","What is man",0,11],["H2135","that he should be clean",13,36],["H3205","and he which is born",38,58],["H0802","of a woman",59,69],["H6663","that he should be righteous",71,98]]},"15:15":{"text":"Behold, he putteth no trust in his saints; yea, the heavens are not clean in his sight.","words":[["H0539","Behold, he putteth no trust",0,27],["H6918","in his saints",28,41],["H8064","yea, the heavens",43,59],["H2141","are not clean",60,73],["H5869","in his sight",74,86]]},"15:16":{"text":"How much more abominable and filthy is man, which drinketh iniquity like water?","words":[["H8581","How much more abominable",0,24],["H0444","and filthy",25,35],["H0376","is man",36,42],["H8354","which drinketh",44,58],["H5766","iniquity",59,67],["H5766","iniquity",59,67],["H4325","like water",68,78]]},"15:17":{"text":"I will shew thee, hear me; and that which I have seen I will declare;","words":[["H2331","I will shew",0,11],["H8085","thee, hear",12,22],["H2372","me; and that which I have seen",23,53],["H5608","I will declare",54,68]]},"15:18":{"text":"Which wise men have told from their fathers, and have not hid it:","words":[["H2450","Which wise",0,10],["H5046","men have told",11,24],["H0001","from their fathers",25,43],["H3582","and have not hid",45,61]]},"15:19":{"text":"Unto whom alone the earth was given, and no stranger passed among them.","words":[["H0776","Unto whom alone the earth",0,25],["H5414","was given",26,35],["H2114","and no stranger",37,52],["H5674","passed",53,59],["H8432","among",60,65]]},"15:20":{"text":"The wicked man travaileth with pain all his days, and the number of years is hidden to the oppressor.","words":[["H7563","The wicked",0,10],["H2342","man travaileth",11,25],["H3117","with pain all his days",26,48],["H4557","and the number",50,64],["H8141","of years",65,73],["H6845","is hidden",74,83],["H6184","to the oppressor",84,100]]},"15:21":{"text":"A dreadful sound is in his ears: in prosperity the destroyer shall come upon him.","words":[["H6343","A dreadful",0,10],["H6963","sound",11,16],["H0241","is in his ears",17,31],["H7965","in prosperity",33,46],["H7703","the destroyer",47,60],["H0935","shall come",61,71]]},"15:22":{"text":"He believeth not that he shall return out of darkness, and he is waited for of the sword.","words":[["H0539","He believeth",0,12],["H7725","not that he shall return",13,37],["H2822","out of darkness",38,53],["H6822","and he is waited",55,71],["H2719","for of the sword",72,88]]},"15:23":{"text":"He wandereth abroad for bread, saying, Where is it? he knoweth that the day of darkness is ready at his hand.","words":[["H5074","He wandereth abroad",0,19],["H3899","for bread",20,29],["H3045","saying, Where is it? he knoweth",31,62],["H3117","that the day",63,75],["H2822","of darkness",76,87],["H3559","is ready",88,96],["H3027","at his hand",97,108]]},"15:24":{"text":"Trouble and anguish shall make him afraid; they shall prevail against him, as a king ready to the battle.","words":[["H6862","Trouble",0,7],["H4691","and anguish",8,19],["H1204","shall make him afraid",20,41],["H8630","they shall prevail",43,61],["H4428","against him, as a king",62,84],["H6264","ready",85,90],["H3593","to the battle",91,104]]},"15:25":{"text":"For he stretcheth out his hand against God, and strengtheneth himself against the Almighty.","words":[["H5186","For he stretcheth out",0,21],["H3027","his hand",22,30],["H0410","against God",31,42],["H1396","and strengtheneth",44,61],["H7706","himself against the Almighty",62,90]]},"15:26":{"text":"He runneth upon him, even on his neck, upon the thick bosses of his bucklers:","words":[["H7323","He runneth",0,10],["H6677","upon him, even on his neck",11,37],["H5672","upon the thick",39,53],["H1354","bosses",54,60],["H4043","of his bucklers",61,76]]},"15:27":{"text":"Because he covereth his face with his fatness, and maketh collops of fat on his flanks.","words":[["H3680","Because he covereth",0,19],["H6440","his face",20,28],["H2459","with his fatness",29,45],["H6213","and maketh",47,57],["H6371","collops of fat",58,72],["H3689","on his flanks",73,86]]},"15:28":{"text":"And he dwelleth in desolate cities, and in houses which no man inhabiteth, which are ready to become heaps.","words":[["H7931","And he dwelleth",0,15],["H3582","in desolate",16,27],["H5892","cities",28,34],["H1004","and in houses",36,49],["H3427","which no man inhabiteth",50,73],["H6257","which are ready",75,90],["H1530","to become heaps",91,106]]},"15:29":{"text":"He shall not be rich, neither shall his substance continue, neither shall he prolong the perfection thereof upon the earth.","words":[["H6238","He shall not be rich",0,20],["H2428","neither shall his substance",22,49],["H6965","continue",50,58],["H5186","neither shall he prolong",60,84],["H4512","the perfection",85,99],["H0776","thereof upon the earth",100,122]]},"15:30":{"text":"He shall not depart out of darkness; the flame shall dry up his branches, and by the breath of his mouth shall he go away.","words":[["H5493","He shall not depart",0,19],["H2822","out of darkness",20,35],["H7957","the flame",37,46],["H3001","shall dry up",47,59],["H3127","his branches",60,72],["H7307","and by the breath",74,91],["H6310","of his mouth",92,104],["H5493","shall he go away",105,121]]},"15:31":{"text":"Let not him that is deceived trust in vanity: for vanity shall be his recompence.","words":[["H8582","Let not him that is deceived",0,28],["H0539","trust",29,34],["H7723","in vanity",35,44],["H7723","for vanity",46,56],["H8545","shall be his recompence",57,80]]},"15:32":{"text":"It shall be accomplished before his time, and his branch shall not be green.","words":[["H4390","It shall be accomplished",0,24],["H3808","before",25,31],["H3117","his time",32,40],["H3712","and his branch",42,56],["H7488","shall not be green",57,75]]},"15:33":{"text":"He shall shake off his unripe grape as the vine, and shall cast off his flower as the olive.","words":[["H2554","He shall shake off",0,18],["H1154","his unripe grape",19,35],["H1612","as the vine",36,47],["H7993","and shall cast off",49,67],["H5328","his flower",68,78],["H2132","as the olive",79,91]]},"15:34":{"text":"For the congregation of hypocrites shall be desolate, and fire shall consume the tabernacles of bribery.","words":[["H5712","For the congregation",0,20],["H2611","of hypocrites",21,34],["H1565","shall be desolate",35,52],["H0784","and fire",54,62],["H0398","shall consume",63,76],["H0168","the tabernacles",77,92],["H7810","of bribery",93,103]]},"15:35":{"text":"They conceive mischief, and bring forth vanity, and their belly prepareth deceit.","words":[["H2029","They conceive",0,13],["H5999","mischief",14,22],["H3205","and bring forth",24,39],["H0205","vanity",40,46],["H0990","and their belly",48,63],["H3559","prepareth",64,73],["H4820","deceit",74,80]]},"16:1":{"text":"Then Job answered and said,","words":[["H0347","Then Job",0,8],["H6030","answered",9,17],["H0559","and said",18,26]]},"16:2":{"text":"I have heard many such things: miserable comforters are ye all.","words":[["H8085","I have heard",0,12],["H7227","many such things",13,29],["H5999","miserable",31,40],["H5162","comforters",41,51]]},"16:3":{"text":"Shall vain words have an end? or what emboldeneth thee that thou answerest?","words":[["H7307","Shall vain",0,10],["H1697","words",11,16],["H7093","have an end",17,28],["H4834","or what emboldeneth",30,49],["H6030","thee that thou answerest",50,74]]},"16:4":{"text":"I also could speak as ye do: if your soul were in my soul's stead, I could heap up words against you, and shake mine head at you.","words":[["H1696","I also could speak",0,18],["H3863","as ye do: if",19,31],["H5315","your soul",32,41],["H3426","were",42,46],["H5315","in my soul's",47,59],["H2266","stead, I could heap up",60,82],["H4405","words",83,88],["H5128","against you, and shake",89,111],["H7218","mine head",112,121],["H1119","at",122,124]]},"16:5":{"text":"But I would strengthen you with my mouth, and the moving of my lips should asswage your grief.","words":[["H0553","But I would strengthen",0,22],["H1119","you with",23,31],["H6310","my mouth",32,40],["H5205","and the moving",42,56],["H8193","of my lips",57,67],["H2820","should asswage",68,82]]},"16:6":{"text":"Though I speak, my grief is not asswaged: and though I forbear, what am I eased?","words":[["H1696","Though I speak",0,14],["H3511","my grief",16,24],["H2820","is not asswaged",25,40],["H2308","and though I forbear",42,62],["H1980","what am I eased",64,79]]},"16:7":{"text":"But now he hath made me weary: thou hast made desolate all my company.","words":[["H3811","But now he hath made me weary",0,29],["H8074","thou hast made desolate",31,54],["H5712","all my company",55,69]]},"16:8":{"text":"And thou hast filled me with wrinkles, which is a witness against me: and my leanness rising up in me beareth witness to my face.","words":[["H7059","And thou hast filled me with wrinkles",0,37],["H5707","which is a witness",39,57],["H3585","against me: and my leanness",58,85],["H6965","rising up",86,95],["H6030","in me beareth witness",96,117],["H6440","to my face",118,128]]},"16:9":{"text":"He teareth me in his wrath, who hateth me: he gnasheth upon me with his teeth; mine enemy sharpeneth his eyes upon me.","words":[["H2963","He teareth",0,10],["H0639","me in his wrath",11,26],["H7852","who hateth",28,38],["H2786","me: he gnasheth",39,54],["H8127","upon me with his teeth",55,77],["H6862","mine enemy",79,89],["H3913","sharpeneth",90,100],["H5869","his eyes",101,109]]},"16:10":{"text":"They have gaped upon me with their mouth; they have smitten me upon the cheek reproachfully; they have gathered themselves together against me.","words":[["H6473","They have gaped",0,15],["H6310","upon me with their mouth",16,40],["H5221","they have smitten",42,59],["H3895","me upon the cheek",60,77],["H2781","reproachfully",78,91],["H4390","they have gathered",93,111],["H3162","themselves together",112,131]]},"16:11":{"text":"God hath delivered me to the ungodly, and turned me over into the hands of the wicked.","words":[["H0410","God",0,3],["H5462","hath delivered",4,18],["H5760","me to the ungodly",19,36],["H3399","and turned me over",38,56],["H3027","into the hands",57,71],["H7563","of the wicked",72,85]]},"16:12":{"text":"I was at ease, but he hath broken me asunder: he hath also taken me by my neck, and shaken me to pieces, and set me up for his mark.","words":[["H7961","I was at ease",0,13],["H6565","but he hath broken me asunder",15,44],["H0270","he hath also taken",46,64],["H6203","me by my neck",65,78],["H6327","and shaken me to pieces",80,103],["H6965","and set me up",105,118],["H4307","for his mark",119,131]]},"16:13":{"text":"His archers compass me round about, he cleaveth my reins asunder, and doth not spare; he poureth out my gall upon the ground.","words":[["H7228","His archers",0,11],["H5437","compass me round about",12,34],["H6398","he cleaveth",36,47],["H3629","my reins",48,56],["H6398","asunder",57,64],["H2550","and doth not spare",66,84],["H8210","he poureth out",86,100],["H4845","my gall",101,108],["H0776","upon the ground",109,124]]},"16:14":{"text":"He breaketh me with breach upon breach, he runneth upon me like a giant.","words":[["H6555","He breaketh",0,11],["H6556","me with breach",12,26],["H6440","upon",27,31],["H6556","breach",32,38],["H7323","he runneth",40,50],["H1368","upon me like a giant",51,71]]},"16:15":{"text":"I have sewed sackcloth upon my skin, and defiled my horn in the dust.","words":[["H8609","I have sewed",0,12],["H8242","sackcloth",13,22],["H1539","upon my skin",23,35],["H5953","and defiled",37,48],["H7161","my horn",49,56],["H6083","in the dust",57,68]]},"16:16":{"text":"My face is foul with weeping, and on my eyelids is the shadow of death;","words":[["H6440","My face",0,7],["H2560","is foul",8,15],["H1065","with weeping",16,28],["H6079","and on my eyelids",30,47],["H6757","is the shadow of death",48,70]]},"16:17":{"text":"Not for any injustice in mine hands: also my prayer is pure.","words":[["H2555","Not for any injustice",0,21],["H3709","in mine hands",22,35],["H8605","also my prayer",37,51],["H2134","is pure",52,59]]},"16:18":{"text":"O earth, cover not thou my blood, and let my cry have no place.","words":[["H0776","O earth",0,7],["H3680","cover",9,14],["H1818","not thou my blood",15,32],["H2201","and let my cry",34,48],["H4725","have no place",49,62]]},"16:19":{"text":"Also now, behold, my witness is in heaven, and my record is on high.","words":[["H5707","Also now, behold, my witness",0,28],["H8064","is in heaven",29,41],["H7717","and my record",43,56],["H4791","is on high",57,67]]},"16:20":{"text":"My friends scorn me: but mine eye poureth out tears unto God.","words":[["H7453","My friends",0,10],["H3887","scorn",11,16],["H5869","me: but mine eye",17,33],["H1811","poureth out",34,45],["H0433","tears unto God",46,60]]},"16:21":{"text":"O that one might plead for a man with God, as a man pleadeth for his neighbour!","words":[["H3198","O that one might plead",0,22],["H1397","for a man",23,32],["H0433","with God",33,41],["H0120","as a man",43,51],["H1121","pleadeth for his neighbour",52,78],["H7453","pleadeth for his neighbour",52,78]]},"16:22":{"text":"When a few years are come, then I shall go the way whence I shall not return.","words":[["H4557","When a few",0,10],["H8141","years",11,16],["H0857","are come",17,25],["H1980","then I shall go",27,42],["H0734","the way",43,50],["H7725","whence I shall not return",51,76]]},"17:1":{"text":"My breath is corrupt, my days are extinct, the graves are ready for me.","words":[["H7307","My breath",0,9],["H2254","is corrupt",10,20],["H3117","my days",22,29],["H2193","are extinct",30,41],["H6913","the graves",43,53]]},"17:2":{"text":"Are there not mockers with me? and doth not mine eye continue in their provocation?","words":[["H2049","Are there not mockers",0,21],["H5869","with me? and doth not mine eye",22,52],["H3885","continue",53,61],["H4784","in their provocation",62,82]]},"17:3":{"text":"Lay down now, put me in a surety with thee; who is he that will strike hands with me?","words":[["H7760","Lay down",0,8],["H6148","now, put me in a surety",9,32],["H8628","with thee; who is he that will strike",33,70],["H3027","hands",71,76]]},"17:4":{"text":"For thou hast hid their heart from understanding: therefore shalt thou not exalt them.","words":[["H6845","For thou hast hid",0,17],["H3820","their heart",18,29],["H7922","from understanding",30,48],["H7311","therefore shalt thou not exalt",50,80]]},"17:5":{"text":"He that speaketh flattery to his friends, even the eyes of his children shall fail.","words":[["H5046","He that speaketh",0,16],["H2506","flattery",17,25],["H7453","to his friends",26,40],["H5869","even the eyes",42,55],["H1121","of his children",56,71],["H3615","shall fail",72,82]]},"17:6":{"text":"He hath made me also a byword of the people; and aforetime I was as a tabret.","words":[["H3322","He hath made",0,12],["H4914","me also a byword",13,29],["H5971","of the people",30,43],["H6440","and aforetime",45,58],["H8611","I was as a tabret",59,76]]},"17:7":{"text":"Mine eye also is dim by reason of sorrow, and all my members are as a shadow.","words":[["H5869","Mine eye",0,8],["H3543","also is dim",9,20],["H3708","by reason of sorrow",21,40],["H3338","and all my members",42,60],["H6738","are as a shadow",61,76]]},"17:8":{"text":"Upright men shall be astonied at this, and the innocent shall stir up himself against the hypocrite.","words":[["H3477","Upright",0,7],["H8074","men shall be astonied",8,29],["H5355","at this, and the innocent",30,55],["H5782","shall stir up",56,69],["H2611","himself against the hypocrite",70,99]]},"17:9":{"text":"The righteous also shall hold on his way, and he that hath clean hands shall be stronger and stronger.","words":[["H6662","The righteous",0,13],["H0270","also shall hold",14,29],["H1870","on his way",30,40],["H2890","and he that hath clean",42,64],["H3027","hands",65,70],["H3254","shall be",71,79],["H0555","stronger and stronger",80,101]]},"17:10":{"text":"But as for you all, do ye return, and come now: for I cannot find one wise man among you.","words":[["H0199","But",0,3],["H7725","as for you all, do ye return",4,32],["H0935","and come now",34,46],["H4672","for I cannot find",48,65],["H2450","one wise",66,74]]},"17:11":{"text":"My days are past, my purposes are broken off, even the thoughts of my heart.","words":[["H3117","My days",0,7],["H5674","are past",8,16],["H2154","my purposes",18,29],["H5423","are broken off",30,44],["H4180","even the thoughts",46,63],["H3824","of my heart",64,75]]},"17:12":{"text":"They change the night into day: the light is short because of darkness.","words":[["H7760","They change",0,11],["H3915","the night",12,21],["H3117","into day",22,30],["H0216","the light",32,41],["H7138","is short",42,50],["H6440","because",51,58],["H2822","of darkness",59,70]]},"17:13":{"text":"If I wait, the grave is mine house: I have made my bed in the darkness.","words":[["H6960","If I wait",0,9],["H7585","the grave",11,20],["H1004","is mine house",21,34],["H7502","I have made",36,47],["H3326","my bed",48,54],["H2822","in the darkness",55,70]]},"17:14":{"text":"I have said to corruption, Thou art my father: to the worm, Thou art my mother, and my sister.","words":[["H7121","I have said",0,11],["H7845","to corruption",12,25],["H0001","Thou art my father",27,45],["H7415","to the worm",47,58],["H0517","Thou art my mother",60,78],["H0269","and my sister",80,93]]},"17:15":{"text":"And where is now my hope? as for my hope, who shall see it?","words":[["H0645","And where is now",0,16],["H8615","my hope",17,24],["H8615","as for my hope",26,40],["H7789","who shall see",42,55]]},"17:16":{"text":"They shall go down to the bars of the pit, when our rest together is in the dust.","words":[["H3381","They shall go down",0,18],["H0905","to the bars",19,30],["H7585","of the pit",31,41],["H5183","when our rest",43,56],["H3162","together",57,65],["H6083","is in the dust",66,80]]},"18:1":{"text":"Then answered Bildad the Shuhite, and said,","words":[["H6030","Then answered",0,13],["H1085","Bildad",14,20],["H7747","the Shuhite",21,32],["H0559","and said",34,42]]},"18:2":{"text":"How long will it be ere ye make an end of words? mark, and afterwards we will speak.","words":[["H5704","How long",0,8],["H7760","will it be ere ye make",9,31],["H7078","an end",32,38],["H4405","of words",39,47],["H0995","mark",49,53],["H0310","and afterwards",55,69],["H1696","we will speak",70,83]]},"18:3":{"text":"Wherefore are we counted as beasts, and reputed vile in your sight?","words":[["H2803","Wherefore are we counted",0,24],["H0929","as beasts",25,34],["H2933","and reputed vile",36,52],["H5869","in your sight",53,66]]},"18:4":{"text":"He teareth himself in his anger: shall the earth be forsaken for thee? and shall the rock be removed out of his place?","words":[["H2963","He teareth",0,10],["H5315","himself",11,18],["H0639","in his anger",19,31],["H0776","shall the earth",33,48],["H5800","be forsaken",49,60],["H6697","for thee? and shall the rock",61,89],["H6275","be removed",90,100],["H4725","out of his place",101,117]]},"18:5":{"text":"Yea, the light of the wicked shall be put out, and the spark of his fire shall not shine.","words":[["H0216","Yea, the light",0,14],["H7563","of the wicked",15,28],["H1846","shall be put out",29,45],["H7632","and the spark",47,60],["H0784","of his fire",61,72],["H5050","shall not shine",73,88]]},"18:6":{"text":"The light shall be dark in his tabernacle, and his candle shall be put out with him.","words":[["H0216","The light",0,9],["H2821","shall be dark",10,23],["H0168","in his tabernacle",24,41],["H5216","and his candle",43,57],["H1846","shall be put out",58,74]]},"18:7":{"text":"The steps of his strength shall be straitened, and his own counsel shall cast him down.","words":[["H6806","The steps",0,9],["H0202","of his strength",10,25],["H3334","shall be straitened",26,45],["H6098","and his own counsel",47,66],["H7993","shall cast him down",67,86]]},"18:8":{"text":"For he is cast into a net by his own feet, and he walketh upon a snare.","words":[["H7971","For he is cast",0,14],["H7568","into a net",15,25],["H7272","by his own feet",26,41],["H1980","and he walketh",43,57],["H7639","upon a snare",58,70]]},"18:9":{"text":"The gin shall take him by the heel, and the robber shall prevail against him.","words":[["H6341","The gin",0,7],["H0270","shall take",8,18],["H6119","him by the heel",19,34],["H6782","and the robber",36,50],["H2388","shall prevail",51,64]]},"18:10":{"text":"The snare is laid for him in the ground, and a trap for him in the way.","words":[["H2256","The snare",0,9],["H2934","is laid",10,17],["H0776","for him in the ground",18,39],["H4434","and a trap",41,51],["H5410","for him in the way",52,70]]},"18:11":{"text":"Terrors shall make him afraid on every side, and shall drive him to his feet.","words":[["H1091","Terrors",0,7],["H1204","shall make him afraid",8,29],["H5439","on every side",30,43],["H6327","and shall drive",45,60],["H7272","him to his feet",61,76]]},"18:12":{"text":"His strength shall be hungerbitten, and destruction shall be ready at his side.","words":[["H0202","His strength",0,12],["H7457","shall be hungerbitten",13,34],["H0343","and destruction",36,51],["H3559","shall be ready",52,66],["H6763","at his side",67,78]]},"18:13":{"text":"It shall devour the strength of his skin: even the firstborn of death shall devour his strength.","words":[["H0398","It shall devour",0,15],["H0905","the strength",16,28],["H5785","of his skin",29,40],["H1060","even the firstborn",42,60],["H4194","of death",61,69],["H0398","shall devour",70,82],["H0905","his strength",83,95]]},"18:14":{"text":"His confidence shall be rooted out of his tabernacle, and it shall bring him to the king of terrors.","words":[["H4009","His confidence",0,14],["H5423","shall be rooted out",15,34],["H0168","of his tabernacle",35,52],["H6805","and it shall bring",54,72],["H4428","him to the king",73,88],["H1091","of terrors",89,99]]},"18:15":{"text":"It shall dwell in his tabernacle, because it is none of his: brimstone shall be scattered upon his habitation.","words":[["H7931","It shall dwell",0,14],["H0168","in his tabernacle",15,32],["H1097","because it is none",34,52],["H1614","of his: brimstone",53,70],["H2219","shall be scattered",71,89],["H5116","upon his habitation",90,109]]},"18:16":{"text":"His roots shall be dried up beneath, and above shall his branch be cut off.","words":[["H8328","His roots",0,9],["H3001","shall be dried up",10,27],["H4605","beneath, and above",28,46],["H7105","shall his branch",47,63],["H5243","be cut off",64,74]]},"18:17":{"text":"His remembrance shall perish from the earth, and he shall have no name in the street.","words":[["H2143","His remembrance",0,15],["H0006","shall perish",16,28],["H0776","from the earth",29,43],["H8034","and he shall have no name",45,70],["H6440","in the street",71,84],["H2351","in the street",71,84]]},"18:18":{"text":"He shall be driven from light into darkness, and chased out of the world.","words":[["H1920","He shall be driven",0,18],["H0216","from light",19,29],["H2822","into darkness",30,43],["H5074","and chased",45,55],["H8398","out of the world",56,72]]},"18:19":{"text":"He shall neither have son nor nephew among his people, nor any remaining in his dwellings.","words":[["H5209","He shall neither have son",0,25],["H5220","nor nephew",26,36],["H5971","among his people",37,53],["H8300","nor any remaining",55,72],["H4033","in his dwellings",73,89]]},"18:20":{"text":"They that come after him shall be astonied at his day, as they that went before were affrighted.","words":[["H0314","They that come after",0,20],["H8074","him shall be astonied",21,42],["H3117","at his day",43,53],["H6931","as they that went before",55,79],["H0270","were affrighted",80,95],["H8178","were affrighted",80,95]]},"18:21":{"text":"Surely such are the dwellings of the wicked, and this is the place of him that knoweth not God.","words":[["H4908","Surely such are the dwellings",0,29],["H5767","of the wicked",30,43],["H4725","and this is the place",45,66],["H3045","of him that knoweth",67,86],["H0410","not God",87,94]]},"19:1":{"text":"Then Job answered and said,","words":[["H0347","Then Job",0,8],["H6030","answered",9,17],["H0559","and said",18,26]]},"19:2":{"text":"How long will ye vex my soul, and break me in pieces with words?","words":[["H3013","How long will ye vex",0,20],["H5315","my soul",21,28],["H1792","and break",30,39],["H4405","me in pieces with words",40,63]]},"19:3":{"text":"These ten times have ye reproached me: ye are not ashamed that ye make yourselves strange to me.","words":[["H6235","These ten",0,9],["H6471","times",10,15],["H3637","have ye reproached",16,34],["H0954","me: ye are not ashamed",35,57],["H1970","that ye make yourselves strange",58,89]]},"19:4":{"text":"And be it indeed that I have erred, mine error remaineth with myself.","words":[["H0551","And be it indeed",0,16],["H7686","that I have erred",17,34],["H4879","mine error",36,46],["H3885","remaineth",47,56]]},"19:5":{"text":"If indeed ye will magnify yourselves against me, and plead against me my reproach:","words":[["H0551","If indeed",0,9],["H1431","ye will magnify",10,25],["H3198","yourselves against me, and plead",26,58],["H2781","against me my reproach",59,81]]},"19:6":{"text":"Know now that God hath overthrown me, and hath compassed me with his net.","words":[["H3045","Know",0,4],["H0645","now",5,8],["H0433","that God",9,17],["H5791","hath overthrown",18,33],["H5362","me, and hath compassed",34,56],["H4686","me with his net",57,72]]},"19:7":{"text":"Behold, I cry out of wrong, but I am not heard: I cry aloud, but there is no judgment.","words":[["H6817","Behold, I cry out",0,17],["H2555","of wrong",18,26],["H6030","but I am not heard",28,46],["H7768","I cry aloud",48,59],["H4941","but there is no judgment",61,85]]},"19:8":{"text":"He hath fenced up my way that I cannot pass, and he hath set darkness in my paths.","words":[["H1443","He hath fenced up",0,17],["H0734","my way",18,24],["H5674","that I cannot pass",25,43],["H7760","and he hath set",45,60],["H2822","darkness",61,69],["H5410","in my paths",70,81]]},"19:9":{"text":"He hath stripped me of my glory, and taken the crown from my head.","words":[["H6584","He hath stripped",0,16],["H3519","me of my glory",17,31],["H5493","and taken",33,42],["H5850","the crown",43,52],["H7218","from my head",53,65]]},"19:10":{"text":"He hath destroyed me on every side, and I am gone: and mine hope hath he removed like a tree.","words":[["H5422","He hath destroyed",0,17],["H5439","me on every side",18,34],["H3212","and I am gone",36,49],["H8615","and mine hope",51,64],["H5265","hath he removed",65,80],["H6086","like a tree",81,92]]},"19:11":{"text":"He hath also kindled his wrath against me, and he counteth me unto him as one of his enemies.","words":[["H2734","He hath also kindled",0,20],["H0639","his wrath",21,30],["H2803","against me, and he counteth",31,58],["H6862","me unto him as one of his enemies",59,92]]},"19:12":{"text":"His troops come together, and raise up their way against me, and encamp round about my tabernacle.","words":[["H1416","His troops",0,10],["H0935","come",11,15],["H3162","together",16,24],["H5549","and raise up",26,38],["H1870","their way",39,48],["H2583","against me, and encamp",49,71],["H5439","round about",72,83],["H0168","my tabernacle",84,97]]},"19:13":{"text":"He hath put my brethren far from me, and mine acquaintance are verily estranged from me.","words":[["H7368","He hath put",0,11],["H0251","my brethren",12,23],["H7368","far",24,27],["H3045","from me, and mine acquaintance",28,58],["H2114","are verily estranged",59,79]]},"19:14":{"text":"My kinsfolk have failed, and my familiar friends have forgotten me.","words":[["H7138","My kinsfolk",0,11],["H2308","have failed",12,23],["H3045","and my familiar friends",25,48],["H7911","have forgotten",49,63]]},"19:15":{"text":"They that dwell in mine house, and my maids, count me for a stranger: I am an alien in their sight.","words":[["H1481","They that dwell",0,15],["H1004","in mine house",16,29],["H0519","and my maids",31,43],["H2803","count",45,50],["H2114","me for a stranger",51,68],["H5237","I am an alien",70,83],["H5869","in their sight",84,98]]},"19:16":{"text":"I called my servant, and he gave me no answer; I intreated him with my mouth.","words":[["H7121","I called",0,8],["H5650","my servant",9,19],["H6030","and he gave me no answer",21,45],["H2603","I intreated",47,58],["H1119","him with",59,67],["H6310","my mouth",68,76]]},"19:17":{"text":"My breath is strange to my wife, though I intreated for the children's sake of mine own body.","words":[["H7307","My breath",0,9],["H2114","is strange",10,20],["H0802","to my wife",21,31],["H2589","though I intreated",33,51],["H1121","for the children's",52,70],["H0990","sake of mine own body",71,92]]},"19:18":{"text":"Yea, young children despised me; I arose, and they spake against me.","words":[["H5759","Yea, young children",0,19],["H3988","despised",20,28],["H6965","me; I arose",29,40],["H1696","and they spake",42,56]]},"19:19":{"text":"All my inward friends abhorred me: and they whom I loved are turned against me.","words":[["H5475","All my inward",0,13],["H4962","friends",14,21],["H8581","abhorred",22,30],["H0157","me: and they whom I loved",31,56],["H2015","are turned",57,67]]},"19:20":{"text":"My bone cleaveth to my skin and to my flesh, and I am escaped with the skin of my teeth.","words":[["H6106","My bone",0,7],["H1692","cleaveth",8,16],["H5785","to my skin",17,27],["H1320","and to my flesh",28,43],["H4422","and I am escaped",45,61],["H5785","with the skin",62,75],["H8127","of my teeth",76,87]]},"19:21":{"text":"Have pity upon me, have pity upon me, O ye my friends; for the hand of God hath touched me.","words":[["H2603","Have pity",0,9],["H2603","upon me, have pity",10,28],["H7453","upon me, O ye my friends",29,53],["H3027","for the hand",55,67],["H0433","of God",68,74],["H5060","hath touched",75,87]]},"19:22":{"text":"Why do ye persecute me as God, and are not satisfied with my flesh?","words":[["H7291","Why do ye persecute",0,19],["H0410","me as God",20,29],["H7646","and are not satisfied",31,52],["H1320","with my flesh",53,66]]},"19:23":{"text":"Oh that my words were now written! oh that they were printed in a book!","words":[["H5414","Oh that",0,7],["H4405","my words",8,16],["H0645","were now",17,25],["H3789","written",26,33],["H5414","oh that",35,42],["H2710","they were printed",43,60],["H5612","in a book",61,70]]},"19:24":{"text":"That they were graven with an iron pen and lead in the rock for ever!","words":[["H2672","That they were graven",0,21],["H1270","with an iron",22,34],["H5842","pen",35,38],["H5777","and lead",39,47],["H6697","in the rock",48,59],["H5703","for ever",60,68]]},"19:25":{"text":"For I know that my redeemer liveth, and that he shall stand at the latter day upon the earth:","words":[["H3045","For I know",0,10],["H1350","that my redeemer",11,27],["H2416","liveth",28,34],["H6965","and that he shall stand",36,59],["H0314","at the latter",60,73],["H6083","day upon the earth",74,92]]},"19:26":{"text":"And though after my skin worms destroy this body, yet in my flesh shall I see God:","words":[["H0310","And though after",0,16],["H5785","my skin",17,24],["H5362","worms destroy",25,38],["H1320","this body, yet in my flesh",39,65],["H2372","shall I see",66,77],["H0433","God",78,81]]},"19:27":{"text":"Whom I shall see for myself, and mine eyes shall behold, and not another; though my reins be consumed within me.","words":[["H2372","Whom I shall see",0,16],["H5869","for myself, and mine eyes",17,42],["H7200","shall behold",43,55],["H2114","and not another",57,72],["H3629","though my reins",74,89],["H3615","be consumed",90,101],["H2436","within",102,108]]},"19:28":{"text":"But ye should say, Why persecute we him, seeing the root of the matter is found in me?","words":[["H0559","But ye should say",0,17],["H7291","Why persecute",19,32],["H8328","we him, seeing the root",33,56],["H1697","of the matter",57,70],["H4672","is found",71,79]]},"19:29":{"text":"Be ye afraid of the sword: for wrath bringeth the punishments of the sword, that ye may know there is a judgment.","words":[["H1481","Be ye afraid",0,12],["H2719","of the sword",13,25],["H2534","for wrath",27,36],["H5771","bringeth the punishments",37,61],["H6440","of",62,64],["H2719","the sword",65,74],["H3045","that ye may know",76,92],["H1779","there is a judgment",93,112],["H1779","there is a judgment",93,112]]},"20:1":{"text":"Then answered Zophar the Naamathite, and said,","words":[["H6030","Then answered",0,13],["H6691","Zophar",14,20],["H5284","the Naamathite",21,35],["H0559","and said",37,45]]},"20:2":{"text":"Therefore do my thoughts cause me to answer, and for this I make haste.","words":[["H5587","Therefore do my thoughts",0,24],["H7725","cause me to answer",25,43],["H2363","and for this I make haste",45,70]]},"20:3":{"text":"I have heard the check of my reproach, and the spirit of my understanding causeth me to answer.","words":[["H8085","I have heard",0,12],["H4148","the check",13,22],["H3639","of my reproach",23,37],["H7307","and the spirit",39,53],["H0998","of my understanding",54,73],["H6030","causeth me to answer",74,94]]},"20:4":{"text":"Knowest thou not this of old, since man was placed upon earth,","words":[["H3045","Knowest",0,7],["H5703","thou not this of old",8,28],["H0120","since man",30,39],["H7760","was placed",40,50],["H0776","upon earth",51,61]]},"20:5":{"text":"That the triumphing of the wicked is short, and the joy of the hypocrite but for a moment?","words":[["H7445","That the triumphing",0,19],["H7563","of the wicked",20,33],["H7138","is short",34,42],["H8057","and the joy",44,55],["H2611","of the hypocrite",56,72],["H7281","but for a moment",73,89]]},"20:6":{"text":"Though his excellency mount up to the heavens, and his head reach unto the clouds;","words":[["H7863","Though his excellency",0,21],["H5927","mount up",22,30],["H8064","to the heavens",31,45],["H7218","and his head",47,59],["H5060","reach",60,65],["H5645","unto the clouds",66,81]]},"20:7":{"text":"Yet he shall perish for ever like his own dung: they which have seen him shall say, Where is he?","words":[["H0006","Yet he shall perish",0,19],["H5331","for ever",20,28],["H1561","like his own dung",29,46],["H7200","they which have seen",48,68],["H0559","him shall say",69,82],["H0335","Where",84,89]]},"20:8":{"text":"He shall fly away as a dream, and shall not be found: yea, he shall be chased away as a vision of the night.","words":[["H5774","He shall fly away",0,17],["H2472","as a dream",18,28],["H4672","and shall not be found",30,52],["H5074","yea, he shall be chased away",54,82],["H2384","as a vision",83,94],["H3915","of the night",95,107]]},"20:9":{"text":"The eye also which saw him shall see him no more; neither shall his place any more behold him.","words":[["H5869","The eye",0,7],["H7805","also which saw",8,22],["H3254","him shall see him no more",23,48],["H4725","neither shall his place",50,73],["H7789","any more behold",74,89]]},"20:10":{"text":"His children shall seek to please the poor, and his hands shall restore their goods.","words":[["H1121","His children",0,12],["H7521","shall seek to please",13,33],["H1800","the poor",34,42],["H3027","and his hands",44,57],["H7725","shall restore",58,71],["H0202","their goods",72,83]]},"20:11":{"text":"His bones are full of the sin of his youth, which shall lie down with him in the dust.","words":[["H6106","His bones",0,9],["H4390","are full",10,18],["H5934","of the sin of his youth",19,42],["H7901","which shall lie down",44,64],["H6083","with him in the dust",65,85]]},"20:12":{"text":"Though wickedness be sweet in his mouth, though he hide it under his tongue;","words":[["H7451","Though wickedness",0,17],["H4985","be sweet",18,26],["H6310","in his mouth",27,39],["H3582","though he hide",41,55],["H3956","it under his tongue",56,75]]},"20:13":{"text":"Though he spare it, and forsake it not; but keep it still within his mouth:","words":[["H2550","Though he spare",0,15],["H5800","it, and forsake",16,31],["H4513","it not; but keep it still",32,57],["H8432","within",58,64],["H2441","his mouth",65,74]]},"20:14":{"text":"Yet his meat in his bowels is turned, it is the gall of asps within him.","words":[["H3899","Yet his meat",0,12],["H4578","in his bowels",13,26],["H2015","is turned",27,36],["H4846","it is the gall",38,52],["H6620","of asps",53,60],["H7130","within",61,67]]},"20:15":{"text":"He hath swallowed down riches, and he shall vomit them up again: God shall cast them out of his belly.","words":[["H1104","He hath swallowed down",0,22],["H2428","riches",23,29],["H6958","and he shall vomit them up again",31,63],["H0410","God",65,68],["H3423","shall cast them out",69,88],["H0990","of his belly",89,101]]},"20:16":{"text":"He shall suck the poison of asps: the viper's tongue shall slay him.","words":[["H3243","He shall suck",0,13],["H7219","the poison",14,24],["H6620","of asps",25,32],["H0660","the viper's",34,45],["H3956","tongue",46,52],["H2026","shall slay",53,63]]},"20:17":{"text":"He shall not see the rivers, the floods, the brooks of honey and butter.","words":[["H7200","He shall not see",0,16],["H6390","the rivers",17,27],["H5104","the floods",29,39],["H5158","the brooks",41,51],["H1706","of honey",52,60],["H2529","and butter",61,71]]},"20:18":{"text":"That which he laboured for shall he restore, and shall not swallow it down: according to his substance shall the restitution be, and he shall not rejoice therein.","words":[["H3022","That which he laboured",0,22],["H7725","for shall he restore",23,43],["H1104","and shall not swallow it down",45,74],["H2428","according to his substance",76,102],["H8545","shall the restitution",103,124],["H5965","be, and he shall not rejoice",125,153]]},"20:19":{"text":"Because he hath oppressed and hath forsaken the poor; because he hath violently taken away an house which he builded not;","words":[["H7533","Because he hath oppressed",0,25],["H5800","and hath forsaken",26,43],["H1800","the poor",44,52],["H1497","because he hath violently taken away",54,90],["H1004","an house",91,99],["H1129","which he builded",100,116]]},"20:20":{"text":"Surely he shall not feel quietness in his belly, he shall not save of that which he desired.","words":[["H3045","Surely he shall not feel",0,24],["H7961","quietness",25,34],["H0990","in his belly",35,47],["H4422","he shall not save",49,66],["H2530","of that which he desired",67,91]]},"20:21":{"text":"There shall none of his meat be left; therefore shall no man look for his goods.","words":[["H0400","There shall none of his meat",0,28],["H8300","be left",29,36],["H2342","therefore shall no man look",38,65],["H2898","for his goods",66,79]]},"20:22":{"text":"In the fulness of his sufficiency he shall be in straits: every hand of the wicked shall come upon him.","words":[["H4390","In the fulness",0,14],["H4390","In the fulness",0,14],["H5607","of his sufficiency",15,33],["H3334","he shall be in straits",34,56],["H3027","every hand",58,68],["H6001","of the wicked",69,82],["H0935","shall come",83,93]]},"20:23":{"text":"When he is about to fill his belly, God shall cast the fury of his wrath upon him, and shall rain it upon him while he is eating.","words":[["H4390","When he is about to fill",0,24],["H0990","his belly",25,34],["H7971","God shall cast",36,50],["H2740","the fury",51,59],["H0639","of his wrath",60,72],["H4305","upon him, and shall rain",73,97],["H3894","it upon him while he is eating",98,128]]},"20:24":{"text":"He shall flee from the iron weapon, and the bow of steel shall strike him through.","words":[["H1272","He shall flee",0,13],["H1270","from the iron",14,27],["H5402","weapon",28,34],["H7198","and the bow",36,47],["H5154","of steel",48,56],["H2498","shall strike him through",57,81]]},"20:25":{"text":"It is drawn, and cometh out of the body; yea, the glittering sword cometh out of his gall: terrors are upon him.","words":[["H8025","It is drawn",0,11],["H3318","and cometh out",13,27],["H1465","of the body",28,39],["H1300","yea, the glittering sword",41,66],["H1980","cometh out",67,77],["H4846","of his gall",78,89],["H0367","terrors",91,98]]},"20:26":{"text":"All darkness shall be hid in his secret places: a fire not blown shall consume him; it shall go ill with him that is left in his tabernacle.","words":[["H2822","All darkness",0,12],["H2934","shall be hid",13,25],["H6845","in his secret places",26,46],["H0784","a fire",48,54],["H5301","not blown",55,64],["H0398","shall consume",65,78],["H3415","him; it shall go ill",79,99],["H8300","with him that is left",100,121],["H0168","in his tabernacle",122,139]]},"20:27":{"text":"The heaven shall reveal his iniquity; and the earth shall rise up against him.","words":[["H8064","The heaven",0,10],["H1540","shall reveal",11,23],["H5771","his iniquity",24,36],["H0776","and the earth",38,51],["H6965","shall rise up",52,65]]},"20:28":{"text":"The increase of his house shall depart, and his goods shall flow away in the day of his wrath.","words":[["H2981","The increase",0,12],["H1004","of his house",13,25],["H1540","shall depart",26,38],["H5064","and his goods shall flow away",40,69],["H3117","in the day",70,80],["H0639","of his wrath",81,93]]},"20:29":{"text":"This is the portion of a wicked man from God, and the heritage appointed unto him by God.","words":[["H2506","This is the portion",0,19],["H7563","of a wicked",20,31],["H0120","man",32,35],["H0430","from God",36,44],["H5159","and the heritage",46,62],["H0561","appointed",63,72],["H0410","unto him by God",73,88]]},"21:1":{"text":"But Job answered and said,","words":[["H0347","But Job",0,7],["H6030","answered",8,16],["H0559","and said",17,25]]},"21:2":{"text":"Hear diligently my speech, and let this be your consolations.","words":[["H8085","Hear",0,4],["H8085","diligently",5,15],["H4405","my speech",16,25],["H8575","and let this be your consolations",27,60]]},"21:3":{"text":"Suffer me that I may speak; and after that I have spoken, mock on.","words":[["H5375","Suffer",0,6],["H1696","me that I may speak",7,26],["H0310","and after",28,37],["H1696","that I have spoken",38,56],["H3932","mock on",58,65]]},"21:4":{"text":"As for me, is my complaint to man? and if it were so, why should not my spirit be troubled?","words":[["H7879","As for me, is my complaint",0,26],["H0120","to man",27,33],["H7307","and if it were so, why should not my spirit",35,78],["H7114","be troubled",79,90]]},"21:5":{"text":"Mark me, and be astonished, and lay your hand upon your mouth.","words":[["H6437","Mark",0,4],["H8074","me, and be astonished",5,26],["H7760","and lay",28,35],["H3027","your hand",36,45],["H6310","upon your mouth",46,61]]},"21:6":{"text":"Even when I remember I am afraid, and trembling taketh hold on my flesh.","words":[["H2142","Even when I remember",0,20],["H0926","I am afraid",21,32],["H6427","and trembling",34,47],["H0270","taketh hold on",48,62],["H1320","my flesh",63,71]]},"21:7":{"text":"Wherefore do the wicked live, become old, yea, are mighty in power?","words":[["H7563","Wherefore do the wicked",0,23],["H2421","live",24,28],["H6275","become old",30,40],["H1396","yea, are mighty",42,57],["H2428","in power",58,66]]},"21:8":{"text":"Their seed is established in their sight with them, and their offspring before their eyes.","words":[["H2233","Their seed",0,10],["H3559","is established",11,25],["H6440","in their sight",26,40],["H6631","with them, and their offspring",41,71],["H5869","before their eyes",72,89]]},"21:9":{"text":"Their houses are safe from fear, neither is the rod of God upon them.","words":[["H1004","Their houses",0,12],["H7965","are safe",13,21],["H6343","from fear",22,31],["H7626","neither is the rod",33,51],["H0433","of God",52,58]]},"21:10":{"text":"Their bull gendereth, and faileth not; their cow calveth, and casteth not her calf.","words":[["H7794","Their bull",0,10],["H5674","gendereth",11,20],["H1602","and faileth",22,33],["H6510","not; their cow",34,48],["H6403","calveth",49,56],["H7921","and casteth not her calf",58,82]]},"21:11":{"text":"They send forth their little ones like a flock, and their children dance.","words":[["H7971","They send forth",0,15],["H5759","their little ones",16,33],["H6629","like a flock",34,46],["H3206","and their children",48,66],["H7540","dance",67,72]]},"21:12":{"text":"They take the timbrel and harp, and rejoice at the sound of the organ.","words":[["H5375","They take",0,9],["H8596","the timbrel",10,21],["H3658","and harp",22,30],["H8055","and rejoice",32,43],["H6963","at the sound",44,56],["H5748","of the organ",57,69]]},"21:13":{"text":"They spend their days in wealth, and in a moment go down to the grave.","words":[["H3615","They spend",0,10],["H1086","They spend",0,10],["H3117","their days",11,21],["H2896","in wealth",22,31],["H7281","and in a moment",33,48],["H2865","go down",49,56],["H5181","go down",49,56],["H7585","to the grave",57,69]]},"21:14":{"text":"Therefore they say unto God, Depart from us; for we desire not the knowledge of thy ways.","words":[["H0559","Therefore they say",0,18],["H0410","unto God",19,27],["H5493","Depart",29,35],["H2654","from us; for we desire",36,58],["H1847","not the knowledge",59,76],["H1870","of thy ways",77,88]]},"21:15":{"text":"What is the Almighty, that we should serve him? and what profit should we have, if we pray unto him?","words":[["H7706","What is the Almighty",0,20],["H5647","that we should serve",22,42],["H3276","him? and what profit",43,63],["H6293","should we have, if we pray",64,90]]},"21:16":{"text":"Lo, their good is not in their hand: the counsel of the wicked is far from me.","words":[["H2898","Lo, their good",0,14],["H3027","is not in their hand",15,35],["H6098","the counsel",37,48],["H7563","of the wicked",49,62],["H7368","is far",63,69]]},"21:17":{"text":"How oft is the candle of the wicked put out! and how oft cometh their destruction upon them! God distributeth sorrows in his anger.","words":[["H5216","How oft is the candle",0,21],["H7563","of the wicked",22,35],["H1846","put out",36,43],["H0935","and how oft cometh",45,63],["H0343","their destruction",64,81],["H2505","upon them! God distributeth",82,109],["H2256","sorrows",110,117],["H0639","in his anger",118,130]]},"21:18":{"text":"They are as stubble before the wind, and as chaff that the storm carrieth away.","words":[["H8401","They are as stubble",0,19],["H6440","before",20,26],["H7307","the wind",27,35],["H4671","and as chaff",37,49],["H5492","that the storm",50,64],["H1589","carrieth away",65,78]]},"21:19":{"text":"God layeth up his iniquity for his children: he rewardeth him, and he shall know it.","words":[["H0433","God",0,3],["H6845","layeth up",4,13],["H0205","his iniquity",14,26],["H1121","for his children",27,43],["H7999","he rewardeth",45,57],["H3045","him, and he shall know",58,80]]},"21:20":{"text":"His eyes shall see his destruction, and he shall drink of the wrath of the Almighty.","words":[["H5869","His eyes",0,8],["H7200","shall see",9,18],["H3589","his destruction",19,34],["H8354","and he shall drink",36,54],["H2534","of the wrath",55,67],["H7706","of the Almighty",68,83]]},"21:21":{"text":"For what pleasure hath he in his house after him, when the number of his months is cut off in the midst?","words":[["H2656","For what pleasure",0,17],["H1004","hath he in his house",18,38],["H0310","after",39,44],["H4557","him, when the number",45,65],["H2320","of his months",66,79],["H2686","is cut off in the midst",80,103]]},"21:22":{"text":"Shall any teach God knowledge? seeing he judgeth those that are high.","words":[["H3925","Shall any teach",0,15],["H0410","God",16,19],["H1847","knowledge",20,29],["H8199","seeing he judgeth",31,48],["H7311","those that are high",49,68]]},"21:23":{"text":"One dieth in his full strength, being wholly at ease and quiet.","words":[["H4191","One dieth",0,9],["H8537","in his full",10,21],["H6106","strength",22,30],["H7946","being wholly at ease",32,52],["H7961","and quiet",53,62]]},"21:24":{"text":"His breasts are full of milk, and his bones are moistened with marrow.","words":[["H5845","His breasts",0,11],["H4390","are full",12,20],["H2461","of milk",21,28],["H6106","and his bones",30,43],["H8248","are moistened",44,57],["H4221","with marrow",58,69]]},"21:25":{"text":"And another dieth in the bitterness of his soul, and never eateth with pleasure.","words":[["H4191","And another dieth",0,17],["H4751","in the bitterness",18,35],["H5315","of his soul",36,47],["H0398","and never eateth",49,65],["H2896","with pleasure",66,79]]},"21:26":{"text":"They shall lie down alike in the dust, and the worms shall cover them.","words":[["H7901","They shall lie down",0,19],["H3162","alike",20,25],["H6083","in the dust",26,37],["H7415","and the worms",39,52],["H3680","shall cover",53,64]]},"21:27":{"text":"Behold, I know your thoughts, and the devices which ye wrongfully imagine against me.","words":[["H3045","Behold, I know",0,14],["H4284","your thoughts",15,28],["H4209","and the devices",30,45],["H2554","which ye wrongfully imagine",46,73]]},"21:28":{"text":"For ye say, Where is the house of the prince? and where are the dwelling places of the wicked?","words":[["H0559","For ye say",0,10],["H1004","Where is the house",12,30],["H5081","of the prince",31,44],["H4908","and where are the dwelling",46,72],["H0168","places",73,79],["H7563","of the wicked",80,93]]},"21:29":{"text":"Have ye not asked them that go by the way? and do ye not know their tokens,","words":[["H7592","Have ye not asked",0,17],["H5674","them that go",18,30],["H1870","by the way",31,41],["H5234","and do ye not know",43,61],["H0226","their tokens",62,74]]},"21:30":{"text":"That the wicked is reserved to the day of destruction? they shall be brought forth to the day of wrath.","words":[["H7451","That the wicked",0,15],["H2820","is reserved",16,27],["H3117","to the day",28,38],["H0343","of destruction",39,53],["H2986","they shall be brought forth",55,82],["H3117","to the day",83,93],["H5678","of wrath",94,102]]},"21:31":{"text":"Who shall declare his way to his face? and who shall repay him what he hath done?","words":[["H5046","Who shall declare",0,17],["H1870","his way",18,25],["H6440","to his face",26,37],["H7999","and who shall repay",39,58],["H6213","him what he hath done",59,80]]},"21:32":{"text":"Yet shall he be brought to the grave, and shall remain in the tomb.","words":[["H2986","Yet shall he be brought",0,23],["H6913","to the grave",24,36],["H8245","and shall remain",38,54],["H1430","in the tomb",55,66]]},"21:33":{"text":"The clods of the valley shall be sweet unto him, and every man shall draw after him, as there are innumerable before him.","words":[["H7263","The clods",0,9],["H5158","of the valley",10,23],["H4985","shall be sweet",24,38],["H0120","unto him, and every man",39,62],["H4900","shall draw",63,73],["H0310","after",74,79],["H4557","him, as there are innumerable",80,109],["H6440","before",110,116]]},"21:34":{"text":"How then comfort ye me in vain, seeing in your answers there remaineth falsehood?","words":[["H5162","How then comfort",0,16],["H1892","ye me in vain",17,30],["H8666","seeing in your answers",32,54],["H7604","there remaineth",55,70],["H4604","falsehood",71,80]]},"22:1":{"text":"Then Eliphaz the Temanite answered and said,","words":[["H0464","Then Eliphaz",0,12],["H8489","the Temanite",13,25],["H6030","answered",26,34],["H0559","and said",35,43]]},"22:2":{"text":"Can a man be profitable unto God, as he that is wise may be profitable unto himself?","words":[["H1397","Can a man",0,9],["H5532","be profitable",10,23],["H0410","unto God",24,32],["H3588","as",34,36],["H7919","he that is wise",37,52],["H5532","may be profitable",53,70]]},"22:3":{"text":"Is it any pleasure to the Almighty, that thou art righteous? or is it gain to him, that thou makest thy ways perfect?","words":[["H2656","Is it any pleasure",0,18],["H7706","to the Almighty",19,34],["H6663","that thou art righteous",36,59],["H1215","or is it gain",61,74],["H1870","to him, that thou makest thy ways",75,108],["H8552","perfect",109,116]]},"22:4":{"text":"Will he reprove thee for fear of thee? will he enter with thee into judgment?","words":[["H3198","Will he reprove",0,15],["H3374","thee for fear",16,29],["H0935","of thee? will he enter",30,52],["H4941","with thee into judgment",53,76]]},"22:5":{"text":"Is not thy wickedness great? and thine iniquities infinite?","words":[["H7451","Is not thy wickedness",0,21],["H7227","great",22,27],["H5771","and thine iniquities",29,49],["H7093","infinite",50,58]]},"22:6":{"text":"For thou hast taken a pledge from thy brother for nought, and stripped the naked of their clothing.","words":[["H2254","For thou hast taken a pledge",0,28],["H0251","from thy brother",29,45],["H2600","for nought",46,56],["H6584","and stripped",58,70],["H6174","the naked",71,80],["H0899","of their clothing",81,98]]},"22:7":{"text":"Thou hast not given water to the weary to drink, and thou hast withholden bread from the hungry.","words":[["H4325","Thou hast not given water",0,25],["H5889","to the weary",26,38],["H8248","to drink",39,47],["H4513","and thou hast withholden",49,73],["H3899","bread",74,79],["H7457","from the hungry",80,95]]},"22:8":{"text":"But as for the mighty man, he had the earth; and the honourable man dwelt in it.","words":[["H2220","But as for the mighty",0,21],["H0376","man",22,25],["H0776","he had the earth",27,43],["H5375","and the honourable man",45,67],["H6440","and the honourable man",45,67],["H3427","dwelt",68,73]]},"22:9":{"text":"Thou hast sent widows away empty, and the arms of the fatherless have been broken.","words":[["H7971","Thou hast sent",0,14],["H0490","widows",15,21],["H7387","away empty",22,32],["H2220","and the arms",34,46],["H3490","of the fatherless",47,64],["H1792","have been broken",65,81]]},"22:10":{"text":"Therefore snares are round about thee, and sudden fear troubleth thee;","words":[["H6341","Therefore snares",0,16],["H5439","are round about",17,32],["H6597","thee, and sudden",33,49],["H6343","fear",50,54],["H0926","troubleth",55,64]]},"22:11":{"text":"Or darkness, that thou canst not see; and abundance of waters cover thee.","words":[["H2822","Or darkness",0,11],["H7200","that thou canst not see",13,36],["H8229","and abundance",38,51],["H4325","of waters",52,61],["H3680","cover",62,67]]},"22:12":{"text":"Is not God in the height of heaven? and behold the height of the stars, how high they are!","words":[["H0433","Is not God",0,10],["H1363","in the height",11,24],["H8064","of heaven",25,34],["H7200","and behold",36,46],["H7218","the height",47,57],["H3556","of the stars",58,70],["H7311","how high",72,80]]},"22:13":{"text":"And thou sayest, How doth God know? can he judge through the dark cloud?","words":[["H0559","And thou sayest",0,15],["H0410","How doth God",17,29],["H3045","know",30,34],["H8199","can he judge",36,48],["H6205","through the dark cloud",49,71]]},"22:14":{"text":"Thick clouds are a covering to him, that he seeth not; and he walketh in the circuit of heaven.","words":[["H5645","Thick clouds",0,12],["H5643","are a covering",13,27],["H7200","to him, that he seeth",28,49],["H1980","not; and he walketh",50,69],["H2329","in the circuit",70,84],["H8064","of heaven",85,94]]},"22:15":{"text":"Hast thou marked the old way which wicked men have trodden?","words":[["H8104","Hast thou marked",0,16],["H5769","the old",17,24],["H0734","way",25,28],["H0205","which wicked",29,41],["H4962","men",42,45],["H1869","have trodden",46,58]]},"22:16":{"text":"Which were cut down out of time, whose foundation was overflown with a flood:","words":[["H7059","Which were cut down",0,19],["H6256","out of time",20,31],["H3247","whose foundation",33,49],["H3332","was overflown",50,63],["H5104","with a flood",64,76]]},"22:17":{"text":"Which said unto God, Depart from us: and what can the Almighty do for them?","words":[["H0559","Which said",0,10],["H0410","unto God",11,19],["H5493","Depart",21,27],["H7706","from us: and what can the Almighty",28,62],["H6466","do",63,65]]},"22:18":{"text":"Yet he filled their houses with good things: but the counsel of the wicked is far from me.","words":[["H4390","Yet he filled",0,13],["H1004","their houses",14,26],["H2896","with good",27,36],["H6098","things: but the counsel",37,60],["H7563","of the wicked",61,74],["H7368","is far",75,81]]},"22:19":{"text":"The righteous see it, and are glad: and the innocent laugh them to scorn.","words":[["H6662","The righteous",0,13],["H7200","see",14,17],["H8055","it, and are glad",18,34],["H5355","and the innocent",36,52],["H3932","laugh them to scorn",53,72]]},"22:20":{"text":"Whereas our substance is not cut down, but the remnant of them the fire consumeth.","words":[["H0518","Whereas",0,7],["H7009","our substance",8,21],["H3582","is not cut down",22,37],["H3499","but the remnant",39,54],["H0784","of them the fire",55,71],["H0398","consumeth",72,81]]},"22:21":{"text":"Acquaint now thyself with him, and be at peace: thereby good shall come unto thee.","words":[["H5532","Acquaint",0,8],["H7999","now thyself with him, and be at peace",9,46],["H2896","thereby good",48,60],["H0935","shall come",61,71]]},"22:22":{"text":"Receive, I pray thee, the law from his mouth, and lay up his words in thine heart.","words":[["H3947","Receive",0,7],["H8451","I pray thee, the law",9,29],["H6310","from his mouth",30,44],["H7760","and lay up",46,56],["H0561","his words",57,66],["H3824","in thine heart",67,81]]},"22:23":{"text":"If thou return to the Almighty, thou shalt be built up, thou shalt put away iniquity far from thy tabernacles.","words":[["H7725","If thou return",0,14],["H7706","to the Almighty",15,30],["H1129","thou shalt be built up",32,54],["H7368","thou shalt put away",56,75],["H5766","iniquity",76,84],["H7368","far",85,88],["H0168","from thy tabernacles",89,109]]},"22:24":{"text":"Then shalt thou lay up gold as dust, and the gold of Ophir as the stones of the brooks.","words":[["H7896","Then shalt thou lay up",0,22],["H1220","gold",23,27],["H5921","as",28,30],["H6083","dust",31,35],["H0211","and the gold of Ophir",37,58],["H6697","as the stones",59,72],["H5158","of the brooks",73,86]]},"22:25":{"text":"Yea, the Almighty shall be thy defence, and thou shalt have plenty of silver.","words":[["H7706","Yea, the Almighty",0,17],["H1220","shall be thy defence",18,38],["H8443","and thou shalt have plenty",40,66],["H3701","of silver",67,76]]},"22:26":{"text":"For then shalt thou have thy delight in the Almighty, and shalt lift up thy face unto God.","words":[["H6026","For then shalt thou have thy delight",0,36],["H7706","in the Almighty",37,52],["H5375","and shalt lift up",54,71],["H6440","thy face",72,80],["H0433","unto God",81,89]]},"22:27":{"text":"Thou shalt make thy prayer unto him, and he shall hear thee, and thou shalt pay thy vows.","words":[["H6279","Thou shalt make thy prayer",0,26],["H8085","unto him, and he shall hear",27,54],["H7999","thee, and thou shalt pay",55,79],["H5088","thy vows",80,88]]},"22:28":{"text":"Thou shalt also decree a thing, and it shall be established unto thee: and the light shall shine upon thy ways.","words":[["H1504","Thou shalt also decree",0,22],["H0562","a thing",23,30],["H6965","and it shall be established",32,59],["H0216","unto thee: and the light",60,84],["H5050","shall shine",85,96],["H1870","upon thy ways",97,110]]},"22:29":{"text":"When men are cast down, then thou shalt say, There is lifting up; and he shall save the humble person.","words":[["H8213","When men are cast down",0,22],["H0559","then thou shalt say",24,43],["H1466","There is lifting up",45,64],["H3467","and he shall save",66,83],["H7807","the humble",84,94],["H5869","person",95,101]]},"22:30":{"text":"He shall deliver the island of the innocent: and it is delivered by the pureness of thine hands.","words":[["H4422","He shall deliver",0,16],["H0336","the island",17,27],["H5355","of the innocent",28,43],["H4422","and it is delivered",45,64],["H1252","by the pureness",65,80],["H3709","of thine hands",81,95]]},"23:1":{"text":"Then Job answered and said,","words":[["H0347","Then Job",0,8],["H6030","answered",9,17],["H0559","and said",18,26]]},"23:2":{"text":"Even to day is my complaint bitter: my stroke is heavier than my groaning.","words":[["H3117","Even to day",0,11],["H7879","is my complaint",12,27],["H4805","bitter",28,34],["H3027","my stroke",36,45],["H3513","is heavier",46,56],["H0585","than my groaning",57,73]]},"23:3":{"text":"Oh that I knew where I might find him! that I might come even to his seat!","words":[["H5414","Oh that",0,7],["H3045","I knew",8,14],["H4672","where I might find",15,33],["H0935","him! that I might come",34,56],["H8499","even to his seat",57,73]]},"23:4":{"text":"I would order my cause before him, and fill my mouth with arguments.","words":[["H6186","I would order",0,13],["H4941","my cause",14,22],["H6440","before",23,29],["H4390","him, and fill",30,43],["H6310","my mouth",44,52],["H8433","with arguments",53,67]]},"23:5":{"text":"I would know the words which he would answer me, and understand what he would say unto me.","words":[["H3045","I would know",0,12],["H4405","the words",13,22],["H6030","which he would answer",23,44],["H0995","me, and understand",45,63],["H0559","what he would say",64,81]]},"23:6":{"text":"Will he plead against me with his great power? No; but he would put strength in me.","words":[["H7378","Will he plead",0,13],["H5978","against",14,21],["H7230","me with his great",22,39],["H3581","power",40,45],["H7760","No; but he would put",47,67]]},"23:7":{"text":"There the righteous might dispute with him; so should I be delivered for ever from my judge.","words":[["H3477","There the righteous",0,19],["H3198","might dispute",20,33],["H6403","with him; so should I be delivered",34,68],["H5331","for ever",69,77],["H8199","from my judge",78,91]]},"23:8":{"text":"Behold, I go forward, but he is not there; and backward, but I cannot perceive him:","words":[["H1980","Behold, I go",0,12],["H6924","forward",13,20],["H0268","but he is not there; and backward",22,55],["H0995","but I cannot perceive",57,78]]},"23:9":{"text":"On the left hand, where he doth work, but I cannot behold him: he hideth himself on the right hand, that I cannot see him:","words":[["H8040","On the left hand",0,16],["H6213","where he doth work",18,36],["H2372","but I cannot behold",38,57],["H5848","him: he hideth",58,72],["H3225","himself on the right hand",73,98],["H7200","that I cannot see",100,117]]},"23:10":{"text":"But he knoweth the way that I take: when he hath tried me, I shall come forth as gold.","words":[["H3045","But he knoweth",0,14],["H1870","the way",15,22],["H5978","that I take",23,34],["H0974","when he hath tried",36,54],["H3318","me, I shall come forth",55,77],["H2091","as gold",78,85]]},"23:11":{"text":"My foot hath held his steps, his way have I kept, and not declined.","words":[["H7272","My foot",0,7],["H0270","hath held",8,17],["H0838","his steps",18,27],["H1870","his way",29,36],["H8104","have I kept",37,48],["H5186","and not declined",50,66]]},"23:12":{"text":"Neither have I gone back from the commandment of his lips; I have esteemed the words of his mouth more than my necessary food.","words":[["H4185","Neither have I gone back",0,24],["H4687","from the commandment",25,45],["H8193","of his lips",46,57],["H6845","I have esteemed",59,74],["H0561","the words",75,84],["H6310","of his mouth",85,97],["H2706","more than my necessary",98,120]]},"23:13":{"text":"But he is in one mind, and who can turn him? and what his soul desireth, even that he doeth.","words":[["H0259","But he is in one",0,16],["H7725","mind, and who can turn",17,39],["H5315","him? and what his soul",40,62],["H0183","desireth",63,71],["H6213","even that he doeth",73,91]]},"23:14":{"text":"For he performeth the thing that is appointed for me: and many such things are with him.","words":[["H7999","For he performeth",0,17],["H2706","the thing that is appointed",18,45],["H7227","for me: and many",46,62],["H2007","such",63,67]]},"23:15":{"text":"Therefore am I troubled at his presence: when I consider, I am afraid of him.","words":[["H0926","Therefore am I troubled",0,23],["H6440","at his presence",24,39],["H0995","when I consider",41,56],["H6342","I am afraid",58,69]]},"23:16":{"text":"For God maketh my heart soft, and the Almighty troubleth me:","words":[["H0410","For God",0,7],["H3820","maketh my heart",8,23],["H7401","soft",24,28],["H7706","and the Almighty",30,46],["H0926","troubleth",47,56]]},"23:17":{"text":"Because I was not cut off before the darkness, neither hath he covered the darkness from my face.","words":[["H6789","Because I was not cut off",0,25],["H6440","before",26,32],["H2822","the darkness",33,45],["H3680","neither hath he covered",47,70],["H0652","the darkness",71,83],["H6440","from my face",84,96]]},"24:1":{"text":"Why, seeing times are not hidden from the Almighty, do they that know him not see his days?","words":[["H6256","Why, seeing times",0,17],["H6845","are not hidden",18,32],["H7706","from the Almighty",33,50],["H3045","do they that know",52,69],["H2372","him not see",70,81],["H3117","his days",82,90]]},"24:2":{"text":"Some remove the landmarks; they violently take away flocks, and feed thereof.","words":[["H5381","Some remove",0,11],["H1367","the landmarks",12,25],["H1497","they violently take away",27,51],["H5739","flocks",52,58],["H7462","and feed",60,68]]},"24:3":{"text":"They drive away the ass of the fatherless, they take the widow's ox for a pledge.","words":[["H5090","They drive away",0,15],["H2543","the ass",16,23],["H3490","of the fatherless",24,41],["H2254","they take",43,52],["H0490","the widow's",53,64],["H7794","ox",65,67],["H2254","for a pledge",68,80]]},"24:4":{"text":"They turn the needy out of the way: the poor of the earth hide themselves together.","words":[["H5186","They turn",0,9],["H0034","the needy",10,19],["H1870","out of the way",20,34],["H6041","the poor",36,44],["H6035","the poor",36,44],["H0776","of the earth",45,57],["H2244","hide",58,62],["H3162","themselves together",63,82]]},"24:5":{"text":"Behold, as wild asses in the desert, go they forth to their work; rising betimes for a prey: the wilderness yieldeth food for them and for their children.","words":[["H6501","Behold, as wild asses",0,21],["H4057","in the desert",22,35],["H3318","go they forth",37,50],["H6467","to their work",51,64],["H7836","rising betimes",66,80],["H2964","for a prey",81,91],["H6160","the wilderness",93,107],["H3899","yieldeth food",108,121],["H5288","for them and for their children",122,153]]},"24:6":{"text":"They reap every one his corn in the field: and they gather the vintage of the wicked.","words":[["H7114","They reap",0,9],["H7114","They reap",0,9],["H1098","every one his corn",10,28],["H7704","in the field",29,41],["H3953","and they gather",43,58],["H3754","the vintage",59,70],["H7563","of the wicked",71,84]]},"24:7":{"text":"They cause the naked to lodge without clothing, that they have no covering in the cold.","words":[["H6174","They cause the naked",0,20],["H3885","to lodge",21,29],["H3830","without clothing",30,46],["H3682","that they have no covering",48,74],["H7135","in the cold",75,86]]},"24:8":{"text":"They are wet with the showers of the mountains, and embrace the rock for want of a shelter.","words":[["H7372","They are wet",0,12],["H2230","with the showers",13,29],["H2022","of the mountains",30,46],["H2263","and embrace",48,59],["H6697","the rock",60,68],["H4268","for want of a shelter",69,90]]},"24:9":{"text":"They pluck the fatherless from the breast, and take a pledge of the poor.","words":[["H1497","They pluck",0,10],["H3490","the fatherless",11,25],["H7699","from the breast",26,41],["H2254","and take a pledge",43,60],["H6041","of the poor",61,72]]},"24:10":{"text":"They cause him to go naked without clothing, and they take away the sheaf from the hungry;","words":[["H1980","They cause him to go",0,20],["H6174","naked",21,26],["H3830","without clothing",27,43],["H5375","and they take away",45,63],["H6016","the sheaf",64,73],["H7457","from the hungry",74,89]]},"24:11":{"text":"Which make oil within their walls, and tread their winepresses, and suffer thirst.","words":[["H6671","Which make oil",0,14],["H0996","within",15,21],["H7791","their walls",22,33],["H1869","and tread",35,44],["H3342","their winepresses",45,62],["H6770","and suffer thirst",64,81]]},"24:12":{"text":"Men groan from out of the city, and the soul of the wounded crieth out: yet God layeth not folly to them.","words":[["H4962","Men",0,3],["H5008","groan",4,9],["H5892","from out of the city",10,30],["H5315","and the soul",32,44],["H2491","of the wounded",45,59],["H7768","crieth out",60,70],["H0433","yet God",72,79],["H7760","layeth",80,86],["H8604","not folly",87,96]]},"24:13":{"text":"They are of those that rebel against the light; they know not the ways thereof, nor abide in the paths thereof.","words":[["H4775","They are of those that rebel",0,28],["H0216","against the light",29,46],["H5234","they know",48,57],["H1870","not the ways",58,70],["H3427","thereof, nor abide",71,89],["H5410","in the paths",90,102]]},"24:14":{"text":"The murderer rising with the light killeth the poor and needy, and in the night is as a thief.","words":[["H7523","The murderer",0,12],["H6965","rising",13,19],["H0216","with the light",20,34],["H6991","killeth",35,42],["H6041","the poor",43,51],["H0034","and needy",52,61],["H3915","and in the night",63,79],["H1590","is as a thief",80,93]]},"24:15":{"text":"The eye also of the adulterer waiteth for the twilight, saying, No eye shall see me: and disguiseth his face.","words":[["H5869","The eye",0,7],["H5003","also of the adulterer",8,29],["H8104","waiteth",30,37],["H5399","for the twilight",38,54],["H0559","saying",56,62],["H5869","No eye",64,70],["H7789","shall see",71,80],["H5643","me: and disguiseth",81,99],["H7760","me: and disguiseth",81,99],["H6440","his face",100,108]]},"24:16":{"text":"In the dark they dig through houses, which they had marked for themselves in the daytime: they know not the light.","words":[["H2822","In the dark",0,11],["H2864","they dig through",12,28],["H1004","houses",29,35],["H2856","which they had marked",37,58],["H3119","for themselves in the daytime",59,88],["H3045","they know",90,99],["H0216","not the light",100,113]]},"24:17":{"text":"For the morning is to them even as the shadow of death: if one know them, they are in the terrors of the shadow of death.","words":[["H1242","For the morning",0,15],["H3162","is to them even as",16,34],["H6757","the shadow of death",35,54],["H5234","if one know",56,67],["H1091","them, they are in the terrors",68,97],["H6757","of the shadow of death",98,120]]},"24:18":{"text":"He is swift as the waters; their portion is cursed in the earth: he beholdeth not the way of the vineyards.","words":[["H7031","He is swift",0,11],["H6440","as the waters",12,25],["H4325","as the waters",12,25],["H2513","their portion",27,40],["H7043","is cursed",41,50],["H0776","in the earth",51,63],["H6437","he beholdeth",65,77],["H1870","not the way",78,89],["H3754","of the vineyards",90,106]]},"24:19":{"text":"Drought and heat consume the snow waters: so doth the grave those which have sinned.","words":[["H6723","Drought",0,7],["H2527","and heat",8,16],["H1497","consume",17,24],["H7950","the snow",25,33],["H4325","waters",34,40],["H7585","so doth the grave",42,59],["H2398","those which have sinned",60,83]]},"24:20":{"text":"The womb shall forget him; the worm shall feed sweetly on him; he shall be no more remembered; and wickedness shall be broken as a tree.","words":[["H7358","The womb",0,8],["H7911","shall forget",9,21],["H7415","him; the worm",22,35],["H4988","shall feed sweetly",36,54],["H2142","on him; he shall be no more remembered",55,93],["H5766","and wickedness",95,109],["H7665","shall be broken",110,125],["H6086","as a tree",126,135]]},"24:21":{"text":"He evil entreateth the barren that beareth not: and doeth not good to the widow.","words":[["H7462","He evil entreateth",0,18],["H6135","the barren",19,29],["H3205","that beareth",30,42],["H3190","not: and doeth not good",43,66],["H0490","to the widow",67,79]]},"24:22":{"text":"He draweth also the mighty with his power: he riseth up, and no man is sure of life.","words":[["H4900","He draweth",0,10],["H0047","also the mighty",11,26],["H3581","with his power",27,41],["H6965","he riseth up",43,55],["H0539","and no man is sure",57,75],["H2416","of life",76,83]]},"24:23":{"text":"Though it be given him to be in safety, whereon he resteth; yet his eyes are upon their ways.","words":[["H5414","Though it be given",0,18],["H0983","him to be in safety",19,38],["H8172","whereon he resteth",40,58],["H5869","yet his eyes",60,72],["H1870","are upon their ways",73,92]]},"24:24":{"text":"They are exalted for a little while, but are gone and brought low; they are taken out of the way as all other, and cut off as the tops of the ears of corn.","words":[["H7426","They are exalted",0,16],["H4592","for a little while",17,35],["H4355","but are gone and brought low",37,65],["H7092","they are taken out",67,85],["H1870","of the way",86,96],["H5243","as all other, and cut off",97,122],["H7218","as the tops",123,134],["H7641","of the ears of corn",135,154]]},"24:25":{"text":"And if it be not so now, who will make me a liar, and make my speech nothing worth?","words":[["H0645","And if it be not so now",0,23],["H7760","who will make",25,38],["H3576","me a liar",39,48],["H7760","and make",50,58],["H4405","my speech",59,68],["H0408","nothing worth",69,82]]},"25:1":{"text":"Then answered Bildad the Shuhite, and said,","words":[["H6030","Then answered",0,13],["H1085","Bildad",14,20],["H7747","the Shuhite",21,32],["H0559","and said",34,42]]},"25:2":{"text":"Dominion and fear are with him, he maketh peace in his high places.","words":[["H4910","Dominion",0,8],["H6343","and fear",9,17],["H6213","are with him, he maketh",18,41],["H7965","peace",42,47],["H4791","in his high places",48,66]]},"25:3":{"text":"Is there any number of his armies? and upon whom doth not his light arise?","words":[["H3426","Is there",0,8],["H4557","any number",9,19],["H1416","of his armies",20,33],["H0216","and upon whom doth not his light",35,67],["H6965","arise",68,73]]},"25:4":{"text":"How then can man be justified with God? or how can he be clean that is born of a woman?","words":[["H0582","How then can man",0,16],["H6663","be justified",17,29],["H0410","with God",30,38],["H2135","or how can he be clean",40,62],["H3205","that is born",63,75],["H0802","of a woman",76,86]]},"25:5":{"text":"Behold even to the moon, and it shineth not; yea, the stars are not pure in his sight.","words":[["H3394","Behold even to the moon",0,23],["H0166","and it shineth",25,39],["H3556","not; yea, the stars",40,59],["H2141","are not pure",60,72],["H5869","in his sight",73,85]]},"25:6":{"text":"How much less man, that is a worm? and the son of man, which is a worm?","words":[["H0582","How much less man",0,17],["H7415","that is a worm",19,33],["H1121","and the son",35,46],["H0120","of man",47,53],["H8438","which is a worm",55,70]]},"26:1":{"text":"But Job answered and said,","words":[["H0347","But Job",0,7],["H6030","answered",8,16],["H0559","and said",17,25]]},"26:2":{"text":"How hast thou helped him that is without power? how savest thou the arm that hath no strength?","words":[["H5826","How hast thou helped",0,20],["H3581","him that is without power",21,46],["H3467","how savest",48,58],["H2220","thou the arm",59,71],["H3808","that hath no",72,84],["H5797","strength",85,93]]},"26:3":{"text":"How hast thou counselled him that hath no wisdom? and how hast thou plentifully declared the thing as it is?","words":[["H3289","How hast thou counselled",0,24],["H3808","him that hath no",25,41],["H2451","wisdom",42,48],["H7230","and how hast thou plentifully",50,79],["H3045","declared",80,88],["H8454","the thing as it is",89,107]]},"26:4":{"text":"To whom hast thou uttered words? and whose spirit came from thee?","words":[["H5046","To whom hast thou uttered",0,25],["H4405","words",26,31],["H5397","and whose spirit",33,49],["H3318","came",50,54]]},"26:5":{"text":"Dead things are formed from under the waters, and the inhabitants thereof.","words":[["H7496","Dead",0,4],["H2342","things are formed",5,22],["H4325","from under the waters",23,44],["H7931","and the inhabitants",46,65]]},"26:6":{"text":"Hell is naked before him, and destruction hath no covering.","words":[["H7585","Hell",0,4],["H6174","is naked",5,13],["H0011","before him, and destruction",14,41],["H3682","hath no covering",42,58]]},"26:7":{"text":"He stretcheth out the north over the empty place, and hangeth the earth upon nothing.","words":[["H5186","He stretcheth out",0,17],["H6828","the north",18,27],["H8414","over the empty place",28,48],["H8518","and hangeth",50,61],["H0776","the earth",62,71],["H1099","upon nothing",72,84]]},"26:8":{"text":"He bindeth up the waters in his thick clouds; and the cloud is not rent under them.","words":[["H6887","He bindeth up",0,13],["H4325","the waters",14,24],["H5645","in his thick clouds",25,44],["H6051","and the cloud",46,59],["H1234","is not rent",60,71]]},"26:9":{"text":"He holdeth back the face of his throne, and spreadeth his cloud upon it.","words":[["H0270","He holdeth back",0,15],["H6440","the face",16,24],["H3678","of his throne",25,38],["H6576","and spreadeth",40,53],["H6051","his cloud",54,63]]},"26:10":{"text":"He hath compassed the waters with bounds, until the day and night come to an end.","words":[["H2328","He hath compassed",0,17],["H6440","the waters",18,28],["H4325","the waters",18,28],["H2706","with bounds",29,40],["H0216","until the day",42,55],["H2822","and night",56,65],["H8503","come to an end",66,80]]},"26:11":{"text":"The pillars of heaven tremble and are astonished at his reproof.","words":[["H5982","The pillars",0,11],["H8064","of heaven",12,21],["H7322","tremble",22,29],["H8539","and are astonished",30,48],["H1606","at his reproof",49,63]]},"26:12":{"text":"He divideth the sea with his power, and by his understanding he smiteth through the proud.","words":[["H7280","He divideth",0,11],["H3220","the sea",12,19],["H3581","with his power",20,34],["H8394","and by his understanding",36,60],["H8394","and by his understanding",36,60],["H4272","he smiteth",61,71],["H7293","through the proud",72,89]]},"26:13":{"text":"By his spirit he hath garnished the heavens; his hand hath formed the crooked serpent.","words":[["H7307","By his spirit",0,13],["H8235","he hath garnished",14,31],["H8064","the heavens",32,43],["H3027","his hand",45,53],["H2342","hath formed",54,65],["H1281","the crooked",66,77],["H5175","serpent",78,85]]},"26:14":{"text":"Lo, these are parts of his ways: but how little a portion is heard of him? but the thunder of his power who can understand?","words":[["H7098","Lo, these are parts",0,19],["H1870","of his ways",20,31],["H8102","but how little",33,47],["H1697","a portion",48,57],["H8085","is heard",58,66],["H7482","of him? but the thunder",67,90],["H1369","of his power",91,103],["H0995","who can understand",104,122]]},"27:1":{"text":"Moreover Job continued his parable, and said,","words":[["H0347","Moreover Job",0,12],["H3254","continued",13,22],["H5375","continued",13,22],["H4912","his parable",23,34],["H0559","and said",36,44]]},"27:2":{"text":"As God liveth, who hath taken away my judgment; and the Almighty, who hath vexed my soul;","words":[["H0410","As God",0,6],["H2416","liveth",7,13],["H5493","who hath taken away",15,34],["H4941","my judgment",35,46],["H7706","and the Almighty",48,64],["H4843","who hath vexed",66,80],["H5315","my soul",81,88]]},"27:3":{"text":"All the while my breath is in me, and the spirit of God is in my nostrils;","words":[["H5750","All the while",0,13],["H5397","my breath",14,23],["H7307","is in me, and the spirit",24,48],["H0433","of God",49,55],["H0639","is in my nostrils",56,73]]},"27:4":{"text":"My lips shall not speak wickedness, nor my tongue utter deceit.","words":[["H8193","My lips",0,7],["H1696","shall not speak",8,23],["H5766","wickedness",24,34],["H3956","nor my tongue",36,49],["H1897","utter",50,55],["H7423","deceit",56,62]]},"27:5":{"text":"God forbid that I should justify you: till I die I will not remove mine integrity from me.","words":[["H2486","God forbid",0,10],["H6663","that I should justify",11,32],["H1478","you: till I die",33,48],["H5493","I will not remove",49,66],["H8538","mine integrity",67,81]]},"27:6":{"text":"My righteousness I hold fast, and will not let it go: my heart shall not reproach me so long as I live.","words":[["H6666","My righteousness",0,16],["H2388","I hold",17,23],["H7503","fast, and will not let it go",24,52],["H3824","my heart",54,62],["H2778","shall not reproach",63,81],["H3117","me so long as I live",82,102]]},"27:7":{"text":"Let mine enemy be as the wicked, and he that riseth up against me as the unrighteous.","words":[["H0341","Let mine enemy",0,14],["H7563","be as the wicked",15,31],["H6965","and he that riseth up",33,54],["H5767","against me as the unrighteous",55,84]]},"27:8":{"text":"For what is the hope of the hypocrite, though he hath gained, when God taketh away his soul?","words":[["H8615","For what is the hope",0,20],["H2611","of the hypocrite",21,37],["H1214","though he hath gained",39,60],["H0433","when God",62,70],["H7953","taketh away",71,82],["H5315","his soul",83,91]]},"27:9":{"text":"Will God hear his cry when trouble cometh upon him?","words":[["H0410","Will God",0,8],["H8085","hear",9,13],["H6818","his cry",14,21],["H6869","when trouble",22,34],["H0935","cometh",35,41]]},"27:10":{"text":"Will he delight himself in the Almighty? will he always call upon God?","words":[["H6026","Will he delight",0,15],["H7706","himself in the Almighty",16,39],["H6256","will he always",41,55],["H7121","call",56,60],["H0433","upon God",61,69]]},"27:11":{"text":"I will teach you by the hand of God: that which is with the Almighty will I not conceal.","words":[["H3384","I will teach",0,12],["H3027","you by the hand",13,28],["H0410","of God",29,35],["H7706","that which is with the Almighty",37,68],["H3582","will I not conceal",69,87]]},"27:12":{"text":"Behold, all ye yourselves have seen it; why then are ye thus altogether vain?","words":[["H2372","Behold, all ye yourselves have seen",0,35],["H1892","it; why then are ye thus altogether",36,71],["H1891","vain",72,76]]},"27:13":{"text":"This is the portion of a wicked man with God, and the heritage of oppressors, which they shall receive of the Almighty.","words":[["H2506","This is the portion",0,19],["H7563","of a wicked",20,31],["H0120","man",32,35],["H0410","with God",36,44],["H5159","and the heritage",46,62],["H6184","of oppressors",63,76],["H3947","which they shall receive",78,102],["H7706","of the Almighty",103,118]]},"27:14":{"text":"If his children be multiplied, it is for the sword: and his offspring shall not be satisfied with bread.","words":[["H1121","If his children",0,15],["H7235","be multiplied",16,29],["H3926","it is for",31,40],["H2719","the sword",41,50],["H6631","and his offspring",52,69],["H7646","shall not be satisfied",70,92],["H3899","with bread",93,103]]},"27:15":{"text":"Those that remain of him shall be buried in death: and his widows shall not weep.","words":[["H8300","Those that remain",0,17],["H6912","of him shall be buried",18,40],["H4194","in death",41,49],["H0490","and his widows",51,65],["H1058","shall not weep",66,80]]},"27:16":{"text":"Though he heap up silver as the dust, and prepare raiment as the clay;","words":[["H6651","Though he heap up",0,17],["H3701","silver",18,24],["H6083","as the dust",25,36],["H3559","and prepare",38,49],["H4403","raiment",50,57],["H2563","as the clay",58,69]]},"27:17":{"text":"He may prepare it, but the just shall put it on, and the innocent shall divide the silver.","words":[["H3559","He may prepare",0,14],["H6662","it, but the just",15,31],["H3847","shall put it on",32,47],["H5355","and the innocent",49,65],["H2505","shall divide",66,78],["H3701","the silver",79,89]]},"27:18":{"text":"He buildeth his house as a moth, and as a booth that the keeper maketh.","words":[["H1129","He buildeth",0,11],["H1004","his house",12,21],["H6211","as a moth",22,31],["H5521","and as a booth",33,47],["H5341","that the keeper",48,63],["H6213","maketh",64,70]]},"27:19":{"text":"The rich man shall lie down, but he shall not be gathered: he openeth his eyes, and he is not.","words":[["H6223","The rich",0,8],["H7901","man shall lie down",9,27],["H0622","but he shall not be gathered",29,57],["H6491","he openeth",59,69],["H5869","his eyes",70,78]]},"27:20":{"text":"Terrors take hold on him as waters, a tempest stealeth him away in the night.","words":[["H1091","Terrors",0,7],["H5381","take hold",8,17],["H4325","on him as waters",18,34],["H5492","a tempest",36,45],["H1589","stealeth him away",46,63],["H3915","in the night",64,76]]},"27:21":{"text":"The east wind carrieth him away, and he departeth: and as a storm hurleth him out of his place.","words":[["H6921","The east",0,8],["H5375","wind carrieth him away",9,31],["H3212","and he departeth",33,49],["H8175","and as a storm hurleth",51,73],["H4725","him out of his place",74,94]]},"27:22":{"text":"For God shall cast upon him, and not spare: he would fain flee out of his hand.","words":[["H7993","For God shall cast",0,18],["H2550","upon him, and not spare",19,42],["H1272","he would fain",44,57],["H1272","flee",58,62],["H3027","out of his hand",63,78]]},"27:23":{"text":"Men shall clap their hands at him, and shall hiss him out of his place.","words":[["H5606","Men shall clap",0,14],["H3709","their hands",15,26],["H8319","at him, and shall hiss",27,49],["H4725","him out of his place",50,70]]},"28:1":{"text":"Surely there is a vein for the silver, and a place for gold where they fine it.","words":[["H3426","Surely",0,6],["H4161","there is a vein",7,22],["H3701","for the silver",23,37],["H4725","and a place",39,50],["H2091","for gold",51,59],["H2212","where they fine",60,75]]},"28:2":{"text":"Iron is taken out of the earth, and brass is molten out of the stone.","words":[["H1270","Iron",0,4],["H3947","is taken",5,13],["H6083","out of the earth",14,30],["H5154","and brass",32,41],["H6694","is molten",42,51],["H0068","out of the stone",52,68]]},"28:3":{"text":"He setteth an end to darkness, and searcheth out all perfection: the stones of darkness, and the shadow of death.","words":[["H7760","He setteth",0,10],["H7093","an end",11,17],["H2822","to darkness",18,29],["H2713","and searcheth out",31,48],["H8503","all perfection",49,63],["H0068","the stones",65,75],["H0652","of darkness",76,87],["H6757","and the shadow of death",89,112]]},"28:4":{"text":"The flood breaketh out from the inhabitant; even the waters forgotten of the foot: they are dried up, they are gone away from men.","words":[["H5158","The flood",0,9],["H6555","breaketh out",10,22],["H1481","from the inhabitant",23,42],["H7911","even the waters forgotten",44,69],["H7272","of the foot",70,81],["H1809","they are dried up",83,100],["H5128","they are gone away",102,120],["H0582","from men",121,129]]},"28:5":{"text":"As for the earth, out of it cometh bread: and under it is turned up as it were fire.","words":[["H0776","As for the earth",0,16],["H3318","out of it cometh",18,34],["H3899","bread",35,40],["H2015","and under it is turned up",42,67],["H0784","as it were fire",68,83]]},"28:6":{"text":"The stones of it are the place of sapphires: and it hath dust of gold.","words":[["H0068","The stones",0,10],["H4725","of it are the place",11,30],["H5601","of sapphires",31,43],["H6083","and it hath dust",45,61],["H2091","of gold",62,69]]},"28:7":{"text":"There is a path which no fowl knoweth, and which the vulture's eye hath not seen:","words":[["H5410","There is a path",0,15],["H5861","which no fowl",16,29],["H3045","knoweth",30,37],["H0344","and which the vulture's",39,62],["H5869","eye",63,66],["H7805","hath not seen",67,80]]},"28:8":{"text":"The lion's whelps have not trodden it, nor the fierce lion passed by it.","words":[["H7830","The lion's",0,10],["H1121","whelps",11,17],["H1869","have not trodden",18,34],["H7826","it, nor the fierce lion",35,58],["H5710","passed",59,65]]},"28:9":{"text":"He putteth forth his hand upon the rock; he overturneth the mountains by the roots.","words":[["H7971","He putteth forth",0,16],["H3027","his hand",17,25],["H2496","upon the rock",26,39],["H2015","he overturneth",41,55],["H2022","the mountains",56,69],["H8328","by the roots",70,82]]},"28:10":{"text":"He cutteth out rivers among the rocks; and his eye seeth every precious thing.","words":[["H1234","He cutteth out",0,14],["H2975","rivers",15,21],["H6697","among the rocks",22,37],["H5869","and his eye",39,50],["H7200","seeth",51,56],["H3366","every precious thing",57,77]]},"28:11":{"text":"He bindeth the floods from overflowing; and the thing that is hid bringeth he forth to light.","words":[["H2280","He bindeth",0,10],["H5104","the floods",11,21],["H1065","from overflowing",22,38],["H8587","and the thing that is hid",40,65],["H3318","bringeth he forth",66,83],["H0216","to light",84,92]]},"28:12":{"text":"But where shall wisdom be found? and where is the place of understanding?","words":[["H0370","But where",0,9],["H2451","shall wisdom",10,22],["H4672","be found",23,31],["H4725","and where is the place",33,55],["H0998","of understanding",56,72]]},"28:13":{"text":"Man knoweth not the price thereof; neither is it found in the land of the living.","words":[["H0582","Man",0,3],["H3045","knoweth",4,11],["H6187","not the price",12,25],["H4672","thereof; neither is it found",26,54],["H0776","in the land",55,66],["H2416","of the living",67,80]]},"28:14":{"text":"The depth saith, It is not in me: and the sea saith, It is not with me.","words":[["H8415","The depth",0,9],["H0559","saith",10,15],["H3220","It is not in me: and the sea",17,45],["H0559","saith",46,51]]},"28:15":{"text":"It cannot be gotten for gold, neither shall silver be weighed for the price thereof.","words":[["H5414","It cannot be gotten",0,19],["H5458","for gold",20,28],["H3701","neither shall silver",30,50],["H8254","be weighed",51,61],["H4242","for the price",62,75]]},"28:16":{"text":"It cannot be valued with the gold of Ophir, with the precious onyx, or the sapphire.","words":[["H5541","It cannot be valued",0,19],["H3800","with the gold",20,33],["H0211","of Ophir",34,42],["H3368","with the precious",44,61],["H7718","onyx",62,66],["H5601","or the sapphire",68,83]]},"28:17":{"text":"The gold and the crystal cannot equal it: and the exchange of it shall not be for jewels of fine gold.","words":[["H2091","The gold",0,8],["H2137","and the crystal",9,24],["H6186","cannot equal",25,37],["H8545","it: and the exchange",38,58],["H3627","of it shall not be for jewels",59,88],["H6337","of fine gold",89,101]]},"28:18":{"text":"No mention shall be made of coral, or of pearls: for the price of wisdom is above rubies.","words":[["H2142","No mention",0,10],["H7215","shall be made of coral",11,33],["H1378","or of pearls",35,47],["H4901","for the price",49,62],["H2451","of wisdom",63,72],["H6443","is above rubies",73,88]]},"28:19":{"text":"The topaz of Ethiopia shall not equal it, neither shall it be valued with pure gold.","words":[["H6357","The topaz",0,9],["H3568","of Ethiopia",10,21],["H6186","shall not equal",22,37],["H5541","it, neither shall it be valued",38,68],["H2889","with pure",69,78],["H3800","gold",79,83]]},"28:20":{"text":"Whence then cometh wisdom? and where is the place of understanding?","words":[["H0370","Whence",0,6],["H0935","then cometh",7,18],["H2451","wisdom",19,25],["H4725","and where is the place",27,49],["H0998","of understanding",50,66]]},"28:21":{"text":"Seeing it is hid from the eyes of all living, and kept close from the fowls of the air.","words":[["H5956","Seeing it is hid",0,16],["H5869","from the eyes",17,30],["H2416","of all living",31,44],["H5641","and kept close",46,60],["H5775","from the fowls",61,75],["H8064","of the air",76,86]]},"28:22":{"text":"Destruction and death say, We have heard the fame thereof with our ears.","words":[["H0011","Destruction",0,11],["H4194","and death",12,21],["H0559","say",22,25],["H8085","We have heard",27,40],["H8088","the fame",41,49],["H0241","thereof with our ears",50,71]]},"28:23":{"text":"God understandeth the way thereof, and he knoweth the place thereof.","words":[["H0430","God",0,3],["H0995","understandeth",4,17],["H1870","the way",18,25],["H3045","thereof, and he knoweth",26,49],["H4725","the place",50,59]]},"28:24":{"text":"For he looketh to the ends of the earth, and seeth under the whole heaven;","words":[["H5027","For he looketh",0,14],["H7098","to the ends",15,26],["H0776","of the earth",27,39],["H7200","and seeth",41,50],["H8064","under the whole heaven",51,73]]},"28:25":{"text":"To make the weight for the winds; and he weigheth the waters by measure.","words":[["H6213","To make",0,7],["H4948","the weight",8,18],["H7307","for the winds",19,32],["H8505","and he weigheth",34,49],["H4325","the waters",50,60],["H4060","by measure",61,71]]},"28:26":{"text":"When he made a decree for the rain, and a way for the lightning of the thunder:","words":[["H6213","When he made",0,12],["H2706","a decree",13,21],["H4306","for the rain",22,34],["H1870","and a way",36,45],["H2385","for the lightning",46,63],["H6963","of the thunder",64,78]]},"28:27":{"text":"Then did he see it, and declare it; he prepared it, yea, and searched it out.","words":[["H7200","Then did he see",0,15],["H5608","it, and declare",16,31],["H3559","it; he prepared",32,47],["H2713","it, yea, and searched it out",48,76]]},"28:28":{"text":"And unto man he said, Behold, the fear of the Lord, that is wisdom; and to depart from evil is understanding.","words":[["H0120","And unto man",0,12],["H0559","he said",13,20],["H3374","Behold, the fear",22,38],["H0136","of the Lord",39,50],["H2451","that is wisdom",52,66],["H5493","and to depart",68,81],["H7451","from evil",82,91],["H0998","is understanding",92,108]]},"29:1":{"text":"Moreover Job continued his parable, and said,","words":[["H0347","Moreover Job",0,12],["H3254","continued",13,22],["H5375","continued",13,22],["H4912","his parable",23,34],["H0559","and said",36,44]]},"29:2":{"text":"Oh that I were as in months past, as in the days when God preserved me;","words":[["H5414","Oh that",0,7],["H3391","I were as in months",8,27],["H6924","past",28,32],["H3117","as in the days",34,48],["H0433","when God",49,57],["H8104","preserved",58,67]]},"29:3":{"text":"When his candle shined upon my head, and when by his light I walked through darkness;","words":[["H5216","When his candle",0,15],["H1984","shined",16,22],["H7218","upon my head",23,35],["H0216","and when by his light",37,58],["H3212","I walked",59,67],["H2822","through darkness",68,84]]},"29:4":{"text":"As I was in the days of my youth, when the secret of God was upon my tabernacle;","words":[["H3117","As I was in the days",0,20],["H2779","of my youth",21,32],["H5475","when the secret",34,49],["H0433","of God",50,56],["H0168","was upon my tabernacle",57,79]]},"29:5":{"text":"When the Almighty was yet with me, when my children were about me;","words":[["H7706","When the Almighty",0,17],["H5288","was yet with me, when my children",18,51],["H5439","were about",52,62]]},"29:6":{"text":"When I washed my steps with butter, and the rock poured me out rivers of oil;","words":[["H7364","When I washed",0,13],["H1978","my steps",14,22],["H2529","with butter",23,34],["H6697","and the rock",36,48],["H6694","poured me out",49,62],["H6388","rivers",63,69],["H8081","of oil",70,76]]},"29:7":{"text":"When I went out to the gate through the city, when I prepared my seat in the street!","words":[["H3318","When I went out",0,15],["H8179","to the gate",16,27],["H7176","through the city",28,44],["H3559","when I prepared",46,61],["H4186","my seat",62,69],["H7339","in the street",70,83]]},"29:8":{"text":"The young men saw me, and hid themselves: and the aged arose, and stood up.","words":[["H5288","The young men",0,13],["H7200","saw",14,17],["H2244","me, and hid",18,29],["H3453","themselves: and the aged",30,54],["H6965","arose",55,60],["H5975","and stood up",62,74]]},"29:9":{"text":"The princes refrained talking, and laid their hand on their mouth.","words":[["H8269","The princes",0,11],["H6113","refrained",12,21],["H4405","talking",22,29],["H7760","and laid",31,39],["H3709","their hand",40,50],["H6310","on their mouth",51,65]]},"29:10":{"text":"The nobles held their peace, and their tongue cleaved to the roof of their mouth.","words":[["H5057","The nobles",0,10],["H2244","held",11,15],["H6963","their peace",16,27],["H3956","and their tongue",29,45],["H1692","cleaved",46,53],["H2441","to the roof of their mouth",54,80]]},"29:11":{"text":"When the ear heard me, then it blessed me; and when the eye saw me, it gave witness to me:","words":[["H0241","When the ear",0,12],["H8085","heard",13,18],["H0833","me, then it blessed",19,38],["H5869","me; and when the eye",39,59],["H7200","saw",60,63],["H5749","me, it gave witness",64,83]]},"29:12":{"text":"Because I delivered the poor that cried, and the fatherless, and him that had none to help him.","words":[["H4422","Because I delivered",0,19],["H6041","the poor",20,28],["H7768","that cried",29,39],["H3490","and the fatherless",41,59],["H5826","and him that had none to help",61,90]]},"29:13":{"text":"The blessing of him that was ready to perish came upon me: and I caused the widow's heart to sing for joy.","words":[["H1293","The blessing",0,12],["H0006","of him that was ready to perish",13,44],["H0935","came",45,49],["H0490","upon me: and I caused the widow's",50,83],["H3820","heart",84,89],["H7442","to sing for joy",90,105]]},"29:14":{"text":"I put on righteousness, and it clothed me: my judgment was as a robe and a diadem.","words":[["H3847","I put",0,5],["H6664","on righteousness",6,22],["H3847","and it clothed",24,38],["H4941","me: my judgment",39,54],["H4598","was as a robe",55,68],["H6797","and a diadem",69,81]]},"29:15":{"text":"I was eyes to the blind, and feet was I to the lame.","words":[["H5869","I was eyes",0,10],["H5787","to the blind",11,23],["H7272","and feet",25,33],["H6455","was I to the lame",34,51]]},"29:16":{"text":"I was a father to the poor: and the cause which I knew not I searched out.","words":[["H0001","I was a father",0,14],["H0034","to the poor",15,26],["H7379","and the cause",28,41],["H3045","which I knew",42,54],["H2713","not I searched out",55,73]]},"29:17":{"text":"And I brake the jaws of the wicked, and plucked the spoil out of his teeth.","words":[["H7665","And I brake",0,11],["H4973","the jaws",12,20],["H5767","of the wicked",21,34],["H7993","and plucked",36,47],["H2964","the spoil",48,57],["H8127","out of his teeth",58,74]]},"29:18":{"text":"Then I said, I shall die in my nest, and I shall multiply my days as the sand.","words":[["H0559","Then I said",0,11],["H1478","I shall die",13,24],["H7064","in my nest",25,35],["H7235","and I shall multiply",37,57],["H3117","my days",58,65],["H2344","as the sand",66,77]]},"29:19":{"text":"My root was spread out by the waters, and the dew lay all night upon my branch.","words":[["H8328","My root",0,7],["H6605","was spread out",8,22],["H4325","by the waters",23,36],["H2919","and the dew",38,49],["H3885","lay all night",50,63],["H7105","upon my branch",64,78]]},"29:20":{"text":"My glory was fresh in me, and my bow was renewed in my hand.","words":[["H3519","My glory",0,8],["H2319","was fresh",9,18],["H5978","in me",19,24],["H7198","and my bow",26,36],["H2498","was renewed",37,48],["H3027","in my hand",49,59]]},"29:21":{"text":"Unto me men gave ear, and waited, and kept silence at my counsel.","words":[["H8085","Unto me men gave ear",0,20],["H3176","and waited",22,32],["H1826","and kept silence",34,50],["H3926","at",51,53],["H6098","my counsel",54,64]]},"29:22":{"text":"After my words they spake not again; and my speech dropped upon them.","words":[["H0310","After",0,5],["H1697","my words",6,14],["H8138","they spake not again",15,35],["H4405","and my speech",37,50],["H5197","dropped",51,58]]},"29:23":{"text":"And they waited for me as for the rain; and they opened their mouth wide as for the latter rain.","words":[["H3176","And they waited",0,15],["H4306","for me as for the rain",16,38],["H6473","and they opened",40,55],["H6310","their mouth",56,67],["H4456","wide as for the latter rain",68,95]]},"29:24":{"text":"If I laughed on them, they believed it not; and the light of my countenance they cast not down.","words":[["H7832","If I laughed",0,12],["H0539","on them, they believed",13,35],["H0216","it not; and the light",36,57],["H6440","of my countenance",58,75],["H5307","they cast not down",76,94]]},"29:25":{"text":"I chose out their way, and sat chief, and dwelt as a king in the army, as one that comforteth the mourners.","words":[["H0977","I chose",0,7],["H1870","out their way",8,21],["H3427","and sat",23,30],["H7218","chief",31,36],["H7931","and dwelt",38,47],["H4428","as a king",48,57],["H1416","in the army",58,69],["H5162","as one that comforteth",71,93],["H0057","the mourners",94,106]]},"30:1":{"text":"But now they that are younger than I have me in derision, whose fathers I would have disdained to have set with the dogs of my flock.","words":[["H6810","But now they that are younger",0,29],["H3117","But now they that are younger",0,29],["H7832","than I have me in derision",30,56],["H0001","whose fathers",58,71],["H3988","I would have disdained",72,94],["H7896","to have set",95,106],["H3611","with the dogs",107,120],["H6629","of my flock",121,132]]},"30:2":{"text":"Yea, whereto might the strength of their hands profit me, in whom old age was perished?","words":[["H4100","Yea, whereto",0,12],["H3581","might the strength",13,31],["H3027","of their hands",32,46],["H3624","profit me, in whom old age",47,73],["H0006","was perished",74,86]]},"30:3":{"text":"For want and famine they were solitary; fleeing into the wilderness in former time desolate and waste.","words":[["H2639","For want",0,8],["H3720","and famine",9,19],["H1565","they were solitary",20,38],["H6207","fleeing",40,47],["H6723","into the wilderness",48,67],["H0570","in former time",68,82],["H7722","desolate",83,91],["H4875","and waste",92,101]]},"30:4":{"text":"Who cut up mallows by the bushes, and juniper roots for their meat.","words":[["H6998","Who cut up",0,10],["H4408","mallows",11,18],["H7880","by the bushes",19,32],["H7574","and juniper",34,45],["H8328","roots",46,51],["H3899","for their meat",52,66]]},"30:5":{"text":"They were driven forth from among men, (they cried after them as after a thief;)","words":[["H1644","They were driven forth",0,22],["H1460","from among",23,33],["H7321","men, (they cried",34,50],["H1590","after them as after a thief",51,78]]},"30:6":{"text":"To dwell in the clifts of the valleys, in caves of the earth, and in the rocks.","words":[["H7931","To dwell",0,8],["H6178","in the clifts",9,22],["H5158","of the valleys",23,37],["H2356","in caves",39,47],["H6083","of the earth",48,60],["H3710","and in the rocks",62,78]]},"30:7":{"text":"Among the bushes they brayed; under the nettles they were gathered together.","words":[["H7880","Among the bushes",0,16],["H5101","they brayed",17,28],["H2738","under the nettles",30,47],["H5596","they were gathered together",48,75]]},"30:8":{"text":"They were children of fools, yea, children of base men: they were viler than the earth.","words":[["H1121","They were children",0,18],["H5036","of fools",19,27],["H1121","yea, children",29,42],["H8034","of base men",43,54],["H5217","they were viler",56,71],["H0776","than the earth",72,86]]},"30:9":{"text":"And now am I their song, yea, I am their byword.","words":[["H5058","And now am I their song",0,23],["H4405","yea, I am their byword",25,47]]},"30:10":{"text":"They abhor me, they flee far from me, and spare not to spit in my face.","words":[["H8581","They abhor",0,10],["H7368","me, they flee far",11,28],["H2820","from me, and spare",29,47],["H7536","not to spit",48,59],["H6440","in my face",60,70]]},"30:11":{"text":"Because he hath loosed my cord, and afflicted me, they have also let loose the bridle before me.","words":[["H6605","Because he hath loosed",0,22],["H3499","my cord",23,30],["H6031","and afflicted",32,45],["H7971","me, they have also let loose",46,74],["H7448","the bridle",75,85],["H6440","before",86,92]]},"30:12":{"text":"Upon my right hand rise the youth; they push away my feet, and they raise up against me the ways of their destruction.","words":[["H3225","Upon my right",0,13],["H6965","hand rise",14,23],["H6526","the youth",24,33],["H7971","they push away",35,49],["H7272","my feet",50,57],["H5549","and they raise up",59,76],["H0734","against me the ways",77,96],["H0343","of their destruction",97,117]]},"30:13":{"text":"They mar my path, they set forward my calamity, they have no helper.","words":[["H5420","They mar",0,8],["H5410","my path",9,16],["H3276","they set forward",18,34],["H1942","my calamity",35,46],["H1962","my calamity",35,46],["H5826","they have no helper",48,67]]},"30:14":{"text":"They came upon me as a wide breaking in of waters: in the desolation they rolled themselves upon me.","words":[["H0857","They came",0,9],["H7342","upon me as a wide",10,27],["H6556","breaking",28,36],["H8478","in of waters: in",37,53],["H7722","the desolation",54,68],["H1556","they rolled",69,80]]},"30:15":{"text":"Terrors are turned upon me: they pursue my soul as the wind: and my welfare passeth away as a cloud.","words":[["H1091","Terrors",0,7],["H2015","are turned",8,18],["H7291","upon me: they pursue",19,39],["H5082","my soul",40,47],["H7307","as the wind",48,59],["H3444","and my welfare",61,75],["H5674","passeth away",76,88],["H5645","as a cloud",89,99]]},"30:16":{"text":"And now my soul is poured out upon me; the days of affliction have taken hold upon me.","words":[["H5315","And now my soul",0,15],["H8210","is poured out",16,29],["H3117","upon me; the days",30,47],["H6040","of affliction",48,61],["H0270","have taken hold",62,77]]},"30:17":{"text":"My bones are pierced in me in the night season: and my sinews take no rest.","words":[["H6106","My bones",0,8],["H5365","are pierced",9,20],["H3915","in me in the night season",21,46],["H6207","and my sinews",48,61],["H7901","take no rest",62,74]]},"30:18":{"text":"By the great force of my disease is my garment changed: it bindeth me about as the collar of my coat.","words":[["H7230","By the great",0,12],["H3581","force",13,18],["H3830","of my disease is my garment",19,46],["H2664","changed",47,54],["H0247","it bindeth me about",56,75],["H6310","as the collar",76,89],["H3801","of my coat",90,100]]},"30:19":{"text":"He hath cast me into the mire, and I am become like dust and ashes.","words":[["H3384","He hath cast",0,12],["H2563","me into the mire",13,29],["H4911","and I am become like",31,51],["H6083","dust",52,56],["H0665","and ashes",57,66]]},"30:20":{"text":"I cry unto thee, and thou dost not hear me: I stand up, and thou regardest me not.","words":[["H7768","I cry",0,5],["H6030","unto thee, and thou dost not hear",6,39],["H5975","me: I stand up",40,54],["H0995","and thou regardest",56,74]]},"30:21":{"text":"Thou art become cruel to me: with thy strong hand thou opposest thyself against me.","words":[["H2015","Thou art become",0,15],["H0393","cruel",16,21],["H6108","to me: with thy strong",22,44],["H3027","hand",45,49],["H7852","thou opposest",50,63]]},"30:22":{"text":"Thou liftest me up to the wind; thou causest me to ride upon it, and dissolvest my substance.","words":[["H5375","Thou liftest me up",0,18],["H7307","to the wind",19,30],["H7392","thou causest me to ride",32,55],["H4127","upon it, and dissolvest",56,79],["H8454","my substance",80,92],["H7738","my substance",80,92]]},"30:23":{"text":"For I know that thou wilt bring me to death, and to the house appointed for all living.","words":[["H3045","For I know",0,10],["H7725","that thou wilt bring",11,31],["H4194","me to death",32,43],["H1004","and to the house",45,61],["H4150","appointed",62,71],["H2416","for all living",72,86]]},"30:24":{"text":"Howbeit he will not stretch out his hand to the grave, though they cry in his destruction.","words":[["H7971","Howbeit he will not stretch out",0,31],["H3027","his hand",32,40],["H1164","to the grave",41,53],["H7769","though they cry",55,70],["H6365","in his destruction",71,89]]},"30:25":{"text":"Did not I weep for him that was in trouble? was not my soul grieved for the poor?","words":[["H1058","Did not I weep",0,14],["H7186","for him that was in trouble",15,42],["H3117","for him that was in trouble",15,42],["H5315","was not my soul",44,59],["H5701","grieved",60,67],["H0034","for the poor",68,80]]},"30:26":{"text":"When I looked for good, then evil came unto me: and when I waited for light, there came darkness.","words":[["H6960","When I looked",0,13],["H2896","for good",14,22],["H7451","then evil",24,33],["H0935","came",34,38],["H3176","unto me: and when I waited",39,65],["H0216","for light",66,75],["H0935","there came",77,87],["H0652","darkness",88,96]]},"30:27":{"text":"My bowels boiled, and rested not: the days of affliction prevented me.","words":[["H4578","My bowels",0,9],["H7570","boiled",10,16],["H1826","and rested",18,28],["H3117","not: the days",29,42],["H6040","of affliction",43,56],["H6923","prevented",57,66]]},"30:28":{"text":"I went mourning without the sun: I stood up, and I cried in the congregation.","words":[["H1980","I went",0,6],["H6937","mourning",7,15],["H2535","without the sun",16,31],["H6965","I stood up",33,43],["H7768","and I cried",45,56],["H6951","in the congregation",57,76]]},"30:29":{"text":"I am a brother to dragons, and a companion to owls.","words":[["H0251","I am a brother",0,14],["H8577","to dragons",15,25],["H7453","and a companion",27,42],["H1323","to owls",43,50],["H3284","to owls",43,50]]},"30:30":{"text":"My skin is black upon me, and my bones are burned with heat.","words":[["H5785","My skin",0,7],["H7835","is black",8,16],["H6106","upon me, and my bones",17,38],["H2787","are burned",39,49],["H2721","with heat",50,59]]},"30:31":{"text":"My harp also is turned to mourning, and my organ into the voice of them that weep.","words":[["H3658","My harp",0,7],["H0060","also is turned to mourning",8,34],["H5748","and my organ",36,48],["H6963","into the voice",49,63],["H1058","of them that weep",64,81]]},"31:1":{"text":"I made a covenant with mine eyes; why then should I think upon a maid?","words":[["H3772","I made",0,6],["H1285","a covenant",7,17],["H5869","with mine eyes",18,32],["H0995","why then should I think",34,57],["H1330","upon a maid",58,69]]},"31:2":{"text":"For what portion of God is there from above? and what inheritance of the Almighty from on high?","words":[["H2506","For what portion",0,16],["H0433","of God",17,23],["H4605","is there from above",24,43],["H5159","and what inheritance",45,65],["H7706","of the Almighty",66,81],["H4791","from on high",82,94]]},"31:3":{"text":"Is not destruction to the wicked? and a strange punishment to the workers of iniquity?","words":[["H0343","Is not destruction",0,18],["H5767","to the wicked",19,32],["H5235","and a strange",34,47],["H6466","punishment to the workers",48,73],["H0205","of iniquity",74,85]]},"31:4":{"text":"Doth not he see my ways, and count all my steps?","words":[["H7200","Doth not he see",0,15],["H1870","my ways",16,23],["H5608","and count",25,34],["H6806","all my steps",35,47]]},"31:5":{"text":"If I have walked with vanity, or if my foot hath hasted to deceit;","words":[["H1980","If I have walked",0,16],["H7723","with vanity",17,28],["H7272","or if my foot",30,43],["H2363","hath hasted",44,55],["H4820","to deceit",56,65]]},"31:6":{"text":"Let me be weighed in an even balance, that God may know mine integrity.","words":[["H8254","Let me be weighed",0,17],["H6664","in an even",18,28],["H3976","balance",29,36],["H0433","that God",38,46],["H3045","may know",47,55],["H8538","mine integrity",56,70]]},"31:7":{"text":"If my step hath turned out of the way, and mine heart walked after mine eyes, and if any blot hath cleaved to mine hands;","words":[["H0838","If my step",0,10],["H5186","hath turned out",11,26],["H1870","of the way",27,37],["H3820","and mine heart",39,53],["H1980","walked",54,60],["H0310","after",61,66],["H5869","mine eyes",67,76],["H3971","and if any blot",78,93],["H1692","hath cleaved",94,106],["H3709","to mine hands",107,120]]},"31:8":{"text":"Then let me sow, and let another eat; yea, let my offspring be rooted out.","words":[["H2232","Then let me sow",0,15],["H0312","and let another",17,32],["H0398","eat",33,36],["H6631","yea, let my offspring",38,59],["H8327","be rooted out",60,73]]},"31:9":{"text":"If mine heart have been deceived by a woman, or if I have laid wait at my neighbour's door;","words":[["H3820","If mine heart",0,13],["H6601","have been deceived",14,32],["H0802","by a woman",33,43],["H0693","or if I have laid wait",45,67],["H7453","at my neighbour's",68,85],["H6607","door",86,90]]},"31:10":{"text":"Then let my wife grind unto another, and let others bow down upon her.","words":[["H0802","Then let my wife",0,16],["H2912","grind",17,22],["H0312","unto another",23,35],["H0312","and let others",37,51],["H3766","bow down",52,60]]},"31:11":{"text":"For this is an heinous crime; yea, it is an iniquity to be punished by the judges.","words":[["H2154","For this is an heinous crime",0,28],["H5771","yea, it is an iniquity",30,52],["H6414","to be punished by the judges",53,81]]},"31:12":{"text":"For it is a fire that consumeth to destruction, and would root out all mine increase.","words":[["H0784","For it is a fire",0,16],["H0398","that consumeth",17,31],["H0011","to destruction",32,46],["H8327","and would root out",48,66],["H8393","all mine increase",67,84]]},"31:13":{"text":"If I did despise the cause of my manservant or of my maidservant, when they contended with me;","words":[["H3988","If I did despise",0,16],["H4941","the cause",17,26],["H5650","of my manservant",27,43],["H0519","or of my maidservant",44,64],["H7379","when they contended",66,85]]},"31:14":{"text":"What then shall I do when God riseth up? and when he visiteth, what shall I answer him?","words":[["H6213","What then shall I do",0,20],["H0410","when God",21,29],["H6965","riseth up",30,39],["H6485","and when he visiteth",41,61],["H7725","what shall I answer",63,82]]},"31:15":{"text":"Did not he that made me in the womb make him? and did not one fashion us in the womb?","words":[["H6213","Did not he that made",0,20],["H0990","me in the womb",21,35],["H6213","make",36,40],["H0259","him? and did not one",41,61],["H3559","fashion",62,69],["H7358","us in the womb",70,84]]},"31:16":{"text":"If I have withheld the poor from their desire, or have caused the eyes of the widow to fail;","words":[["H4513","If I have withheld",0,18],["H1800","the poor",19,27],["H2656","from their desire",28,45],["H5869","or have caused the eyes",47,70],["H0490","of the widow",71,83],["H3615","to fail",84,91]]},"31:17":{"text":"Or have eaten my morsel myself alone, and the fatherless hath not eaten thereof;","words":[["H0398","Or have eaten",0,13],["H6595","my morsel",14,23],["H3490","myself alone, and the fatherless",24,56],["H0398","hath not eaten",57,71]]},"31:18":{"text":"(For from my youth he was brought up with me, as with a father, and I have guided her from my mother's womb;)","words":[["H5271","(For from my youth",0,18],["H1431","he was brought up",19,36],["H0001","with me, as with a father",37,62],["H5148","and I have guided",64,81],["H0517","her from my mother's",82,102],["H0990","womb",103,107]]},"31:19":{"text":"If I have seen any perish for want of clothing, or any poor without covering;","words":[["H7200","If I have seen",0,14],["H0006","any perish",15,25],["H3830","for want of clothing",26,46],["H0034","or any poor",48,59],["H3682","without covering",60,76]]},"31:20":{"text":"If his loins have not blessed me, and if he were not warmed with the fleece of my sheep;","words":[["H2504","If his loins",0,12],["H1288","have not blessed",13,29],["H2552","me, and if he were not warmed",30,59],["H1488","with the fleece",60,75],["H3532","of my sheep",76,87]]},"31:21":{"text":"If I have lifted up my hand against the fatherless, when I saw my help in the gate:","words":[["H5130","If I have lifted up",0,19],["H3027","my hand",20,27],["H3490","against the fatherless",28,50],["H7200","when I saw",52,62],["H5833","my help",63,70],["H8179","in the gate",71,82]]},"31:22":{"text":"Then let mine arm fall from my shoulder blade, and mine arm be broken from the bone.","words":[["H3802","Then let mine arm",0,17],["H5307","fall",18,22],["H7929","from my shoulder blade",23,45],["H0248","and mine arm",47,59],["H7665","be broken",60,69],["H7070","from the bone",70,83]]},"31:23":{"text":"For destruction from God was a terror to me, and by reason of his highness I could not endure.","words":[["H0343","For destruction",0,15],["H0410","from God",16,24],["H6343","was a terror",25,37],["H7613","to me, and by reason of his highness",38,74],["H3201","I could",75,82]]},"31:24":{"text":"If I have made gold my hope, or have said to the fine gold, Thou art my confidence;","words":[["H7760","If I have made",0,14],["H2091","gold",15,19],["H3689","my hope",20,27],["H0559","or have said",29,41],["H3800","to the fine gold",42,58],["H4009","Thou art my confidence",60,82]]},"31:25":{"text":"If I rejoiced because my wealth was great, and because mine hand had gotten much;","words":[["H8055","If I rejoiced",0,13],["H2428","because my wealth",14,31],["H7227","was great",32,41],["H3027","and because mine hand",43,64],["H4672","had gotten",65,75],["H3524","much",76,80]]},"31:26":{"text":"If I beheld the sun when it shined, or the moon walking in brightness;","words":[["H7200","If I beheld",0,11],["H0216","the sun",12,19],["H1984","when it shined",20,34],["H3394","or the moon",36,47],["H1980","walking",48,55],["H3368","in brightness",56,69]]},"31:27":{"text":"And my heart hath been secretly enticed, or my mouth hath kissed my hand:","words":[["H3820","And my heart",0,12],["H5643","hath been secretly",13,31],["H6601","enticed",32,39],["H6310","or my mouth",41,52],["H5401","hath kissed",53,64],["H3027","my hand",65,72]]},"31:28":{"text":"This also were an iniquity to be punished by the judge: for I should have denied the God that is above.","words":[["H5771","This also were an iniquity",0,26],["H6416","to be punished by the judge",27,54],["H3584","for I should have denied",56,80],["H0410","the God",81,88],["H4605","that is above",89,102]]},"31:29":{"text":"If I rejoiced at the destruction of him that hated me, or lifted up myself when evil found him:","words":[["H8055","If I rejoiced",0,13],["H6365","at the destruction",14,32],["H8130","of him that hated",33,50],["H5782","me, or lifted up",51,67],["H7451","myself when evil",68,84],["H4672","found",85,90]]},"31:30":{"text":"Neither have I suffered my mouth to sin by wishing a curse to his soul.","words":[["H5414","Neither have I suffered",0,23],["H2441","my mouth",24,32],["H2398","to sin",33,39],["H7592","by wishing",40,50],["H0423","a curse",51,58],["H5315","to his soul",59,70]]},"31:31":{"text":"If the men of my tabernacle said not, Oh that we had of his flesh! we cannot be satisfied.","words":[["H4962","If the men",0,10],["H0168","of my tabernacle",11,27],["H0559","said",28,32],["H5414","not, Oh that we had",33,52],["H1320","of his flesh",53,65],["H7646","we cannot be satisfied",67,89]]},"31:32":{"text":"The stranger did not lodge in the street: but I opened my doors to the traveller.","words":[["H1616","The stranger",0,12],["H3885","did not lodge",13,26],["H2351","in the street",27,40],["H6605","but I opened",42,54],["H1817","my doors",55,63],["H0734","to the traveller",64,80]]},"31:33":{"text":"If I covered my transgressions as Adam, by hiding mine iniquity in my bosom:","words":[["H3680","If I covered",0,12],["H6588","my transgressions",13,30],["H0121","as Adam",31,38],["H2934","by hiding",40,49],["H5771","mine iniquity",50,63],["H2243","in my bosom",64,75]]},"31:34":{"text":"Did I fear a great multitude, or did the contempt of families terrify me, that I kept silence, and went not out of the door?","words":[["H6206","Did I fear",0,10],["H7227","a great",11,18],["H1995","multitude",19,28],["H0937","or did the contempt",30,49],["H4940","of families",50,61],["H2865","terrify",62,69],["H1826","me, that I kept silence",70,93],["H3318","and went not out",95,111],["H6607","of the door",112,123]]},"31:35":{"text":"Oh that one would hear me! behold, my desire is, that the Almighty would answer me, and that mine adversary had written a book.","words":[["H5414","Oh that",0,7],["H8085","one would hear",8,22],["H8420","me! behold, my desire",23,44],["H7706","is, that the Almighty",45,66],["H6030","would answer",67,79],["H0376","me, and that mine adversary",80,107],["H7379","me, and that mine adversary",80,107],["H3789","had written",108,119],["H5612","a book",120,126]]},"31:36":{"text":"Surely I would take it upon my shoulder, and bind it as a crown to me.","words":[["H5375","Surely I would take",0,19],["H7926","it upon my shoulder",20,39],["H6029","and bind",41,49],["H5850","it as a crown",50,63]]},"31:37":{"text":"I would declare unto him the number of my steps; as a prince would I go near unto him.","words":[["H5046","I would declare",0,15],["H4557","unto him the number",16,35],["H6806","of my steps",36,47],["H5057","as a prince",49,60],["H7126","would I go near",61,76]]},"31:38":{"text":"If my land cry against me, or that the furrows likewise thereof complain;","words":[["H0127","If my land",0,10],["H2199","cry",11,14],["H8525","against me, or that the furrows",15,46],["H3162","likewise",47,55],["H1058","thereof complain",56,72]]},"31:39":{"text":"If I have eaten the fruits thereof without money, or have caused the owners thereof to lose their life:","words":[["H0398","If I have eaten",0,15],["H3581","the fruits",16,26],["H3701","thereof without money",27,48],["H1167","or have caused the owners",50,75],["H5301","thereof to lose",76,91],["H5315","their life",92,102]]},"31:40":{"text":"Let thistles grow instead of wheat, and cockle instead of barley. The words of Job are ended.","words":[["H2336","Let thistles",0,12],["H3318","grow",13,17],["H2406","instead of wheat",18,34],["H0890","and cockle",36,46],["H8184","instead of barley",47,64],["H1697","The words",66,75],["H0347","of Job",76,82],["H8552","are ended",83,92]]},"32:1":{"text":"So these three men ceased to answer Job, because he was righteous in his own eyes.","words":[["H7969","So these three",0,14],["H0582","men",15,18],["H7673","ceased",19,25],["H6030","to answer",26,35],["H0347","Job",36,39],["H6662","because he was righteous",41,65],["H5869","in his own eyes",66,81]]},"32:2":{"text":"Then was kindled the wrath of Elihu the son of Barachel the Buzite, of the kindred of Ram: against Job was his wrath kindled, because he justified himself rather than God.","words":[["H2734","Then was kindled",0,16],["H0639","the wrath",17,26],["H0453","of Elihu",27,35],["H1121","the son",36,43],["H1292","of Barachel",44,55],["H0940","the Buzite",56,66],["H4940","of the kindred",68,82],["H7410","of Ram",83,89],["H0347","against Job",91,102],["H0639","was his wrath",103,116],["H2734","kindled",117,124],["H6663","because he justified",126,146],["H5315","himself",147,154],["H0430","rather than God",155,170]]},"32:3":{"text":"Also against his three friends was his wrath kindled, because they had found no answer, and yet had condemned Job.","words":[["H7969","Also against his three",0,22],["H7453","friends",23,30],["H0639","was his wrath",31,44],["H2734","kindled",45,52],["H4672","because they had found",54,76],["H4617","no answer",77,86],["H7561","and yet had condemned",88,109],["H0347","Job",110,113]]},"32:4":{"text":"Now Elihu had waited till Job had spoken, because they were elder than he.","words":[["H0453","Now Elihu",0,9],["H2442","had waited",10,20],["H0347","till Job",21,29],["H1697","had spoken",30,40],["H2205","because they were elder",42,65],["H3117","because they were elder",42,65]]},"32:5":{"text":"When Elihu saw that there was no answer in the mouth of these three men, then his wrath was kindled.","words":[["H0453","When Elihu",0,10],["H7200","saw",11,14],["H4617","that there was no answer",15,39],["H6310","in the mouth",40,52],["H7969","of these three",53,67],["H0582","men",68,71],["H0639","then his wrath",73,87],["H2734","was kindled",88,99]]},"32:6":{"text":"And Elihu the son of Barachel the Buzite answered and said, I am young, and ye are very old; wherefore I was afraid, and durst not shew you mine opinion.","words":[["H0453","And Elihu",0,9],["H1121","the son",10,17],["H1292","of Barachel",18,29],["H0940","the Buzite",30,40],["H6030","answered",41,49],["H0559","and said",50,58],["H6810","I am young",60,70],["H3117","I am young",60,70],["H3453","and ye are very old",72,91],["H2119","wherefore I was afraid",93,115],["H3372","and durst",117,126],["H2331","not shew",127,135],["H1843","you mine opinion",136,152]]},"32:7":{"text":"I said, Days should speak, and multitude of years should teach wisdom.","words":[["H0559","I said",0,6],["H3117","Days",8,12],["H1696","should speak",13,25],["H7230","and multitude",27,40],["H8141","of years",41,49],["H3045","should teach",50,62],["H2451","wisdom",63,69]]},"32:8":{"text":"But there is a spirit in man: and the inspiration of the Almighty giveth them understanding.","words":[["H0403","But",0,3],["H7307","there is a spirit",4,21],["H0582","in man",22,28],["H5397","and the inspiration",30,49],["H7706","of the Almighty",50,65],["H0995","giveth them understanding",66,91]]},"32:9":{"text":"Great men are not always wise: neither do the aged understand judgment.","words":[["H7227","Great men",0,9],["H2449","are not always wise",10,29],["H2205","neither do the aged",31,50],["H0995","understand",51,61],["H4941","judgment",62,70]]},"32:10":{"text":"Therefore I said, Hearken to me; I also will shew mine opinion.","words":[["H0559","Therefore I said",0,16],["H8085","Hearken",18,25],["H2331","to me; I also will shew",26,49],["H1843","mine opinion",50,62]]},"32:11":{"text":"Behold, I waited for your words; I gave ear to your reasons, whilst ye searched out what to say.","words":[["H3176","Behold, I waited",0,16],["H1697","for your words",17,31],["H0238","I gave ear",33,43],["H8394","to your reasons",44,59],["H2713","whilst ye searched out",61,83],["H4405","what to say",84,95]]},"32:12":{"text":"Yea, I attended unto you, and, behold, there was none of you that convinced Job, or that answered his words:","words":[["H0995","Yea, I attended",0,15],["H3198","unto you, and, behold, there was none of you that convinced",16,75],["H0347","Job",76,79],["H6030","or that answered",81,97],["H0561","his words",98,107]]},"32:13":{"text":"Lest ye should say, We have found out wisdom: God thrusteth him down, not man.","words":[["H0559","Lest ye should say",0,18],["H4672","We have found out",20,37],["H2451","wisdom",38,44],["H0410","God",46,49],["H5086","thrusteth him down",50,68],["H0376","not man",70,77]]},"32:14":{"text":"Now he hath not directed his words against me: neither will I answer him with your speeches.","words":[["H6186","Now he hath not directed",0,24],["H4405","his words",25,34],["H7725","against me: neither will I answer",35,68],["H0561","him with your speeches",69,91]]},"32:15":{"text":"They were amazed, they answered no more: they left off speaking.","words":[["H2865","They were amazed",0,16],["H6030","they answered",18,31],["H6275","no more: they left off",32,54],["H4405","speaking",55,63]]},"32:16":{"text":"When I had waited, (for they spake not, but stood still, and answered no more;)","words":[["H3176","When I had waited",0,17],["H1696","(for they spake",19,34],["H5975","not, but stood still",35,55],["H6030","and answered",57,69]]},"32:17":{"text":"I said, I will answer also my part, I also will shew mine opinion.","words":[["H6030","I said, I will answer",0,21],["H2506","also my part",22,34],["H2331","I also will shew",36,52],["H1843","mine opinion",53,65]]},"32:18":{"text":"For I am full of matter, the spirit within me constraineth me.","words":[["H4390","For I am full",0,13],["H4405","of matter",14,23],["H7307","the spirit",25,35],["H0990","within",36,42],["H6693","me constraineth",43,58]]},"32:19":{"text":"Behold, my belly is as wine which hath no vent; it is ready to burst like new bottles.","words":[["H0990","Behold, my belly",0,16],["H3196","is as wine",17,27],["H6605","which hath no vent",28,46],["H1234","it is ready to burst",48,68],["H2319","like new",69,77],["H0178","bottles",78,85]]},"32:20":{"text":"I will speak, that I may be refreshed: I will open my lips and answer.","words":[["H1696","I will speak",0,12],["H7304","that I may be refreshed",14,37],["H6605","I will open",39,50],["H8193","my lips",51,58],["H6030","and answer",59,69]]},"32:21":{"text":"Let me not, I pray you, accept any man's person, neither let me give flattering titles unto man.","words":[["H5375","Let me not, I pray you, accept",0,30],["H0376","any man's",31,40],["H6440","person",41,47],["H3655","neither let me give flattering titles",49,86],["H0120","unto man",87,95]]},"32:22":{"text":"For I know not to give flattering titles; in so doing my maker would soon take me away.","words":[["H3045","For I know",0,10],["H3655","not to give flattering titles",11,40],["H6213","in so doing my maker",42,62],["H4592","would soon",63,73],["H5375","take me away",74,86]]},"33:1":{"text":"Wherefore, Job, I pray thee, hear my speeches, and hearken to all my words.","words":[["H0199","Wherefore",0,9],["H0347","Job",11,14],["H8085","I pray thee, hear",16,33],["H4405","my speeches",34,45],["H0238","and hearken",47,58],["H1697","to all my words",59,74]]},"33:2":{"text":"Behold, now I have opened my mouth, my tongue hath spoken in my mouth.","words":[["H6605","Behold, now I have opened",0,25],["H6310","my mouth",26,34],["H3956","my tongue",36,45],["H1696","hath spoken",46,57],["H2441","in my mouth",58,69]]},"33:3":{"text":"My words shall be of the uprightness of my heart: and my lips shall utter knowledge clearly.","words":[["H0561","My words",0,8],["H3476","shall be of the uprightness",9,36],["H3820","of my heart",37,48],["H8193","and my lips",50,61],["H4448","shall utter",62,73],["H1847","knowledge",74,83],["H1305","clearly",84,91]]},"33:4":{"text":"The Spirit of God hath made me, and the breath of the Almighty hath given me life.","words":[["H7307","The Spirit",0,10],["H0410","of God",11,17],["H6213","hath made",18,27],["H5397","me, and the breath",28,46],["H7706","of the Almighty",47,62],["H2421","hath given me life",63,81]]},"33:5":{"text":"If thou canst answer me, set thy words in order before me, stand up.","words":[["H3201","If thou canst",0,13],["H7725","answer",14,20],["H6186","me, set thy words in order",21,47],["H6440","before",48,54],["H3320","me, stand up",55,67]]},"33:6":{"text":"Behold, I am according to thy wish in God's stead: I also am formed out of the clay.","words":[["H6310","Behold, I am according to thy wish",0,34],["H0410","in God's",35,43],["H7169","stead: I also am formed",44,67],["H2563","out of the clay",68,83]]},"33:7":{"text":"Behold, my terror shall not make thee afraid, neither shall my hand be heavy upon thee.","words":[["H0367","Behold, my terror",0,17],["H1204","shall not make thee afraid",18,44],["H0405","neither shall my hand",46,67],["H3513","be heavy",68,76]]},"33:8":{"text":"Surely thou hast spoken in mine hearing, and I have heard the voice of thy words, saying,","words":[["H0559","Surely thou hast spoken",0,23],["H0241","in mine hearing",24,39],["H8085","and I have heard",41,57],["H6963","the voice",58,67],["H4405","of thy words",68,80]]},"33:9":{"text":"I am clean without transgression, I am innocent; neither is there iniquity in me.","words":[["H2134","I am clean",0,10],["H6588","without transgression",11,32],["H2643","I am innocent",34,47],["H5771","neither is there iniquity",49,74]]},"33:10":{"text":"Behold, he findeth occasions against me, he counteth me for his enemy,","words":[["H4672","Behold, he findeth",0,18],["H8569","occasions",19,28],["H2803","against me, he counteth",29,52],["H0341","me for his enemy",53,69]]},"33:11":{"text":"He putteth my feet in the stocks, he marketh all my paths.","words":[["H7760","He putteth",0,10],["H7272","my feet",11,18],["H5465","in the stocks",19,32],["H8104","he marketh",34,44],["H0734","all my paths",45,57]]},"33:12":{"text":"Behold, in this thou art not just: I will answer thee, that God is greater than man.","words":[["H6663","Behold, in this thou art not just",0,33],["H6030","I will answer",35,48],["H0433","thee, that God",49,63],["H7235","is greater",64,74],["H0582","than man",75,83]]},"33:13":{"text":"Why dost thou strive against him? for he giveth not account of any of his matters.","words":[["H7378","Why dost thou strive",0,20],["H6030","against him? for he giveth not account",21,59],["H1697","of any of his matters",60,81]]},"33:14":{"text":"For God speaketh once, yea twice, yet man perceiveth it not.","words":[["H0410","For God",0,7],["H1696","speaketh",8,16],["H0259","once",17,21],["H8147","yea twice",23,32],["H7789","yet man perceiveth",34,52]]},"33:15":{"text":"In a dream, in a vision of the night, when deep sleep falleth upon men, in slumberings upon the bed;","words":[["H2472","In a dream",0,10],["H2384","in a vision",12,23],["H3915","of the night",24,36],["H8639","when deep",38,47],["H5307","sleep falleth",48,61],["H0582","upon men",62,70],["H8572","in slumberings",72,86],["H4904","upon the bed",87,99]]},"33:16":{"text":"Then he openeth the ears of men, and sealeth their instruction,","words":[["H1540","Then he openeth",0,15],["H0241","the ears",16,24],["H0582","of men",25,31],["H2856","and sealeth",33,44],["H4561","their instruction",45,62]]},"33:17":{"text":"That he may withdraw man from his purpose, and hide pride from man.","words":[["H5493","That he may withdraw",0,20],["H0120","man",21,24],["H4639","from his purpose",25,41],["H3680","and hide",43,51],["H1466","pride",52,57],["H1397","from man",58,66]]},"33:18":{"text":"He keepeth back his soul from the pit, and his life from perishing by the sword.","words":[["H2820","He keepeth back",0,15],["H5315","his soul",16,24],["H7845","from the pit",25,37],["H2416","and his life",39,51],["H5674","from perishing",52,66],["H7973","by the sword",67,79]]},"33:19":{"text":"He is chastened also with pain upon his bed, and the multitude of his bones with strong pain:","words":[["H3198","He is chastened",0,15],["H4341","also with pain",16,30],["H4904","upon his bed",31,43],["H7230","and the multitude",45,62],["H7379","and the multitude",45,62],["H6106","of his bones",63,75],["H0386","with strong",76,87]]},"33:20":{"text":"So that his life abhorreth bread, and his soul dainty meat.","words":[["H2416","So that his life",0,16],["H2092","abhorreth",17,26],["H3899","bread",27,32],["H5315","and his soul",34,46],["H8378","dainty",47,53],["H3978","meat",54,58]]},"33:21":{"text":"His flesh is consumed away, that it cannot be seen; and his bones that were not seen stick out.","words":[["H1320","His flesh",0,9],["H3615","is consumed away",10,26],["H7210","that it cannot be seen",28,50],["H6106","and his bones",52,65],["H7200","that were not seen",66,84],["H8192","stick out",85,94],["H8205","stick out",85,94]]},"33:22":{"text":"Yea, his soul draweth near unto the grave, and his life to the destroyers.","words":[["H5315","Yea, his soul",0,13],["H7126","draweth near",14,26],["H7845","unto the grave",27,41],["H2416","and his life",43,55],["H4191","to the destroyers",56,73]]},"33:23":{"text":"If there be a messenger with him, an interpreter, one among a thousand, to shew unto man his uprightness:","words":[["H3426","If there",0,8],["H4397","be a messenger",9,23],["H3887","with him, an interpreter",24,48],["H0259","one",50,53],["H0505","among a thousand",54,70],["H5046","to shew",72,79],["H0120","unto man",80,88],["H3476","his uprightness",89,104]]},"33:24":{"text":"Then he is gracious unto him, and saith, Deliver him from going down to the pit: I have found a ransom.","words":[["H2603","Then he is gracious",0,19],["H0559","unto him, and saith",20,39],["H6308","Deliver",41,48],["H3381","him from going down",49,68],["H7845","to the pit",69,79],["H4672","I have found",81,93],["H3724","a ransom",94,102]]},"33:25":{"text":"His flesh shall be fresher than a child's: he shall return to the days of his youth:","words":[["H1320","His flesh",0,9],["H7375","shall be fresher",10,26],["H5290","than a child's",27,41],["H7725","he shall return",43,58],["H3117","to the days",59,70],["H5934","of his youth",71,83]]},"33:26":{"text":"He shall pray unto God, and he will be favourable unto him: and he shall see his face with joy: for he will render unto man his righteousness.","words":[["H6279","He shall pray",0,13],["H0433","unto God",14,22],["H7521","and he will be favourable",24,49],["H7200","unto him: and he shall see",50,76],["H6440","his face",77,85],["H8643","with joy",86,94],["H7725","for he will render",96,114],["H0582","unto man",115,123],["H6666","his righteousness",124,141]]},"33:27":{"text":"He looketh upon men, and if any say, I have sinned, and perverted that which was right, and it profited me not;","words":[["H7789","He looketh",0,10],["H0582","upon men",11,19],["H0559","and if any say",21,35],["H2398","I have sinned",37,50],["H5753","and perverted",52,65],["H3477","that which was right",66,86],["H7737","and it profited",88,103]]},"33:28":{"text":"He will deliver his soul from going into the pit, and his life shall see the light.","words":[["H6299","He will deliver",0,15],["H5315","his soul",16,24],["H5674","from going",25,35],["H7845","into the pit",36,48],["H2416","and his life",50,62],["H7200","shall see",63,72],["H0216","the light",73,82]]},"33:29":{"text":"Lo, all these things worketh God oftentimes with man,","words":[["H6466","Lo, all these things worketh",0,28],["H0410","God",29,32],["H6471","oftentimes",33,43],["H7969","oftentimes",33,43],["H1397","with man",44,52]]},"33:30":{"text":"To bring back his soul from the pit, to be enlightened with the light of the living.","words":[["H7725","To bring back",0,13],["H5315","his soul",14,22],["H7845","from the pit",23,35],["H0215","to be enlightened",37,54],["H0216","with the light",55,69],["H2416","of the living",70,83]]},"33:31":{"text":"Mark well, O Job, hearken unto me: hold thy peace, and I will speak.","words":[["H7181","Mark well",0,9],["H0347","O Job",11,16],["H8085","hearken",18,25],["H2790","unto me: hold thy peace",26,49],["H1696","and I will speak",51,67]]},"33:32":{"text":"If thou hast any thing to say, answer me: speak, for I desire to justify thee.","words":[["H3426","If thou hast",0,12],["H4405","any thing to say",13,29],["H7725","answer",31,37],["H1696","me: speak",38,47],["H2654","for I desire",49,61],["H6663","to justify",62,72]]},"33:33":{"text":"If not, hearken unto me: hold thy peace, and I shall teach thee wisdom.","words":[["H8085","If not, hearken",0,15],["H2790","unto me: hold thy peace",16,39],["H0502","and I shall teach",41,58],["H2451","thee wisdom",59,70]]},"34:1":{"text":"Furthermore Elihu answered and said,","words":[["H0453","Furthermore Elihu",0,17],["H6030","answered",18,26],["H0559","and said",27,35]]},"34:2":{"text":"Hear my words, O ye wise men; and give ear unto me, ye that have knowledge.","words":[["H8085","Hear",0,4],["H4405","my words",5,13],["H2450","O ye wise",15,24],["H0238","men; and give ear",25,42],["H3045","unto me, ye that have knowledge",43,74]]},"34:3":{"text":"For the ear trieth words, as the mouth tasteth meat.","words":[["H0241","For the ear",0,11],["H0974","trieth",12,18],["H4405","words",19,24],["H2441","as the mouth",26,38],["H2938","tasteth",39,46],["H0398","meat",47,51]]},"34:4":{"text":"Let us choose to us judgment: let us know among ourselves what is good.","words":[["H0977","Let us choose",0,13],["H4941","to us judgment",14,28],["H3045","let us know",30,41],["H2896","among ourselves what is good",42,70]]},"34:5":{"text":"For Job hath said, I am righteous: and God hath taken away my judgment.","words":[["H0347","For Job",0,7],["H0559","hath said",8,17],["H6663","I am righteous",19,33],["H0410","and God",35,42],["H5493","hath taken away",43,58],["H4941","my judgment",59,70]]},"34:6":{"text":"Should I lie against my right? my wound is incurable without transgression.","words":[["H3576","Should I lie",0,12],["H4941","against my right",13,29],["H2671","my wound",31,39],["H0605","is incurable",40,52],["H6588","without transgression",53,74]]},"34:7":{"text":"What man is like Job, who drinketh up scorning like water?","words":[["H1397","What man",0,8],["H0347","is like Job",9,20],["H8354","who drinketh up",22,37],["H3933","scorning",38,46],["H4325","like water",47,57]]},"34:8":{"text":"Which goeth in company with the workers of iniquity, and walketh with wicked men.","words":[["H0732","Which goeth",0,11],["H2274","in company",12,22],["H6466","with the workers",23,39],["H0205","of iniquity",40,51],["H3212","and walketh",53,64],["H7562","with wicked",65,76],["H0582","men",77,80]]},"34:9":{"text":"For he hath said, It profiteth a man nothing that he should delight himself with God.","words":[["H0559","For he hath said",0,16],["H5532","It profiteth",18,30],["H1397","a man",31,36],["H7521","nothing that he should delight",37,67],["H0430","himself with God",68,84]]},"34:10":{"text":"Therefore hearken unto me, ye men of understanding: far be it from God, that he should do wickedness; and from the Almighty, that he should commit iniquity.","words":[["H8085","Therefore hearken",0,17],["H0582","unto me, ye men",18,33],["H3824","of understanding",34,50],["H2486","far be it",52,61],["H0410","from God",62,70],["H7562","that he should do wickedness",72,100],["H7706","and from the Almighty",102,123],["H5766","that he should commit iniquity",125,155]]},"34:11":{"text":"For the work of a man shall he render unto him, and cause every man to find according to his ways.","words":[["H6467","For the work",0,12],["H0120","of a man",13,21],["H7999","shall he render",22,37],["H0376","unto him, and cause every man",38,67],["H4672","to find",68,75],["H0734","according to his ways",76,97]]},"34:12":{"text":"Yea, surely God will not do wickedly, neither will the Almighty pervert judgment.","words":[["H0551","Yea, surely",0,11],["H0410","God",12,15],["H7561","will not do wickedly",16,36],["H7706","neither will the Almighty",38,63],["H5791","pervert",64,71],["H4941","judgment",72,80]]},"34:13":{"text":"Who hath given him a charge over the earth? or who hath disposed the whole world?","words":[["H6485","Who hath given him a charge",0,27],["H0776","over the earth",28,42],["H7760","or who hath disposed",44,64],["H8398","the whole world",65,80]]},"34:14":{"text":"If he set his heart upon man, if he gather unto himself his spirit and his breath;","words":[["H7760","If he set",0,9],["H3820","his heart",10,19],["H0622","upon man, if he gather",20,42],["H7307","unto himself his spirit",43,66],["H5397","and his breath",67,81]]},"34:15":{"text":"All flesh shall perish together, and man shall turn again unto dust.","words":[["H1320","All flesh",0,9],["H1478","shall perish",10,22],["H3162","together",23,31],["H0120","and man",33,40],["H7725","shall turn again",41,57],["H6083","unto dust",58,67]]},"34:16":{"text":"If now thou hast understanding, hear this: hearken to the voice of my words.","words":[["H0998","If now thou hast understanding",0,30],["H8085","hear",32,36],["H0238","this: hearken",37,50],["H6963","to the voice",51,63],["H4405","of my words",64,75]]},"34:17":{"text":"Shall even he that hateth right govern? and wilt thou condemn him that is most just?","words":[["H8130","Shall even he that hateth",0,25],["H4941","right",26,31],["H2280","govern",32,38],["H7561","and wilt thou condemn",40,61],["H3524","him that is most",62,78],["H6662","just",79,83]]},"34:18":{"text":"Is it fit to say to a king, Thou art wicked? and to princes, Ye are ungodly?","words":[["H0559","Is it fit to say",0,16],["H4428","to a king",17,26],["H1100","Thou art wicked",28,43],["H5081","and to princes",45,59],["H7563","Ye are ungodly",61,75]]},"34:19":{"text":"How much less to him that accepteth not the persons of princes, nor regardeth the rich more than the poor? for they all are the work of his hands.","words":[["H5375","How much less to him that accepteth",0,35],["H6440","not the persons",36,51],["H8269","of princes",52,62],["H5234","nor regardeth",64,77],["H7771","the rich",78,86],["H6440","more than",87,96],["H1800","the poor",97,105],["H4639","for they all are the work",107,132],["H3027","of his hands",133,145]]},"34:20":{"text":"In a moment shall they die, and the people shall be troubled at midnight, and pass away: and the mighty shall be taken away without hand.","words":[["H7281","In a moment",0,11],["H4191","shall they die",12,26],["H5971","and the people",28,42],["H1607","shall be troubled",43,60],["H2676","at midnight",61,72],["H3915","at midnight",61,72],["H5674","and pass away",74,87],["H0047","and the mighty",89,103],["H5493","shall be taken away",104,123],["H3027","without hand",124,136]]},"34:21":{"text":"For his eyes are upon the ways of man, and he seeth all his goings.","words":[["H5869","For his eyes",0,12],["H1870","are upon the ways",13,30],["H0376","of man",31,37],["H7200","and he seeth",39,51],["H6806","all his goings",52,66]]},"34:22":{"text":"There is no darkness, nor shadow of death, where the workers of iniquity may hide themselves.","words":[["H2822","There is no darkness",0,20],["H6757","nor shadow of death",22,41],["H6466","where the workers",43,60],["H0205","of iniquity",61,72],["H5641","may hide",73,81]]},"34:23":{"text":"For he will not lay upon man more than right; that he should enter into judgment with God.","words":[["H7760","For he will not lay",0,19],["H0376","upon man",20,28],["H1980","more than right; that he should enter",29,66],["H4941","into judgment",67,80],["H0410","with God",81,89]]},"34:24":{"text":"He shall break in pieces mighty men without number, and set others in their stead.","words":[["H7489","He shall break in pieces",0,24],["H3524","mighty men",25,35],["H2714","without number",36,50],["H5975","and set",52,59],["H0312","others",60,66]]},"34:25":{"text":"Therefore he knoweth their works, and he overturneth them in the night, so that they are destroyed.","words":[["H5234","Therefore he knoweth",0,20],["H4566","their works",21,32],["H2015","and he overturneth",34,52],["H3915","them in the night",53,70],["H1792","so that they are destroyed",72,98]]},"34:26":{"text":"He striketh them as wicked men in the open sight of others;","words":[["H5606","He striketh",0,11],["H8478","them as",12,19],["H7563","wicked men",20,30],["H4725","in the open",31,42],["H7200","sight",43,48]]},"34:27":{"text":"Because they turned back from him, and would not consider any of his ways:","words":[["H5493","Because they turned back",0,24],["H0310","from him",25,33],["H7919","and would not consider",35,57],["H1870","any of his ways",58,73]]},"34:28":{"text":"So that they cause the cry of the poor to come unto him, and he heareth the cry of the afflicted.","words":[["H6818","So that they cause the cry",0,26],["H1800","of the poor",27,38],["H0935","to come",39,46],["H8085","unto him, and he heareth",47,71],["H6818","the cry",72,79],["H6041","of the afflicted",80,96]]},"34:29":{"text":"When he giveth quietness, who then can make trouble? and when he hideth his face, who then can behold him? whether it be done against a nation, or against a man only:","words":[["H8252","When he giveth quietness",0,24],["H7561","who then can make trouble",26,51],["H5641","and when he hideth",53,71],["H6440","his face",72,80],["H7789","who then can behold",82,101],["H1471","him? whether it be done against a nation",102,142],["H0120","or against a man",144,160],["H3162","only",161,165]]},"34:30":{"text":"That the hypocrite reign not, lest the people be ensnared.","words":[["H0120","That the hypocrite",0,18],["H2611","That the hypocrite",0,18],["H4427","reign",19,24],["H5971","not, lest the people",25,45],["H4170","be ensnared",46,57]]},"34:31":{"text":"Surely it is meet to be said unto God, I have borne chastisement, I will not offend any more:","words":[["H0559","Surely it is meet to be said",0,28],["H0410","unto God",29,37],["H5375","I have borne",39,51],["H2254","chastisement, I will not offend",52,83]]},"34:32":{"text":"That which I see not teach thou me: if I have done iniquity, I will do no more.","words":[["H2372","That which I see",0,16],["H1107","not",17,20],["H3384","teach",21,26],["H6466","thou me: if I have done",27,50],["H5766","iniquity",51,59],["H3254","I will do",61,70]]},"34:33":{"text":"Should it be according to thy mind? he will recompense it, whether thou refuse, or whether thou choose; and not I: therefore speak what thou knowest.","words":[["H7999","Should it be according to thy mind? he will recompense",0,54],["H3588","it, whether thou refuse",55,78],["H3988","it, whether thou refuse",55,78],["H0977","or whether thou choose",80,102],["H1696","and not I: therefore speak",104,130],["H3045","what thou knowest",131,148]]},"34:34":{"text":"Let men of understanding tell me, and let a wise man hearken unto me.","words":[["H0582","Let men",0,7],["H3824","of understanding",8,24],["H0559","tell",25,29],["H2450","me, and let a wise",30,48],["H1397","man",49,52],["H8085","hearken",53,60]]},"34:35":{"text":"Job hath spoken without knowledge, and his words were without wisdom.","words":[["H0347","Job",0,3],["H1696","hath spoken",4,15],["H1847","without knowledge",16,33],["H1697","and his words",35,48],["H7919","were without wisdom",49,68]]},"34:36":{"text":"My desire is that Job may be tried unto the end because of his answers for wicked men.","words":[["H0015","My desire",0,9],["H0001","My desire",0,9],["H0347","is that Job",10,21],["H0974","may be tried",22,34],["H5331","unto the end",35,47],["H8666","because of his answers",48,70],["H0205","for wicked",71,81],["H0582","men",82,85]]},"34:37":{"text":"For he addeth rebellion unto his sin, he clappeth his hands among us, and multiplieth his words against God.","words":[["H3254","For he addeth",0,13],["H6588","rebellion",14,23],["H2403","unto his sin",24,36],["H5606","he clappeth",38,49],["H7235","his hands among us, and multiplieth",50,85],["H0561","his words",86,95],["H0410","against God",96,107]]},"35:1":{"text":"Elihu spake moreover, and said,","words":[["H0453","Elihu",0,5],["H6030","spake",6,11],["H0559","moreover, and said",12,30]]},"35:2":{"text":"Thinkest thou this to be right, that thou saidst, My righteousness is more than God's?","words":[["H2803","Thinkest",0,8],["H4941","thou this to be right",9,30],["H0559","that thou saidst",32,48],["H6664","My righteousness",50,66],["H0410","is more than God's",67,85]]},"35:3":{"text":"For thou saidst, What advantage will it be unto thee? and, What profit shall I have, if I be cleansed from my sin?","words":[["H0559","For thou saidst",0,15],["H5532","What advantage",17,31],["H3276","will it be unto thee? and, What profit",32,70],["H2403","shall I have, if I be cleansed from my sin",71,113]]},"35:4":{"text":"I will answer thee, and thy companions with thee.","words":[["H7725","I will answer",0,13],["H4405","I will answer",0,13],["H7453","thee, and thy companions",14,38]]},"35:5":{"text":"Look unto the heavens, and see; and behold the clouds which are higher than thou.","words":[["H5027","Look",0,4],["H8064","unto the heavens",5,21],["H7200","and see",23,30],["H7789","and behold",32,42],["H7834","the clouds",43,53],["H1361","which are higher",54,70]]},"35:6":{"text":"If thou sinnest, what doest thou against him? or if thy transgressions be multiplied, what doest thou unto him?","words":[["H2398","If thou sinnest",0,15],["H6466","what doest",17,27],["H6588","thou against him? or if thy transgressions",28,70],["H7231","be multiplied",71,84],["H6213","what doest",86,96]]},"35:7":{"text":"If thou be righteous, what givest thou him? or what receiveth he of thine hand?","words":[["H6663","If thou be righteous",0,20],["H5414","what givest",22,33],["H3947","thou him? or what receiveth",34,61],["H3027","he of thine hand",62,78]]},"35:8":{"text":"Thy wickedness may hurt a man as thou art; and thy righteousness may profit the son of man.","words":[["H7562","Thy wickedness",0,14],["H0376","may hurt a man",15,29],["H6666","as thou art; and thy righteousness",30,64],["H1121","may profit the son",65,83],["H0120","of man",84,90]]},"35:9":{"text":"By reason of the multitude of oppressions they make the oppressed to cry: they cry out by reason of the arm of the mighty.","words":[["H7230","By reason of the multitude",0,26],["H6217","of oppressions",27,41],["H2199","they make the oppressed to cry",42,72],["H7768","they cry out",74,86],["H2220","by reason of the arm",87,107],["H7227","of the mighty",108,121]]},"35:10":{"text":"But none saith, Where is God my maker, who giveth songs in the night;","words":[["H0559","But none saith",0,14],["H0433","Where is God",16,28],["H6213","my maker",29,37],["H5414","who giveth",39,49],["H2158","songs",50,55],["H3915","in the night",56,68]]},"35:11":{"text":"Who teacheth us more than the beasts of the earth, and maketh us wiser than the fowls of heaven?","words":[["H0502","Who teacheth",0,12],["H0929","us more than the beasts",13,36],["H0776","of the earth",37,49],["H2449","and maketh us wiser",51,70],["H5775","than the fowls",71,85],["H8064","of heaven",86,95]]},"35:12":{"text":"There they cry, but none giveth answer, because of the pride of evil men.","words":[["H6817","There they cry",0,14],["H6030","but none giveth answer",16,38],["H6440","because",40,47],["H1347","of the pride",48,60],["H7451","of evil men",61,72]]},"35:13":{"text":"Surely God will not hear vanity, neither will the Almighty regard it.","words":[["H0410","Surely God",0,10],["H8085","will not hear",11,24],["H7723","vanity",25,31],["H7706","neither will the Almighty",33,58],["H7789","regard",59,65]]},"35:14":{"text":"Although thou sayest thou shalt not see him, yet judgment is before him; therefore trust thou in him.","words":[["H0637","Although",0,8],["H0559","thou sayest",9,20],["H7789","thou shalt not see",21,39],["H1779","him, yet judgment",40,57],["H6440","is before",58,67],["H2342","him; therefore trust",68,88]]},"35:15":{"text":"But now, because it is not so, he hath visited in his anger; yet he knoweth it not in great extremity:","words":[["H6485","But now, because it is not so, he hath visited",0,46],["H0639","in his anger",47,59],["H3045","yet he knoweth",61,75],["H3966","it not in great",76,91],["H6580","extremity",92,101]]},"35:16":{"text":"Therefore doth Job open his mouth in vain; he multiplieth words without knowledge.","words":[["H0347","Therefore doth Job",0,18],["H6475","open",19,23],["H6310","his mouth",24,33],["H1892","in vain",34,41],["H3527","he multiplieth",43,57],["H4405","words",58,63],["H1097","without",64,71],["H1847","knowledge",72,81]]},"36:1":{"text":"Elihu also proceeded, and said,","words":[["H0453","Elihu",0,5],["H3254","also proceeded",6,20],["H0559","and said",22,30]]},"36:2":{"text":"Suffer me a little, and I will shew thee that I have yet to speak on God's behalf.","words":[["H3803","Suffer",0,6],["H2191","me a little",7,18],["H2331","and I will shew",20,35],["H4405","thee that I have yet to speak",36,65],["H0433","on God's",66,74]]},"36:3":{"text":"I will fetch my knowledge from afar, and will ascribe righteousness to my Maker.","words":[["H5375","I will fetch",0,12],["H1843","my knowledge",13,25],["H7350","from afar",26,35],["H5414","and will ascribe",37,53],["H6664","righteousness",54,67],["H6466","to my Maker",68,79]]},"36:4":{"text":"For truly my words shall not be false: he that is perfect in knowledge is with thee.","words":[["H0551","For truly",0,9],["H4405","my words",10,18],["H8267","shall not be false",19,37],["H8549","he that is perfect",39,57],["H1844","in knowledge",58,70]]},"36:5":{"text":"Behold, God is mighty, and despiseth not any: he is mighty in strength and wisdom.","words":[["H0410","Behold, God",0,11],["H3524","is mighty",12,21],["H3988","and despiseth",23,36],["H3524","not any: he is mighty",37,58],["H3581","in strength",59,70],["H3820","and wisdom",71,81]]},"36:6":{"text":"He preserveth not the life of the wicked: but giveth right to the poor.","words":[["H2421","He preserveth not the life",0,26],["H7563","of the wicked",27,40],["H5414","but giveth",42,52],["H4941","right",53,58],["H6041","to the poor",59,70]]},"36:7":{"text":"He withdraweth not his eyes from the righteous: but with kings are they on the throne; yea, he doth establish them for ever, and they are exalted.","words":[["H1639","He withdraweth",0,14],["H5869","not his eyes",15,27],["H6662","from the righteous",28,46],["H4428","but with kings",48,62],["H3678","are they on the throne",63,85],["H3427","yea, he doth establish",87,109],["H5331","them for ever",110,123],["H1361","and they are exalted",125,145]]},"36:8":{"text":"And if they be bound in fetters, and be holden in cords of affliction;","words":[["H0631","And if they be bound",0,20],["H2131","in fetters",21,31],["H3920","and be holden",33,46],["H2256","in cords",47,55],["H6040","of affliction",56,69]]},"36:9":{"text":"Then he sheweth them their work, and their transgressions that they have exceeded.","words":[["H5046","Then he sheweth",0,15],["H6467","them their work",16,31],["H6588","and their transgressions",33,57],["H1396","that they have exceeded",58,81]]},"36:10":{"text":"He openeth also their ear to discipline, and commandeth that they return from iniquity.","words":[["H1540","He openeth",0,10],["H0241","also their ear",11,25],["H4148","to discipline",26,39],["H0559","and commandeth",41,55],["H7725","that they return",56,72],["H0205","from iniquity",73,86]]},"36:11":{"text":"If they obey and serve him, they shall spend their days in prosperity, and their years in pleasures.","words":[["H8085","If they obey",0,12],["H5647","and serve",13,22],["H3615","him, they shall spend",23,44],["H3117","their days",45,55],["H2896","in prosperity",56,69],["H8141","and their years",71,86],["H5273","in pleasures",87,99]]},"36:12":{"text":"But if they obey not, they shall perish by the sword, and they shall die without knowledge.","words":[["H8085","But if they obey",0,16],["H5674","not, they shall perish",17,39],["H7973","by the sword",40,52],["H1478","and they shall die",54,72],["H1847","without knowledge",73,90]]},"36:13":{"text":"But the hypocrites in heart heap up wrath: they cry not when he bindeth them.","words":[["H2611","But the hypocrites",0,18],["H3820","in heart",19,27],["H7760","heap up",28,35],["H0639","wrath",36,41],["H7768","they cry",43,51],["H0631","not when he bindeth",52,71]]},"36:14":{"text":"They die in youth, and their life is among the unclean.","words":[["H5315","They",0,4],["H4191","die",5,8],["H5290","in youth",9,17],["H2416","and their life",19,33],["H6945","is among the unclean",34,54]]},"36:15":{"text":"He delivereth the poor in his affliction, and openeth their ears in oppression.","words":[["H2502","He delivereth",0,13],["H6041","the poor",14,22],["H6040","in his affliction",23,40],["H1540","and openeth",42,53],["H0241","their ears",54,64],["H3906","in oppression",65,78]]},"36:16":{"text":"Even so would he have removed thee out of the strait into a broad place, where there is no straitness; and that which should be set on thy table should be full of fatness.","words":[["H5496","Even so would he have removed",0,29],["H6310","thee out of the strait",30,52],["H6862","thee out of the strait",30,52],["H7338","into a broad place",53,71],["H8478","where",73,78],["H4164","there is no straitness",79,101],["H5183","and that which should be set",103,131],["H7979","on thy table",132,144],["H4390","should be full",145,159],["H1880","of fatness",160,170]]},"36:17":{"text":"But thou hast fulfilled the judgment of the wicked: judgment and justice take hold on thee.","words":[["H4390","But thou hast fulfilled",0,23],["H1779","the judgment",24,36],["H7563","of the wicked",37,50],["H1779","judgment",52,60],["H4941","and justice",61,72],["H8551","take hold",73,82]]},"36:18":{"text":"Because there is wrath, beware lest he take thee away with his stroke: then a great ransom cannot deliver thee.","words":[["H2534","Because there is wrath",0,22],["H5496","beware lest he take thee away",24,53],["H5607","with his stroke",54,69],["H7230","then a great",71,83],["H3724","ransom",84,90],["H5186","cannot deliver",91,105]]},"36:19":{"text":"Will he esteem thy riches? no, not gold, nor all the forces of strength.","words":[["H6186","Will he esteem",0,14],["H7769","thy riches",15,25],["H1222","no, not gold",27,39],["H3981","nor all the forces",41,59],["H3581","of strength",60,71]]},"36:20":{"text":"Desire not the night, when people are cut off in their place.","words":[["H7602","Desire",0,6],["H3915","not the night",7,20],["H5971","when people",22,33],["H5927","are cut off",34,45]]},"36:21":{"text":"Take heed, regard not iniquity: for this hast thou chosen rather than affliction.","words":[["H8104","Take heed",0,9],["H6437","regard",11,17],["H0205","not iniquity",18,30],["H0977","for this hast thou chosen",32,57],["H6040","rather than affliction",58,80]]},"36:22":{"text":"Behold, God exalteth by his power: who teacheth like him?","words":[["H0410","Behold, God",0,11],["H7682","exalteth",12,20],["H3581","by his power",21,33],["H3384","who teacheth",35,47]]},"36:23":{"text":"Who hath enjoined him his way? or who can say, Thou hast wrought iniquity?","words":[["H6485","Who hath enjoined",0,17],["H1870","him his way",18,29],["H0559","or who can say",31,45],["H6466","Thou hast wrought",47,64],["H5766","iniquity",65,73]]},"36:24":{"text":"Remember that thou magnify his work, which men behold.","words":[["H2142","Remember",0,8],["H7679","that thou magnify",9,26],["H6467","his work",27,35],["H0582","which men",37,46],["H7891","behold",47,53]]},"36:25":{"text":"Every man may see it; man may behold it afar off.","words":[["H0120","Every man",0,9],["H2372","may see",10,17],["H0582","it; man",18,25],["H5027","may behold",26,36],["H7350","it afar off",37,48]]},"36:26":{"text":"Behold, God is great, and we know him not, neither can the number of his years be searched out.","words":[["H0410","Behold, God",0,11],["H7689","is great",12,20],["H3045","and we know",22,33],["H4557","him not, neither can the number",34,65],["H8141","of his years",66,78],["H2714","be searched out",79,94]]},"36:27":{"text":"For he maketh small the drops of water: they pour down rain according to the vapour thereof:","words":[["H1639","For he maketh small",0,19],["H5198","the drops",20,29],["H4325","of water",30,38],["H2212","they pour down",40,54],["H4306","rain",55,59],["H0108","according to the vapour",60,83]]},"36:28":{"text":"Which the clouds do drop and distil upon man abundantly.","words":[["H7834","Which the clouds",0,16],["H5140","do drop",17,24],["H7491","and distil",25,35],["H0120","upon man",36,44],["H7227","abundantly",45,55]]},"36:29":{"text":"Also can any understand the spreadings of the clouds, or the noise of his tabernacle?","words":[["H0995","Also can any understand",0,23],["H4666","the spreadings",24,38],["H5645","of the clouds",39,52],["H8663","or the noise",54,66],["H5521","of his tabernacle",67,84]]},"36:30":{"text":"Behold, he spreadeth his light upon it, and covereth the bottom of the sea.","words":[["H6566","Behold, he spreadeth",0,20],["H0216","his light",21,30],["H3680","upon it, and covereth",31,52],["H8328","the bottom",53,63],["H3220","of the sea",64,74]]},"36:31":{"text":"For by them judgeth he the people; he giveth meat in abundance.","words":[["H1777","For by them judgeth",0,19],["H5971","he the people",20,33],["H5414","he giveth",35,44],["H0400","meat",45,49],["H4342","in abundance",50,62]]},"36:32":{"text":"With clouds he covereth the light; and commandeth it not to shine by the cloud that cometh betwixt.","words":[["H3709","With clouds",0,11],["H3680","he covereth",12,23],["H0216","the light",24,33],["H6680","and commandeth",35,49],["H6293","it not to shine by the cloud that cometh betwixt",50,98]]},"36:33":{"text":"The noise thereof sheweth concerning it, the cattle also concerning the vapour.","words":[["H7452","The noise",0,9],["H5046","thereof sheweth",10,25],["H4735","concerning it, the cattle",26,51],["H5927","also concerning the vapour",52,78]]},"37:1":{"text":"At this also my heart trembleth, and is moved out of his place.","words":[["H2063","At this",0,7],["H3820","also my heart",8,21],["H2729","trembleth",22,31],["H5425","and is moved out",33,49],["H4725","of his place",50,62]]},"37:2":{"text":"Hear attentively the noise of his voice, and the sound that goeth out of his mouth.","words":[["H8085","Hear",0,4],["H8085","attentively",5,16],["H7267","the noise",17,26],["H6963","of his voice",27,39],["H1899","and the sound",41,54],["H3318","that goeth out",55,69],["H6310","of his mouth",70,82]]},"37:3":{"text":"He directeth it under the whole heaven, and his lightning unto the ends of the earth.","words":[["H3474","He directeth",0,12],["H8281","it",13,15],["H8064","under the whole heaven",16,38],["H0216","and his lightning",40,57],["H3671","unto the ends",58,71],["H0776","of the earth",72,84]]},"37:4":{"text":"After it a voice roareth: he thundereth with the voice of his excellency; and he will not stay them when his voice is heard.","words":[["H0310","After",0,5],["H6963","it a voice",6,16],["H7580","roareth",17,24],["H7481","he thundereth",26,39],["H6963","with the voice",40,54],["H1347","of his excellency",55,72],["H6117","and he will not stay",74,94],["H6963","them when his voice",95,114],["H8085","is heard",115,123]]},"37:5":{"text":"God thundereth marvellously with his voice; great things doeth he, which we cannot comprehend.","words":[["H0410","God",0,3],["H7481","thundereth",4,14],["H6381","marvellously",15,27],["H6963","with his voice",28,42],["H1419","great things",44,56],["H6213","doeth",57,62],["H3045","he, which we cannot comprehend",63,93]]},"37:6":{"text":"For he saith to the snow, Be thou on the earth; likewise to the small rain, and to the great rain of his strength.","words":[["H0559","For he saith",0,12],["H7950","to the snow",13,24],["H1933","Be thou",26,33],["H0776","on the earth",34,46],["H4306","likewise to the small",48,69],["H1653","rain",70,74],["H4306","and to the great",76,92],["H1653","rain",93,97],["H5797","of his strength",98,113]]},"37:7":{"text":"He sealeth up the hand of every man; that all men may know his work.","words":[["H2856","He sealeth up",0,13],["H3027","the hand",14,22],["H0120","of every man",23,35],["H0582","that all men",37,49],["H3045","may know",50,58],["H4639","his work",59,67]]},"37:8":{"text":"Then the beasts go into dens, and remain in their places.","words":[["H2416","Then the beasts",0,15],["H0935","go",16,18],["H1119","into",19,23],["H0695","dens",24,28],["H7931","and remain",30,40],["H4585","in their places",41,56]]},"37:9":{"text":"Out of the south cometh the whirlwind: and cold out of the north.","words":[["H2315","Out of the south",0,16],["H0935","cometh",17,23],["H5492","the whirlwind",24,37],["H7135","and cold",39,47],["H4215","out of the north",48,64]]},"37:10":{"text":"By the breath of God frost is given: and the breadth of the waters is straitened.","words":[["H5397","By the breath",0,13],["H0410","of God",14,20],["H7140","frost",21,26],["H5414","is given",27,35],["H7341","and the breadth",37,52],["H4325","of the waters",53,66],["H4164","is straitened",67,80]]},"37:11":{"text":"Also by watering he wearieth the thick cloud: he scattereth his bright cloud:","words":[["H7377","Also by watering",0,16],["H2959","he wearieth",17,28],["H5645","the thick cloud",29,44],["H6327","he scattereth",46,59],["H0216","his bright",60,70],["H6051","cloud",71,76]]},"37:12":{"text":"And it is turned round about by his counsels: that they may do whatsoever he commandeth them upon the face of the world in the earth.","words":[["H2015","And it is turned",0,16],["H4524","round about",17,28],["H8458","by his counsels",29,44],["H6467","that they may do",46,62],["H6680","whatsoever he commandeth",63,87],["H6440","them upon the face",88,106],["H8398","of the world",107,119],["H0776","in the earth",120,132]]},"37:13":{"text":"He causeth it to come, whether for correction, or for his land, or for mercy.","words":[["H4672","He causeth it to come",0,21],["H7626","whether for correction",23,45],["H0776","or for his land",47,62],["H2617","or for mercy",64,76]]},"37:14":{"text":"Hearken unto this, O Job: stand still, and consider the wondrous works of God.","words":[["H0238","Hearken",0,7],["H0347","unto this, O Job",8,24],["H5975","stand still",26,37],["H0995","and consider",39,51],["H6381","the wondrous",52,64],["H0410","works of God",65,77]]},"37:15":{"text":"Dost thou know when God disposed them, and caused the light of his cloud to shine?","words":[["H3045","Dost thou know",0,14],["H0433","when God",15,23],["H7760","disposed",24,32],["H0216","them, and caused the light",33,59],["H6051","of his cloud",60,72],["H3313","to shine",73,81]]},"37:16":{"text":"Dost thou know the balancings of the clouds, the wondrous works of him which is perfect in knowledge?","words":[["H3045","Dost thou know",0,14],["H4657","the balancings",15,29],["H5645","of the clouds",30,43],["H4652","the wondrous works",45,63],["H8549","of him which is perfect",64,87],["H1843","in knowledge",88,100]]},"37:17":{"text":"How thy garments are warm, when he quieteth the earth by the south wind?","words":[["H0899","How thy garments",0,16],["H2525","are warm",17,25],["H8252","when he quieteth",27,43],["H0776","the earth",44,53],["H1864","by the south",54,66]]},"37:18":{"text":"Hast thou with him spread out the sky, which is strong, and as a molten looking glass?","words":[["H7554","Hast thou with him spread out",0,29],["H7834","the sky",30,37],["H2389","which is strong",39,54],["H3332","and as a molten",56,71],["H7209","looking glass",72,85]]},"37:19":{"text":"Teach us what we shall say unto him; for we cannot order our speech by reason of darkness.","words":[["H3045","Teach",0,5],["H0559","us what we shall say",6,26],["H6186","unto him; for we cannot order",27,56],["H6440","our speech by reason",57,77],["H2822","of darkness",78,89]]},"37:20":{"text":"Shall it be told him that I speak? if a man speak, surely he shall be swallowed up.","words":[["H5608","Shall it be told",0,16],["H1696","him that I speak",17,33],["H0376","if a man",35,43],["H0559","speak",44,49],["H1104","surely he shall be swallowed up",51,82]]},"37:21":{"text":"And now men see not the bright light which is in the clouds: but the wind passeth, and cleanseth them.","words":[["H7200","And now men see",0,15],["H0925","not the bright",16,30],["H0216","light",31,36],["H7834","which is in the clouds",37,59],["H7307","but the wind",61,73],["H5674","passeth",74,81],["H2891","and cleanseth",83,96]]},"37:22":{"text":"Fair weather cometh out of the north: with God is terrible majesty.","words":[["H2091","Fair weather",0,12],["H0857","cometh",13,19],["H6828","out of the north",20,36],["H0433","with God",38,46],["H3372","is terrible",47,58],["H1935","majesty",59,66]]},"37:23":{"text":"Touching the Almighty, we cannot find him out: he is excellent in power, and in judgment, and in plenty of justice: he will not afflict.","words":[["H7706","Touching the Almighty",0,21],["H4672","we cannot find him out",23,45],["H7689","he is excellent",47,62],["H3581","in power",63,71],["H4941","and in judgment",73,88],["H7230","and in plenty",90,103],["H6666","of justice",104,114],["H6031","he will not afflict",116,135]]},"37:24":{"text":"Men do therefore fear him: he respecteth not any that are wise of heart.","words":[["H0582","Men",0,3],["H3372","do therefore fear",4,21],["H7200","him: he respecteth",22,40],["H2450","not any that are wise",41,62],["H3820","of heart",63,71]]},"38:1":{"text":"Then the LORD answered Job out of the whirlwind, and said,","words":[["H3068","Then the LORD",0,13],["H6030","answered",14,22],["H0347","Job",23,26],["H5591","out of the whirlwind",27,47],["H0559","and said",49,57]]},"38:2":{"text":"Who is this that darkeneth counsel by words without knowledge?","words":[["H2821","Who is this that darkeneth",0,26],["H6098","counsel",27,34],["H4405","by words",35,43],["H1847","without knowledge",44,61]]},"38:3":{"text":"Gird up now thy loins like a man; for I will demand of thee, and answer thou me.","words":[["H0247","Gird up",0,7],["H2504","now thy loins",8,21],["H1397","like a man",22,32],["H7592","for I will demand",34,51],["H3045","of thee, and answer",52,71]]},"38:4":{"text":"Where wast thou when I laid the foundations of the earth? declare, if thou hast understanding.","words":[["H0375","Where",0,5],["H3245","wast thou when I laid the foundations",6,43],["H0776","of the earth",44,56],["H5046","declare",58,65],["H3045","if thou hast",67,79],["H0998","understanding",80,93]]},"38:5":{"text":"Who hath laid the measures thereof, if thou knowest? or who hath stretched the line upon it?","words":[["H7760","Who hath laid",0,13],["H4461","the measures",14,26],["H3045","thereof, if thou knowest",27,51],["H5186","or who hath stretched",53,74],["H6957","the line",75,83]]},"38:6":{"text":"Whereupon are the foundations thereof fastened? or who laid the corner stone thereof;","words":[["H0134","Whereupon are the foundations",0,29],["H2883","thereof fastened",30,46],["H3384","or who laid",48,59],["H6438","the corner",60,70],["H0068","stone",71,76]]},"38:7":{"text":"When the morning stars sang together, and all the sons of God shouted for joy?","words":[["H1242","When the morning",0,16],["H3556","stars",17,22],["H7442","sang",23,27],["H3162","together",28,36],["H1121","and all the sons",38,54],["H0430","of God",55,61],["H7321","shouted",62,69]]},"38:8":{"text":"Or who shut up the sea with doors, when it brake forth, as if it had issued out of the womb?","words":[["H5526","Or who shut up",0,14],["H3220","the sea",15,22],["H1817","with doors",23,33],["H1518","when it brake forth",35,54],["H3318","as if it had issued out",56,79],["H7358","of the womb",80,91]]},"38:9":{"text":"When I made the cloud the garment thereof, and thick darkness a swaddlingband for it,","words":[["H7760","When I made",0,11],["H6051","the cloud",12,21],["H3830","the garment",22,33],["H6205","thereof, and thick darkness",34,61],["H2854","a swaddlingband",62,77]]},"38:10":{"text":"And brake up for it my decreed place, and set bars and doors,","words":[["H7665","And brake up",0,12],["H2706","for it my decreed",13,30],["H7760","place, and set",31,45],["H1280","bars",46,50],["H1817","and doors",51,60]]},"38:11":{"text":"And said, Hitherto shalt thou come, but no further: and here shall thy proud waves be stayed?","words":[["H0559","And said",0,8],["H5704","Hitherto",10,18],["H6311","Hitherto",10,18],["H0935","shalt thou come",19,34],["H3254","but no further",36,50],["H1347","and here shall thy proud",52,76],["H1530","waves",77,82],["H7896","be stayed",83,92]]},"38:12":{"text":"Hast thou commanded the morning since thy days; and caused the dayspring to know his place;","words":[["H6680","Hast thou commanded",0,19],["H1242","the morning",20,31],["H3117","since thy days",32,46],["H7837","and caused the dayspring",48,72],["H3045","to know",73,80],["H4725","his place",81,90]]},"38:13":{"text":"That it might take hold of the ends of the earth, that the wicked might be shaken out of it?","words":[["H0270","That it might take hold",0,23],["H3671","of the ends",24,35],["H0776","of the earth",36,48],["H7563","that the wicked",50,65],["H5287","might be shaken out",66,85]]},"38:14":{"text":"It is turned as clay to the seal; and they stand as a garment.","words":[["H2015","It is turned",0,12],["H2563","as clay",13,20],["H2368","to the seal",21,32],["H3320","and they stand",34,48],["H3830","as a garment",49,61]]},"38:15":{"text":"And from the wicked their light is withholden, and the high arm shall be broken.","words":[["H7563","And from the wicked",0,19],["H0216","their light",20,31],["H4513","is withholden",32,45],["H7311","and the high",47,59],["H2220","arm",60,63],["H7665","shall be broken",64,79]]},"38:16":{"text":"Hast thou entered into the springs of the sea? or hast thou walked in the search of the depth?","words":[["H0935","Hast thou entered",0,17],["H5033","into the springs",18,34],["H3220","of the sea",35,45],["H1980","or hast thou walked",47,66],["H2714","in the search",67,80],["H8415","of the depth",81,93]]},"38:17":{"text":"Have the gates of death been opened unto thee? or hast thou seen the doors of the shadow of death?","words":[["H8179","Have the gates",0,14],["H4194","of death",15,23],["H1540","been opened",24,35],["H7200","unto thee? or hast thou seen",36,64],["H8179","the doors",65,74],["H6757","of the shadow of death",75,97]]},"38:18":{"text":"Hast thou perceived the breadth of the earth? declare if thou knowest it all.","words":[["H0995","Hast thou perceived",0,19],["H7338","the breadth",20,31],["H0776","of the earth",32,44],["H5046","declare",46,53],["H3045","if thou knowest",54,69]]},"38:19":{"text":"Where is the way where light dwelleth? and as for darkness, where is the place thereof,","words":[["H1870","Where is the way",0,16],["H0216","where light",17,28],["H7931","dwelleth",29,37],["H2822","and as for darkness",39,58],["H4725","where is the place",60,78]]},"38:20":{"text":"That thou shouldest take it to the bound thereof, and that thou shouldest know the paths to the house thereof?","words":[["H3947","That thou shouldest take",0,24],["H1366","it to the bound",25,40],["H0995","thereof, and that thou shouldest know",41,78],["H5410","the paths",79,88],["H1004","to the house",89,101]]},"38:21":{"text":"Knowest thou it, because thou wast then born? or because the number of thy days is great?","words":[["H3045","Knowest",0,7],["H3205","thou it, because thou wast then born",8,44],["H4557","or because the number",46,67],["H3117","of thy days",68,79],["H7227","is great",80,88]]},"38:22":{"text":"Hast thou entered into the treasures of the snow? or hast thou seen the treasures of the hail,","words":[["H0935","Hast thou entered",0,17],["H0214","into the treasures",18,36],["H7950","of the snow",37,48],["H7200","or hast thou seen",50,67],["H0214","the treasures",68,81],["H1259","of the hail",82,93]]},"38:23":{"text":"Which I have reserved against the time of trouble, against the day of battle and war?","words":[["H2820","Which I have reserved",0,21],["H6256","against the time",22,38],["H6862","of trouble",39,49],["H3117","against the day",51,66],["H7128","of battle",67,76],["H4421","and war",77,84]]},"38:24":{"text":"By what way is the light parted, which scattereth the east wind upon the earth?","words":[["H0335","By what",0,7],["H1870","way",8,11],["H0216","is the light",12,24],["H2505","parted",25,31],["H6327","which scattereth",33,49],["H6921","the east wind",50,63],["H0776","upon the earth",64,78]]},"38:25":{"text":"Who hath divided a watercourse for the overflowing of waters, or a way for the lightning of thunder;","words":[["H6385","Who hath divided",0,16],["H8585","a watercourse",17,30],["H7858","for the overflowing of waters",31,60],["H1870","or a way",62,70],["H2385","for the lightning",71,88],["H6963","of thunder",89,99]]},"38:26":{"text":"To cause it to rain on the earth, where no man is; on the wilderness, wherein there is no man;","words":[["H4305","To cause it to rain",0,19],["H0776","on the earth",20,32],["H0376","where no man",34,46],["H4057","is; on the wilderness",47,68],["H0120","wherein there is no man",70,93]]},"38:27":{"text":"To satisfy the desolate and waste ground; and to cause the bud of the tender herb to spring forth?","words":[["H7646","To satisfy",0,10],["H7722","the desolate",11,23],["H4875","and waste",24,33],["H4161","ground; and to cause the bud",34,62],["H1877","of the tender herb",63,81],["H6779","to spring forth",82,97]]},"38:28":{"text":"Hath the rain a father? or who hath begotten the drops of dew?","words":[["H3426","Hath",0,4],["H4306","the rain",5,13],["H0001","a father",14,22],["H3205","or who hath begotten",24,44],["H0096","the drops",45,54],["H2919","of dew",55,61]]},"38:29":{"text":"Out of whose womb came the ice? and the hoary frost of heaven, who hath gendered it?","words":[["H0990","Out of whose womb",0,17],["H3318","came",18,22],["H7140","the ice",23,30],["H3713","and the hoary frost",32,51],["H8064","of heaven",52,61],["H3205","who hath gendered",63,80]]},"38:30":{"text":"The waters are hid as with a stone, and the face of the deep is frozen.","words":[["H4325","The waters",0,10],["H2244","are hid",11,18],["H0068","as with a stone",19,34],["H6440","and the face",36,48],["H8415","of the deep",49,60],["H3920","is frozen",61,70]]},"38:31":{"text":"Canst thou bind the sweet influences of Pleiades, or loose the bands of Orion?","words":[["H7194","Canst thou bind",0,15],["H4575","the sweet influences",16,36],["H3598","of Pleiades",37,48],["H6605","or loose",50,58],["H4189","the bands",59,68],["H3685","of Orion",69,77]]},"38:32":{"text":"Canst thou bring forth Mazzaroth in his season? or canst thou guide Arcturus with his sons?","words":[["H3318","Canst thou bring forth",0,22],["H4216","Mazzaroth",23,32],["H6256","in his season",33,46],["H5148","or canst thou guide",48,67],["H5906","Arcturus",68,76],["H1121","with his sons",77,90]]},"38:33":{"text":"Knowest thou the ordinances of heaven? canst thou set the dominion thereof in the earth?","words":[["H3045","Knowest",0,7],["H2708","thou the ordinances",8,27],["H8064","of heaven",28,37],["H7760","canst thou set",39,53],["H4896","the dominion",54,66],["H0776","thereof in the earth",67,87]]},"38:34":{"text":"Canst thou lift up thy voice to the clouds, that abundance of waters may cover thee?","words":[["H7311","Canst thou lift up",0,18],["H6963","thy voice",19,28],["H5645","to the clouds",29,42],["H8229","that abundance",44,58],["H4325","of waters",59,68],["H3680","may cover",69,78]]},"38:35":{"text":"Canst thou send lightnings, that they may go, and say unto thee, Here we are?","words":[["H7971","Canst thou send",0,15],["H1300","lightnings",16,26],["H3212","that they may go",28,44],["H0559","and say",46,53]]},"38:36":{"text":"Who hath put wisdom in the inward parts? or who hath given understanding to the heart?","words":[["H7896","Who hath put",0,12],["H2451","wisdom",13,19],["H2910","in the inward parts",20,39],["H5414","or who hath given",41,58],["H0998","understanding",59,72],["H7907","to the heart",73,85]]},"38:37":{"text":"Who can number the clouds in wisdom? or who can stay the bottles of heaven,","words":[["H5608","Who can number",0,14],["H7834","the clouds",15,25],["H2451","in wisdom",26,35],["H7901","or who can stay",37,52],["H5035","the bottles",53,64],["H8064","of heaven",65,74]]},"38:38":{"text":"When the dust groweth into hardness, and the clods cleave fast together?","words":[["H6083","When the dust",0,13],["H3332","groweth",14,21],["H4165","into hardness",22,35],["H7263","and the clods",37,50],["H1692","cleave fast together",51,71]]},"38:39":{"text":"Wilt thou hunt the prey for the lion? or fill the appetite of the young lions,","words":[["H6679","Wilt thou hunt",0,14],["H2964","the prey",15,23],["H3833","for the lion",24,36],["H4390","or fill",38,45],["H2416","the appetite",46,58],["H3715","of the young lions",59,77]]},"38:40":{"text":"When they couch in their dens, and abide in the covert to lie in wait?","words":[["H7817","When they couch",0,15],["H4585","in their dens",16,29],["H3427","and abide",31,40],["H5521","in the covert",41,54],["H3926","to",55,57],["H0695","lie in wait",58,69]]},"38:41":{"text":"Who provideth for the raven his food? when his young ones cry unto God, they wander for lack of meat.","words":[["H3559","Who provideth",0,13],["H6158","for the raven",14,27],["H6718","his food",28,36],["H3206","when his young ones",38,57],["H7768","cry",58,61],["H0410","unto God",62,70],["H8582","they wander",72,83],["H1097","for lack",84,92],["H0400","of meat",93,100]]},"39:1":{"text":"Knowest thou the time when the wild goats of the rock bring forth? or canst thou mark when the hinds do calve?","words":[["H3045","Knowest",0,7],["H6256","thou the time",8,21],["H3277","when the wild goats",22,41],["H5553","of the rock",42,53],["H3205","bring forth",54,65],["H8104","or canst thou mark",67,85],["H0355","when the hinds",86,100],["H2342","do calve",101,109]]},"39:2":{"text":"Canst thou number the months that they fulfil? or knowest thou the time when they bring forth?","words":[["H5608","Canst thou number",0,17],["H3391","the months",18,28],["H4390","that they fulfil",29,45],["H3045","or knowest",47,57],["H6256","thou the time",58,71],["H3205","when they bring forth",72,93]]},"39:3":{"text":"They bow themselves, they bring forth their young ones, they cast out their sorrows.","words":[["H3766","They bow",0,8],["H6398","themselves, they bring forth",9,37],["H3206","their young ones",38,54],["H7971","they cast out",56,69],["H2256","their sorrows",70,83]]},"39:4":{"text":"Their young ones are in good liking, they grow up with corn; they go forth, and return not unto them.","words":[["H1121","Their young ones",0,16],["H2492","are in good liking",17,35],["H7235","they grow up",37,49],["H1250","with corn",50,59],["H3318","they go forth",61,74],["H7725","and return",76,86]]},"39:5":{"text":"Who hath sent out the wild ass free? or who hath loosed the bands of the wild ass?","words":[["H7971","Who hath sent out",0,17],["H6501","the wild ass",18,30],["H2670","free",31,35],["H6605","or who hath loosed",37,55],["H4147","the bands",56,65],["H6171","of the wild ass",66,81]]},"39:6":{"text":"Whose house I have made the wilderness, and the barren land his dwellings.","words":[["H1004","Whose house",0,11],["H7760","I have made",12,23],["H6160","the wilderness",24,38],["H4420","and the barren",40,54],["H4908","land his dwellings",55,73]]},"39:7":{"text":"He scorneth the multitude of the city, neither regardeth he the crying of the driver.","words":[["H7832","He scorneth",0,11],["H1995","the multitude",12,25],["H7151","of the city",26,37],["H8085","neither regardeth",39,56],["H8663","he the crying",57,70],["H5065","of the driver",71,84]]},"39:8":{"text":"The range of the mountains is his pasture, and he searcheth after every green thing.","words":[["H3491","The range",0,9],["H2022","of the mountains",10,26],["H4829","is his pasture",27,41],["H1875","and he searcheth",43,59],["H0310","after",60,65],["H3387","every green thing",66,83]]},"39:9":{"text":"Will the unicorn be willing to serve thee, or abide by thy crib?","words":[["H7214","Will the unicorn",0,16],["H0014","be willing",17,27],["H5647","to serve",28,36],["H3885","thee, or abide",37,51],["H0018","by thy crib",52,63]]},"39:10":{"text":"Canst thou bind the unicorn with his band in the furrow? or will he harrow the valleys after thee?","words":[["H7194","Canst thou bind",0,15],["H7214","the unicorn",16,27],["H5688","with his band",28,41],["H8525","in the furrow",42,55],["H7702","or will he harrow",57,74],["H6010","the valleys",75,86],["H0310","after",87,92]]},"39:11":{"text":"Wilt thou trust him, because his strength is great? or wilt thou leave thy labour to him?","words":[["H0982","Wilt thou trust",0,15],["H3581","him, because his strength",16,41],["H7227","is great",42,50],["H5800","or wilt thou leave",52,70],["H3018","thy labour",71,81]]},"39:12":{"text":"Wilt thou believe him, that he will bring home thy seed, and gather it into thy barn?","words":[["H0539","Wilt thou believe",0,17],["H7725","him, that he will bring home",18,46],["H7725","him, that he will bring home",18,46],["H2233","thy seed",47,55],["H0622","and gather",57,67],["H1637","it into thy barn",68,84]]},"39:13":{"text":"Gavest thou the goodly wings unto the peacocks? or wings and feathers unto the ostrich?","words":[["H7443","Gavest thou the goodly",0,22],["H3671","wings",23,28],["H5965","unto the peacocks",29,46],["H0084","or wings",48,56],["H2624","and feathers",57,69],["H5133","unto the ostrich",70,86]]},"39:14":{"text":"Which leaveth her eggs in the earth, and warmeth them in dust,","words":[["H5800","Which leaveth",0,13],["H1000","her eggs",14,22],["H0776","in the earth",23,35],["H2552","and warmeth",37,48],["H6083","them in dust",49,61]]},"39:15":{"text":"And forgetteth that the foot may crush them, or that the wild beast may break them.","words":[["H7911","And forgetteth",0,14],["H7272","that the foot",15,28],["H2115","may crush",29,38],["H7704","them, or that the wild",39,61],["H2416","beast",62,67],["H1758","may break",68,77]]},"39:16":{"text":"She is hardened against her young ones, as though they were not hers: her labour is in vain without fear;","words":[["H7188","She is hardened",0,15],["H1121","against her young ones",16,38],["H3808","as though they were not",40,63],["H3018","hers: her labour",64,80],["H7385","is in vain",81,91],["H6343","without fear",92,104]]},"39:17":{"text":"Because God hath deprived her of wisdom, neither hath he imparted to her understanding.","words":[["H0433","Because God",0,11],["H5382","hath deprived",12,25],["H2451","her of wisdom",26,39],["H2505","neither hath he imparted",41,65],["H0998","to her understanding",66,86]]},"39:18":{"text":"What time she lifteth up herself on high, she scorneth the horse and his rider.","words":[["H6256","What time",0,9],["H4754","she lifteth up",10,24],["H4791","herself on high",25,40],["H7832","she scorneth",42,54],["H5483","the horse",55,64],["H7392","and his rider",65,78]]},"39:19":{"text":"Hast thou given the horse strength? hast thou clothed his neck with thunder?","words":[["H5414","Hast thou given",0,15],["H5483","the horse",16,25],["H1369","strength",26,34],["H3847","hast thou clothed",36,53],["H6677","his neck",54,62],["H7483","with thunder",63,75]]},"39:20":{"text":"Canst thou make him afraid as a grasshopper? the glory of his nostrils is terrible.","words":[["H7493","Canst thou make him afraid",0,26],["H0697","as a grasshopper",27,43],["H1935","the glory",45,54],["H5170","of his nostrils",55,70],["H0367","is terrible",71,82]]},"39:21":{"text":"He paweth in the valley, and rejoiceth in his strength: he goeth on to meet the armed men.","words":[["H2658","He paweth",0,9],["H6010","in the valley",10,23],["H7797","and rejoiceth",25,38],["H3581","in his strength",39,54],["H3318","he goeth on",56,67],["H7125","to meet",68,75],["H5402","the armed men",76,89]]},"39:22":{"text":"He mocketh at fear, and is not affrighted; neither turneth he back from the sword.","words":[["H7832","He mocketh",0,10],["H6343","at fear",11,18],["H2865","and is not affrighted",20,41],["H7725","neither turneth he back",43,66],["H6440","from",67,71],["H2719","the sword",72,81]]},"39:23":{"text":"The quiver rattleth against him, the glittering spear and the shield.","words":[["H0827","The quiver",0,10],["H7439","rattleth",11,19],["H3851","against him, the glittering",20,47],["H2595","spear",48,53],["H3591","and the shield",54,68]]},"39:24":{"text":"He swalloweth the ground with fierceness and rage: neither believeth he that it is the sound of the trumpet.","words":[["H1572","He swalloweth",0,13],["H0776","the ground",14,24],["H7494","with fierceness",25,40],["H7267","and rage",41,49],["H0539","neither believeth",51,68],["H6963","he that it is the sound",69,92],["H7782","of the trumpet",93,107]]},"39:25":{"text":"He saith among the trumpets, Ha, ha; and he smelleth the battle afar off, the thunder of the captains, and the shouting.","words":[["H0559","He saith",0,8],["H1767","among",9,14],["H7782","the trumpets",15,27],["H1889","Ha",29,31],["H1889","ha",33,35],["H7306","and he smelleth",37,52],["H4421","the battle",53,63],["H7350","afar off",64,72],["H7482","the thunder",74,85],["H8269","of the captains",86,101],["H8643","and the shouting",103,119]]},"39:26":{"text":"Doth the hawk fly by thy wisdom, and stretch her wings toward the south?","words":[["H5322","Doth the hawk",0,13],["H0082","fly",14,17],["H0998","by thy wisdom",18,31],["H6566","and stretch",33,44],["H3671","her wings",45,54],["H8486","toward the south",55,71]]},"39:27":{"text":"Doth the eagle mount up at thy command, and make her nest on high?","words":[["H5404","Doth the eagle",0,14],["H1361","mount up",15,23],["H6310","at thy command",24,38],["H7311","and make",40,48],["H7064","her nest",49,57],["H7311","on high",58,65]]},"39:28":{"text":"She dwelleth and abideth on the rock, upon the crag of the rock, and the strong place.","words":[["H7931","She dwelleth",0,12],["H3885","and abideth",13,24],["H5553","on the rock",25,36],["H8127","upon the crag",38,51],["H5553","of the rock",52,63],["H4686","and the strong place",65,85]]},"39:29":{"text":"From thence she seeketh the prey, and her eyes behold afar off.","words":[["H2658","From thence she seeketh",0,23],["H0400","the prey",24,32],["H5869","and her eyes",34,46],["H5027","behold",47,53],["H7350","afar off",54,62]]},"39:30":{"text":"Her young ones also suck up blood: and where the slain are, there is she.","words":[["H0667","Her young ones",0,14],["H5966","also suck up",15,27],["H1818","blood",28,33],["H2491","and where the slain",35,54],["H1931","are, there is she",55,72]]},"40:1":{"text":"Moreover the LORD answered Job, and said,","words":[["H3068","Moreover the LORD",0,17],["H6030","answered",18,26],["H0347","Job",27,30],["H0559","and said",32,40]]},"40:2":{"text":"Shall he that contendeth with the Almighty instruct him? he that reproveth God, let him answer it.","words":[["H7378","Shall he that contendeth",0,24],["H7706","with the Almighty",25,42],["H3250","instruct",43,51],["H3198","him? he that reproveth",52,74],["H0433","God",75,78],["H6030","let him answer",80,94]]},"40:3":{"text":"Then Job answered the LORD, and said,","words":[["H0347","Then Job",0,8],["H6030","answered",9,17],["H3068","the LORD",18,26],["H0559","and said",28,36]]},"40:4":{"text":"Behold, I am vile; what shall I answer thee? I will lay mine hand upon my mouth.","words":[["H7043","Behold, I am vile",0,17],["H7725","what shall I answer",19,38],["H7760","thee? I will lay",39,55],["H3027","mine hand",56,65],["H3926","upon",66,70],["H6310","my mouth",71,79]]},"40:5":{"text":"Once have I spoken; but I will not answer: yea, twice; but I will proceed no further.","words":[["H0259","Once",0,4],["H1696","have I spoken",5,18],["H6030","but I will not answer",20,41],["H8147","yea, twice",43,53],["H3254","but I will proceed no further",55,84]]},"40:6":{"text":"Then answered the LORD unto Job out of the whirlwind, and said,","words":[["H6030","Then answered",0,13],["H3068","the LORD",14,22],["H0347","unto Job",23,31],["H5591","out of the whirlwind",32,52],["H0559","and said",54,62]]},"40:7":{"text":"Gird up thy loins now like a man: I will demand of thee, and declare thou unto me.","words":[["H0247","Gird up",0,7],["H2504","thy loins",8,17],["H1397","now like a man",18,32],["H7592","I will demand",34,47],["H3045","of thee, and declare",48,68]]},"40:8":{"text":"Wilt thou also disannul my judgment? wilt thou condemn me, that thou mayest be righteous?","words":[["H6565","Wilt thou also disannul",0,23],["H4941","my judgment",24,35],["H7561","wilt thou condemn",37,54],["H6663","me, that thou mayest be righteous",55,88]]},"40:9":{"text":"Hast thou an arm like God? or canst thou thunder with a voice like him?","words":[["H2220","Hast thou an arm",0,16],["H0410","like God",17,25],["H7481","or canst thou thunder",27,48],["H6963","with a voice",49,61]]},"40:10":{"text":"Deck thyself now with majesty and excellency; and array thyself with glory and beauty.","words":[["H5710","Deck",0,4],["H1347","thyself now with majesty",5,29],["H1363","and excellency",30,44],["H3847","and array",46,55],["H1935","thyself with glory",56,74],["H1926","and beauty",75,85]]},"40:11":{"text":"Cast abroad the rage of thy wrath: and behold every one that is proud, and abase him.","words":[["H6327","Cast abroad",0,11],["H5678","the rage",12,20],["H0639","of thy wrath",21,33],["H7200","and behold",35,45],["H1343","every one that is proud",46,69],["H8213","and abase",71,80]]},"40:12":{"text":"Look on every one that is proud, and bring him low; and tread down the wicked in their place.","words":[["H7200","Look",0,4],["H1343","on every one that is proud",5,31],["H3665","and bring him low",33,50],["H1915","and tread down",52,66],["H7563","the wicked",67,77]]},"40:13":{"text":"Hide them in the dust together; and bind their faces in secret.","words":[["H2934","Hide",0,4],["H6083","them in the dust",5,21],["H3162","together",22,30],["H2280","and bind",32,40],["H6440","their faces",41,52],["H2934","in secret",53,62]]},"40:14":{"text":"Then will I also confess unto thee that thine own right hand can save thee.","words":[["H3034","Then will I also confess",0,24],["H3225","unto thee that thine own right hand",25,60],["H3467","can save",61,69]]},"40:15":{"text":"Behold now behemoth, which I made with thee; he eateth grass as an ox.","words":[["H0930","Behold now behemoth",0,19],["H6213","which I made",21,33],["H0398","with thee; he eateth",34,54],["H2682","grass",55,60],["H1241","as an ox",61,69]]},"40:16":{"text":"Lo now, his strength is in his loins, and his force is in the navel of his belly.","words":[["H3581","Lo now, his strength",0,20],["H4975","is in his loins",21,36],["H0202","and his force",38,51],["H8306","is in the navel",52,67],["H0990","of his belly",68,80]]},"40:17":{"text":"He moveth his tail like a cedar: the sinews of his stones are wrapped together.","words":[["H2654","He moveth",0,9],["H2180","his tail",10,18],["H0730","like a cedar",19,31],["H1517","the sinews",33,43],["H6344","of his stones",44,57],["H8276","are wrapped together",58,78]]},"40:18":{"text":"His bones are as strong pieces of brass; his bones are like bars of iron.","words":[["H6106","His bones",0,9],["H0650","are as strong",10,23],["H5154","pieces of brass",24,39],["H1634","his bones",41,50],["H4300","are like bars",51,64],["H1270","of iron",65,72]]},"40:19":{"text":"He is the chief of the ways of God: he that made him can make his sword to approach unto him.","words":[["H7225","He is the chief",0,15],["H1870","of the ways",16,27],["H0410","of God",28,34],["H6213","he that made",36,48],["H5066","him can make",49,61],["H2719","his sword",62,71],["H5066","to approach",72,83]]},"40:20":{"text":"Surely the mountains bring him forth food, where all the beasts of the field play.","words":[["H2022","Surely the mountains",0,20],["H5375","bring him forth",21,36],["H0944","food",37,41],["H2416","where all the beasts",43,63],["H7704","of the field",64,76],["H7832","play",77,81]]},"40:21":{"text":"He lieth under the shady trees, in the covert of the reed, and fens.","words":[["H7901","He lieth",0,8],["H6628","under the shady trees",9,30],["H5643","in the covert",32,45],["H7070","of the reed",46,57],["H1207","and fens",59,67]]},"40:22":{"text":"The shady trees cover him with their shadow; the willows of the brook compass him about.","words":[["H6628","The shady trees",0,15],["H5526","cover",16,21],["H6752","him with their shadow",22,43],["H6155","the willows",45,56],["H5158","of the brook",57,69],["H5437","compass him about",70,87]]},"40:23":{"text":"Behold, he drinketh up a river, and hasteth not: he trusteth that he can draw up Jordan into his mouth.","words":[["H6231","Behold, he drinketh up",0,22],["H5104","a river",23,30],["H2648","and hasteth",32,43],["H0982","not: he trusteth",44,60],["H1518","that he can draw up",61,80],["H3383","Jordan",81,87],["H6310","into his mouth",88,102]]},"40:24":{"text":"He taketh it with his eyes: his nose pierceth through snares.","words":[["H3947","He taketh",0,9],["H5869","it with his eyes",10,26],["H0639","his nose",28,36],["H5344","pierceth through",37,53],["H4170","snares",54,60]]},"41:1":{"text":"Canst thou draw out leviathan with an hook? or his tongue with a cord which thou lettest down?","words":[["H4900","Canst thou draw out",0,19],["H3882","leviathan",20,29],["H2443","with an hook",30,42],["H3956","or his tongue",44,57],["H2256","with a cord",58,69],["H8257","which thou lettest down",70,93]]},"41:2":{"text":"Canst thou put an hook into his nose? or bore his jaw through with a thorn?","words":[["H7760","Canst thou put",0,14],["H0100","an hook",15,22],["H0639","into his nose",23,36],["H5344","or bore",38,45],["H3895","his jaw",46,53],["H2336","through with a thorn",54,74]]},"41:3":{"text":"Will he make many supplications unto thee? will he speak soft words unto thee?","words":[["H7235","Will he make many",0,17],["H8469","supplications",18,31],["H1696","unto thee? will he speak",32,56],["H7390","soft",57,61]]},"41:4":{"text":"Will he make a covenant with thee? wilt thou take him for a servant for ever?","words":[["H3772","Will he make",0,12],["H1285","a covenant",13,23],["H3947","with thee? wilt thou take",24,49],["H5650","him for a servant",50,67],["H5769","for ever",68,76]]},"41:5":{"text":"Wilt thou play with him as with a bird? or wilt thou bind him for thy maidens?","words":[["H7832","Wilt thou play",0,14],["H6833","with him as with a bird",15,38],["H7194","or wilt thou bind",40,57],["H5291","him for thy maidens",58,77]]},"41:6":{"text":"Shall the companions make a banquet of him? shall they part him among the merchants?","words":[["H2271","Shall the companions",0,20],["H3739","make a banquet",21,35],["H2673","of him? shall they part",36,59],["H3669","him among the merchants",60,83]]},"41:7":{"text":"Canst thou fill his skin with barbed irons? or his head with fish spears?","words":[["H4390","Canst thou fill",0,15],["H5785","his skin",16,24],["H7905","with barbed irons",25,42],["H7218","or his head",44,55],["H1709","with fish",56,65],["H6767","spears",66,72]]},"41:8":{"text":"Lay thine hand upon him, remember the battle, do no more.","words":[["H7760","Lay",0,3],["H3709","thine hand",4,14],["H2142","upon him, remember",15,33],["H4421","the battle",34,44],["H3254","do no more",46,56]]},"41:9":{"text":"Behold, the hope of him is in vain: shall not one be cast down even at the sight of him?","words":[["H8431","Behold, the hope",0,16],["H3576","of him is in vain",17,34],["H2904","shall not one be cast down",36,62],["H4758","even at the sight",63,80]]},"41:10":{"text":"None is so fierce that dare stir him up: who then is able to stand before me?","words":[["H0393","None is so fierce",0,17],["H5782","that dare stir him up",18,39],["H5782","that dare stir him up",18,39],["H3320","who then is able to stand",41,66],["H6440","before",67,73]]},"41:11":{"text":"Who hath prevented me, that I should repay him? whatsoever is under the whole heaven is mine.","words":[["H6923","Who hath prevented",0,18],["H7999","me, that I should repay",19,42],["H8064","him? whatsoever is under the whole heaven",43,84]]},"41:12":{"text":"I will not conceal his parts, nor his power, nor his comely proportion.","words":[["H2790","I will not conceal",0,18],["H0907","his parts",19,28],["H1369","nor his power",30,43],["H1697","nor his power",30,43],["H2433","nor his comely",45,59],["H6187","proportion",60,70]]},"41:13":{"text":"Who can discover the face of his garment? or who can come to him with his double bridle?","words":[["H1540","Who can discover",0,16],["H6440","the face",17,25],["H3830","of his garment",26,40],["H0935","or who can come",42,57],["H3718","to him with his double",58,80],["H7448","bridle",81,87]]},"41:14":{"text":"Who can open the doors of his face? his teeth are terrible round about.","words":[["H6605","Who can open",0,12],["H1817","the doors",13,22],["H6440","of his face",23,34],["H8127","his teeth",36,45],["H0367","are terrible",46,58],["H5439","round about",59,70]]},"41:15":{"text":"His scales are his pride, shut up together as with a close seal.","words":[["H4043","His scales",0,10],["H0650","His scales",0,10],["H1346","are his pride",11,24],["H5462","shut up together",26,42],["H6862","as with a close",43,58],["H2368","seal",59,63]]},"41:16":{"text":"One is so near to another, that no air can come between them.","words":[["H0259","One",0,3],["H5066","is so near",4,14],["H0259","to another",15,25],["H7307","that no air",27,38],["H0935","can come",39,47]]},"41:17":{"text":"They are joined one to another, they stick together, that they cannot be sundered.","words":[["H1692","They are joined",0,15],["H0376","one",16,19],["H0251","to another",20,30],["H3920","they stick together",32,51],["H6504","that they cannot be sundered",53,81]]},"41:18":{"text":"By his neesings a light doth shine, and his eyes are like the eyelids of the morning.","words":[["H5846","By his neesings",0,15],["H0216","a light",16,23],["H1984","doth shine",24,34],["H5869","and his eyes",36,48],["H6079","are like the eyelids",49,69],["H7837","of the morning",70,84]]},"41:19":{"text":"Out of his mouth go burning lamps, and sparks of fire leap out.","words":[["H6310","Out of his mouth",0,16],["H1980","go",17,19],["H3940","burning lamps",20,33],["H3590","and sparks",35,45],["H0784","of fire",46,53],["H4422","leap out",54,62]]},"41:20":{"text":"Out of his nostrils goeth smoke, as out of a seething pot or caldron.","words":[["H5156","Out of his nostrils",0,19],["H3318","goeth",20,25],["H6227","smoke",26,31],["H5301","as out of a seething",33,53],["H1731","pot",54,57],["H0100","or caldron",58,68]]},"41:21":{"text":"His breath kindleth coals, and a flame goeth out of his mouth.","words":[["H5315","His breath",0,10],["H3857","kindleth",11,19],["H1513","coals",20,25],["H3851","and a flame",27,38],["H3318","goeth out",39,48],["H6310","of his mouth",49,61]]},"41:22":{"text":"In his neck remaineth strength, and sorrow is turned into joy before him.","words":[["H6677","In his neck",0,11],["H3885","remaineth",12,21],["H5797","strength",22,30],["H1670","and sorrow",32,42],["H1750","is turned into joy",43,61],["H6440","before",62,68]]},"41:23":{"text":"The flakes of his flesh are joined together: they are firm in themselves; they cannot be moved.","words":[["H4651","The flakes",0,10],["H1320","of his flesh",11,23],["H1692","are joined together",24,43],["H3332","they are firm",45,58],["H4131","in themselves; they cannot be moved",59,94]]},"41:24":{"text":"His heart is as firm as a stone; yea, as hard as a piece of the nether millstone.","words":[["H3820","His heart",0,9],["H3332","is as firm",10,20],["H0068","as a stone",21,31],["H3332","yea, as hard",33,45],["H6400","as a piece",46,56],["H8482","of the nether",57,70]]},"41:25":{"text":"When he raiseth up himself, the mighty are afraid: by reason of breakings they purify themselves.","words":[["H7613","When he raiseth up",0,18],["H0352","himself, the mighty",19,38],["H1481","are afraid",39,49],["H7667","by reason of breakings",51,73],["H2398","they purify",74,85]]},"41:26":{"text":"The sword of him that layeth at him cannot hold: the spear, the dart, nor the habergeon.","words":[["H2719","The sword",0,9],["H5381","of him that layeth",10,28],["H6965","at him cannot hold",29,47],["H2595","the spear",49,58],["H4551","the dart",60,68],["H8302","nor the habergeon",70,87]]},"41:27":{"text":"He esteemeth iron as straw, and brass as rotten wood.","words":[["H2803","He esteemeth",0,12],["H1270","iron",13,17],["H8401","as straw",18,26],["H5154","and brass",28,37],["H7539","as rotten",38,47],["H6086","wood",48,52]]},"41:28":{"text":"The arrow cannot make him flee: slingstones are turned with him into stubble.","words":[["H1121","The arrow",0,9],["H7198","The arrow",0,9],["H1272","cannot make him flee",10,30],["H0068","slingstones",32,43],["H7050","slingstones",32,43],["H2015","are turned",44,54],["H7179","with him into stubble",55,76]]},"41:29":{"text":"Darts are counted as stubble: he laugheth at the shaking of a spear.","words":[["H8455","Darts",0,5],["H2803","are counted",6,17],["H7179","as stubble",18,28],["H7832","he laugheth",30,41],["H7494","at the shaking",42,56],["H3591","of a spear",57,67]]},"41:30":{"text":"Sharp stones are under him: he spreadeth sharp pointed things upon the mire.","words":[["H2303","Sharp",0,5],["H2789","stones",6,12],["H7502","are under him: he spreadeth",13,40],["H2742","sharp pointed things",41,61],["H2916","upon the mire",62,75]]},"41:31":{"text":"He maketh the deep to boil like a pot: he maketh the sea like a pot of ointment.","words":[["H4688","He maketh the deep",0,18],["H7570","to boil",19,26],["H5518","like a pot",27,37],["H7760","he maketh",39,48],["H3220","the sea",49,56],["H4841","like a pot of ointment",57,79]]},"41:32":{"text":"He maketh a path to shine after him; one would think the deep to be hoary.","words":[["H5410","He maketh a path",0,16],["H0215","to shine",17,25],["H0310","after",26,31],["H2803","him; one would think",32,52],["H8415","the deep",53,61],["H7872","to be hoary",62,73]]},"41:33":{"text":"Upon earth there is not his like, who is made without fear.","words":[["H6083","Upon earth",0,10],["H4915","there is not his like",11,32],["H6213","who is made",34,45],["H1097","without",46,53],["H2844","fear",54,58]]},"41:34":{"text":"He beholdeth all high things: he is a king over all the children of pride.","words":[["H7200","He beholdeth",0,12],["H1364","all high",13,21],["H4428","things: he is a king",22,42],["H1121","over all the children",43,64],["H7830","of pride",65,73]]},"42:1":{"text":"Then Job answered the LORD, and said,","words":[["H0347","Then Job",0,8],["H6030","answered",9,17],["H3068","the LORD",18,26],["H0559","and said",28,36]]},"42:2":{"text":"I know that thou canst do every thing, and that no thought can be withholden from thee.","words":[["H3045","I know",0,6],["H3201","that thou canst do",7,25],["H4209","every thing, and that no thought",26,58],["H1219","can be withholden",59,76]]},"42:3":{"text":"Who is he that hideth counsel without knowledge? therefore have I uttered that I understood not; things too wonderful for me, which I knew not.","words":[["H5956","Who is he that hideth",0,21],["H6098","counsel",22,29],["H1847","without knowledge",30,47],["H5046","therefore have I uttered",49,73],["H0995","that I understood",74,91],["H6381","not; things too wonderful",92,117],["H3045","for me, which I knew",118,138]]},"42:4":{"text":"Hear, I beseech thee, and I will speak: I will demand of thee, and declare thou unto me.","words":[["H8085","Hear",0,4],["H1696","I beseech thee, and I will speak",6,38],["H7592","I will demand",40,53],["H3045","of thee, and declare",54,74]]},"42:5":{"text":"I have heard of thee by the hearing of the ear: but now mine eye seeth thee.","words":[["H8085","I have heard",0,12],["H8088","of thee by the hearing",13,35],["H0241","of the ear",36,46],["H5869","but now mine eye",48,64],["H7200","seeth",65,70]]},"42:6":{"text":"Wherefore I abhor myself, and repent in dust and ashes.","words":[["H3988","Wherefore I abhor",0,17],["H5162","myself, and repent",18,36],["H6083","in dust",37,44],["H0665","and ashes",45,54]]},"42:7":{"text":"And it was so, that after the LORD had spoken these words unto Job, the LORD said to Eliphaz the Temanite, My wrath is kindled against thee, and against thy two friends: for ye have not spoken of me the thing that is right, as my servant Job hath.","words":[["H0310","And it was so, that after",0,25],["H3068","the LORD",26,34],["H1696","had spoken",35,45],["H1697","these words",46,57],["H0347","unto Job",58,66],["H3068","the LORD",68,76],["H0559","said",77,81],["H0464","to Eliphaz",82,92],["H8489","the Temanite",93,105],["H0639","My wrath",107,115],["H2734","is kindled",116,126],["H8147","against thee, and against thy two",127,160],["H7453","friends",161,168],["H1696","for ye have not spoken",170,192],["H3559","of me the thing that is right",193,222],["H5650","as my servant",224,237],["H0347","Job",238,241]]},"42:8":{"text":"Therefore take unto you now seven bullocks and seven rams, and go to my servant Job, and offer up for yourselves a burnt offering; and my servant Job shall pray for you: for him will I accept: lest I deal with you after your folly, in that ye have not spoken of me the thing which is right, like my servant Job.","words":[["H3947","Therefore take",0,14],["H7651","unto you now seven",15,33],["H6499","bullocks",34,42],["H7651","and seven",43,52],["H0352","rams",53,57],["H3212","and go",59,65],["H5650","to my servant",66,79],["H0347","Job",80,83],["H5927","and offer up",85,97],["H5930","for yourselves a burnt offering",98,129],["H5650","and my servant",131,145],["H0347","Job",146,149],["H6419","shall pray",150,160],["H6440","for you: for him",161,177],["H5375","will I accept",178,191],["H6213","lest I deal",193,204],["H5039","with you after your folly",205,230],["H1696","in that ye have not spoken",232,258],["H3559","of me the thing which is right",259,289],["H5650","like my servant",291,306],["H0347","Job",307,310]]},"42:9":{"text":"So Eliphaz the Temanite and Bildad the Shuhite and Zophar the Naamathite went, and did according as the LORD commanded them: the LORD also accepted Job.","words":[["H0464","So Eliphaz",0,10],["H8489","the Temanite",11,23],["H1085","and Bildad",24,34],["H7747","the Shuhite",35,46],["H6691","and Zophar",47,57],["H5284","the Naamathite",58,72],["H3212","went",73,77],["H6213","and did",79,86],["H3068","according as the LORD",87,108],["H1696","commanded",109,118],["H3068","them: the LORD",119,133],["H5375","also accepted",134,147],["H6440","Job",148,151],["H0347","Job",148,151]]},"42:10":{"text":"And the LORD turned the captivity of Job, when he prayed for his friends: also the LORD gave Job twice as much as he had before.","words":[["H3068","And the LORD",0,12],["H7725","turned",13,19],["H7622","the captivity",20,33],["H7622","the captivity",20,33],["H0347","of Job",34,40],["H6419","when he prayed",42,56],["H7453","for his friends",57,72],["H3068","also the LORD",74,87],["H3254","gave",88,92],["H0347","Job",93,96],["H4932","twice as much",97,110]]},"42:11":{"text":"Then came there unto him all his brethren, and all his sisters, and all they that had been of his acquaintance before, and did eat bread with him in his house: and they bemoaned him, and comforted him over all the evil that the LORD had brought upon him: every man also gave him a piece of money, and every one an earring of gold.","words":[["H0935","Then came",0,9],["H0251","there unto him all his brethren",10,41],["H0269","and all his sisters",43,62],["H3045","and all they that had been of his acquaintance",64,110],["H6440","before",111,117],["H0398","and did eat",119,130],["H3899","bread",131,136],["H1004","with him in his house",137,158],["H5110","and they bemoaned",160,177],["H5162","him, and comforted",178,196],["H7451","him over all the evil",197,218],["H3068","that the LORD",219,232],["H0935","had brought",233,244],["H0376","upon him: every man",245,264],["H5414","also gave",265,274],["H0259","him a",275,280],["H7192","piece of money",281,295],["H0376","and every one",297,310],["H5141","an earring",311,321],["H2091","of gold",322,329]]},"42:12":{"text":"So the LORD blessed the latter end of Job more than his beginning: for he had fourteen thousand sheep, and six thousand camels, and a thousand yoke of oxen, and a thousand she asses.","words":[["H3068","So the LORD",0,11],["H1288","blessed",12,19],["H0319","the latter end",20,34],["H0347","of Job",35,41],["H7225","more than his beginning",42,65],["H0702","for he had fourteen",67,86],["H6240","for he had fourteen",67,86],["H0505","thousand",87,95],["H6629","sheep",96,101],["H8337","and six",103,110],["H0505","thousand",111,119],["H1581","camels",120,126],["H0505","and a thousand",128,142],["H6776","yoke",143,147],["H1241","of oxen",148,155],["H0505","and a thousand",157,171],["H0860","she asses",172,181]]},"42:13":{"text":"He had also seven sons and three daughters.","words":[["H7658","He had also seven",0,17],["H1121","sons",18,22],["H7969","and three",23,32],["H1323","daughters",33,42]]},"42:14":{"text":"And he called the name of the first, Jemima; and the name of the second, Kezia; and the name of the third, Kerenhappuch.","words":[["H7121","And he called",0,13],["H8034","the name",14,22],["H0259","of the first",23,35],["H3224","Jemima",37,43],["H8034","and the name",45,57],["H8145","of the second",58,71],["H7103","Kezia",73,78],["H8034","and the name",80,92],["H7992","of the third",93,105],["H7163","Kerenhappuch",107,119]]},"42:15":{"text":"And in all the land were no women found so fair as the daughters of Job: and their father gave them inheritance among their brethren.","words":[["H0776","And in all the land",0,19],["H0802","were no women",20,33],["H4672","found",34,39],["H3303","so fair",40,47],["H1323","as the daughters",48,64],["H0347","of Job",65,71],["H0001","and their father",73,89],["H5414","gave",90,94],["H5159","them inheritance",95,111],["H8432","among",112,117],["H0251","their brethren",118,132]]},"42:16":{"text":"After this lived Job an hundred and forty years, and saw his sons, and his sons' sons, even four generations.","words":[["H0310","After",0,5],["H2421","this lived",6,16],["H0347","Job",17,20],["H3967","an hundred",21,31],["H0705","and forty",32,41],["H8141","years",42,47],["H7200","and saw",49,56],["H1121","his sons",57,65],["H1121","and his sons'",67,80],["H1121","sons",81,85],["H0702","even four",87,96],["H1755","generations",97,108]]},"42:17":{"text":"So Job died, being old and full of days.","words":[["H0347","So Job",0,6],["H4191","died",7,11],["H2205","being old",13,22],["H7649","and full",23,31],["H3117","of days",32,39]]}}};
